  type: string;
  duration: string;
  price: number;
  note?: string;
}

export interface Product {
  appName: string;
  variants: Variant[];
  tags?: string[];
}

export interface CartItem {
  id: string; // Unique ID for cart item (productName + variantIndex)
  product: Product;
  selectedVariantIndex: number;
  quantity: number;
}

export interface Order {
  id: string;
  date: string;
  items: CartItem[];
  total: number;
  status: 'Pending' | 'Completed';
}

