export const formatRupiah = (amount: number) => {
  return new Intl.NumberFormat('id-ID', {
    style: 'currency',
    currency: 'IDR',
    minimumFractionDigits: 0,
    maximumFractionDigits: 0,
  }).format(amount);
};

import React from 'react';

const LiquidBackground: React.FC = () => {
  return (
    <div className="fixed inset-0 w-full h-full -z-50 overflow-hidden pointer-events-none">
      {/* Dark mode heavy gradients */}
      <div className="absolute top-0 left-0 w-full h-full bg-slate-50 dark:bg-slate-900 transition-colors duration-500"></div>

      {/* Animated Blobs */}
      <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-purple-400/30 dark:bg-purple-600/20 rounded-full mix-blend-multiply dark:mix-blend-screen filter blur-3xl opacity-70 animate-blob"></div>
      <div className="absolute top-[-10%] right-[-10%] w-96 h-96 bg-blue-400/30 dark:bg-blue-600/20 rounded-full mix-blend-multiply dark:mix-blend-screen filter blur-3xl opacity-70 animate-blob animation-delay-2000"></div>
      <div className="absolute bottom-[-20%] left-[20%] w-96 h-96 bg-pink-400/30 dark:bg-pink-600/20 rounded-full mix-blend-multiply dark:mix-blend-screen filter blur-3xl opacity-70 animate-blob animation-delay-4000"></div>
      <div className="absolute bottom-[20%] right-[10%] w-80 h-80 bg-indigo-400/30 dark:bg-indigo-900/30 rounded-full mix-blend-multiply dark:mix-blend-screen filter blur-3xl opacity-70 animate-blob animation-delay-3000"></div>
    </div>
  );
};

export default LiquidBackground;

import React from 'react';
import { ShoppingCart, Moon, Sun, Heart, History } from 'lucide-react';

interface NavbarProps {
  toggleTheme: () => void;
  isDarkMode: boolean;
  cartCount: number;
  openCart: () => void;
  openWishlist: () => void;
  openHistory: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ 
  toggleTheme, 
  isDarkMode, 
  cartCount, 
  openCart,
  openWishlist,
  openHistory
}) => {
  return (
    <nav className="sticky top-0 z-40 w-full">
      {/* Glassmorphism Container */}
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="relative my-4 rounded-2xl border border-white/40 dark:border-white/10 bg-white/40 dark:bg-black/40 backdrop-blur-xl shadow-lg transition-all duration-300">
          <div className="flex h-16 items-center justify-between px-6">

            {/* Logo */}
            <div className="flex-shrink-0 flex items-center gap-2">
              <div className="h-8 w-8 rounded-lg bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white font-bold text-lg shadow-lg">
                P
              </div>
              <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600 dark:from-indigo-400 dark:to-purple-400">
                PremiumStore
              </span>
            </div>

            {/* Right Actions */}
            <div className="flex items-center gap-2 sm:gap-4">

              {/* History Button (Desktop/Tablet) */}
              <button 
                onClick={openHistory}
                className="hidden sm:flex p-2 rounded-xl text-gray-700 dark:text-gray-200 hover:bg-white/50 dark:hover:bg-white/10 transition-all"
                title="Riwayat Pesanan"
              >
                <History size={20} />
              </button>

              {/* Wishlist Button */}
              <button 
                onClick={openWishlist}
                className="p-2 rounded-xl text-gray-700 dark:text-gray-200 hover:bg-white/50 dark:hover:bg-white/10 transition-all"
                title="Favorit"
              >
                <Heart size={20} />
              </button>

              {/* Theme Toggle */}
              <button
                onClick={toggleTheme}
                className="p-2 rounded-xl text-gray-700 dark:text-gray-200 hover:bg-white/50 dark:hover:bg-white/10 transition-all"
                aria-label="Toggle Theme"
              >
                {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
              </button>

              {/* Cart Button */}
              <button
                onClick={openCart}
                className="group relative p-3 rounded-xl bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg shadow-indigo-500/30 hover:shadow-indigo-500/50 hover:scale-105 transition-all duration-300"
              >
                <ShoppingCart size={20} />
                {cartCount > 0 && (
                  <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-red-500 text-[10px] font-bold ring-2 ring-white dark:ring-slate-900 animate-pulse">
                    {cartCount}
                  </span>
                )}
              </button>
            </div>

          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState } from 'react';
import { Product, formatRupiah } from '../constants';
import { Heart, ShoppingCart, Check } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  addToCart: (product: Product, variantIndex: number) => void;
  toggleWishlist: (appName: string) => void;
  isWishlisted: boolean;
}

const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  addToCart, 
  toggleWishlist, 
  isWishlisted 
}) => {
  const [selectedVariantIdx, setSelectedVariantIdx] = useState(0);
  const currentVariant = product.variants[selectedVariantIdx];

  const handleAddToCart = () => {
    addToCart(product, selectedVariantIdx);
  };

  return (
    <div className="group relative flex flex-col overflow-hidden rounded-2xl border border-white/40 dark:border-white/10 bg-white/40 dark:bg-slate-800/40 backdrop-blur-md shadow-xl transition-all duration-300 hover:shadow-2xl hover:-translate-y-1">

      {/* Decorative Gradient Top */}
      <div className="absolute top-0 left-0 h-1 w-full bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 opacity-0 transition-opacity duration-300 group-hover:opacity-100"></div>

      {/* Header / Image Placeholder Area */}
      <div className="relative p-6 pb-4">
        <div className="flex justify-between items-start">
          <div className="flex items-center gap-3">
             {/* Simple Initial Icon for aesthetics */}
            <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-indigo-100 to-purple-100 dark:from-indigo-900 dark:to-purple-900 flex items-center justify-center text-indigo-600 dark:text-indigo-300 font-bold text-xl shadow-inner">
              {product.appName.charAt(0)}
