import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import LiquidBackground from './components/LiquidBackground';
import ProductCard from './components/ProductCard';
import CartModal from './components/CartModal';
import WishlistModal from './components/WishlistModal';
import HistoryModal from './components/HistoryModal';
import { PRODUCTS } from './constants';
import { Product, CartItem, Order } from './types';

const App: React.FC = () => {
  // State: Theme
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark';
    }
    return false;
  });

  // State: Modals
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isWishlistOpen, setIsWishlistOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);

  // State: Data
  const [cart, setCart] = useState<CartItem[]>([]);
  const [wishlist, setWishlist] = useState<string[]>(() => {
    const saved = localStorage.getItem('wishlist');
    return saved ? JSON.parse(saved) : [];
  });
  const [orderHistory, setOrderHistory] = useState<Order[]>(() => {
    const saved = localStorage.getItem('history');
    return saved ? JSON.parse(saved) : [];
  });

  // Effects
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    localStorage.setItem('wishlist', JSON.stringify(wishlist));
  }, [wishlist]);

  useEffect(() => {
    localStorage.setItem('history', JSON.stringify(orderHistory));
  }, [orderHistory]);

  // Handlers
  const toggleTheme = () => setIsDarkMode(!isDarkMode);

  const addToCart = (product: Product, variantIndex: number) => {
    const newItem: CartItem = {
      id: `${product.appName}-${variantIndex}-${Date.now()}`,
      product,
      selectedVariantIndex: variantIndex,
      quantity: 1
    };
    setCart([...cart, newItem]);
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const clearCart = () => setCart([]);

  const saveOrder = (order: Order) => {
    setOrderHistory([order, ...orderHistory]);
  };

  const toggleWishlist = (appName: string) => {
    if (wishlist.includes(appName)) {
      setWishlist(wishlist.filter(id => id !== appName));
    } else {
      setWishlist([...wishlist, appName]);
    }
  };

  const removeFromWishlist = (appName: string) => {
    setWishlist(wishlist.filter(id => id !== appName));
  }

  return (
    <div className="relative min-h-screen">
      <LiquidBackground />

      <Navbar 
        toggleTheme={toggleTheme}
        isDarkMode={isDarkMode}
        cartCount={cart.length}
        openCart={() => setIsCartOpen(true)}
        openWishlist={() => setIsWishlistOpen(true)}
        openHistory={() => setIsHistoryOpen(true)}
      />

      <main className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-8 pb-24">
        {/* Header Section */}
        <div className="mb-10 text-center relative">
          <h1 className="text-4xl sm:text-5xl font-extrabold tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-purple-600 dark:from-indigo-400 dark:to-purple-400 mb-4 drop-shadow-sm">
            Premium Apps Store
          </h1>
          <p className="text-lg text-gray-600 dark:text-gray-300 max-w-2xl mx-auto">
            Upgrade gaya hidup digitalmu dengan langganan aplikasi premium legal, aman, dan bergaransi dengan harga terbaik.
          </p>

          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120%] h-[150%] bg-white/30 dark:bg-black/30 blur-3xl -z-10 rounded-full pointer-events-none"></div>
        </div>

        {/* Product Grid */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {PRODUCTS.map((product, index) => (
            <ProductCard 
              key={index}
              product={product}
              addToCart={addToCart}
              toggleWishlist={toggleWishlist}
              isWishlisted={wishlist.includes(product.appName)}
            />
          ))}
        </div>
      </main>

      {/* Modals */}
      <CartModal 
        isOpen={isCartOpen}
        onClose={() => setIsCartOpen(false)}
        cart={cart}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
        saveOrder={saveOrder}
      />

      <WishlistModal 
        isOpen={isWishlistOpen}
        onClose={() => setIsWishlistOpen(false)}
        wishlistIds={wishlist}
        allProducts={PRODUCTS}
        removeFromWishlist={removeFromWishlist}
      />

      <HistoryModal
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        history={orderHistory}
      />

      {/* Simple Footer */}
      <footer className="text-center py-8 text-gray-500 dark:text-gray-400 text-sm">
        <p>&copy; {new Date().getFullYear()} PremiumStore. All rights reserved.</p>
      </footer>
    </div>
  );
};

