import React from 'react';
import { CartItem, Order } from '../types';
import { formatRupiah } from '../constants';
import { X, Trash2, MessageCircle, CreditCard, ShieldCheck } from 'lucide-react';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  removeFromCart: (id: string) => void;
  clearCart: () => void;
  saveOrder: (order: Order) => void;
}

const CartModal: React.FC<CartModalProps> = ({ 
  isOpen, 
  onClose, 
  cart, 
  removeFromCart,
  clearCart,
  saveOrder
}) => {
  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.product.variants[item.selectedVariantIndex].price * item.quantity), 0);

  const handleCheckout = () => {
    if (cart.length === 0) return;

    // 1. Construct Message
    let message = `Halo Admin, saya ingin memesan:\n\n`;
    cart.forEach((item, index) => {
      const variant = item.product.variants[item.selectedVariantIndex];
      message += `${index + 1}. ${item.product.appName} - ${variant.type} (${variant.duration})\n   Harga: ${formatRupiah(variant.price)}\n`;
    });
    message += `\nTotal Pembayaran: ${formatRupiah(total)}\n\nMohon diproses.`;

    // 2. Save to History (Simulated)
    const newOrder: Order = {
      id: `ORD-${Date.now()}`,
      date: new Date().toLocaleDateString('id-ID'),
      items: [...cart],
      total: total,
      status: 'Pending'
    };
    saveOrder(newOrder);

    // 3. Clear Cart
    clearCart();

    // 4. Open WhatsApp
    // Replace placeholder number with real one
    const phoneNumber = "628123456789"; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');

    // 5. Close Modal
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-end sm:justify-center p-0 sm:p-4">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-black/30 backdrop-blur-sm transition-opacity"
        onClick={onClose}
      ></div>

      {/* Modal Content */}
      <div className="relative w-full h-full sm:h-auto sm:max-w-lg sm:max-h-[90vh] bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border border-white/20 sm:rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom sm:slide-in-from-bottom-10 fade-in duration-300">

        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-200 dark:border-white/10">
          <h2 className="text-xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <CreditCard className="text-indigo-500" />
            Keranjang Belanja
          </h2>
          <button 
            onClick={onClose}
            className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-white/10 transition-colors"
          >
            <X size={20} className="text-gray-500 dark:text-gray-400" />
          </button>
        </div>

        {/* Cart Items */}
        <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
          {cart.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-48 text-gray-500 dark:text-gray-400">
              <p>Keranjang masih kosong.</p>
            </div>
          ) : (
            cart.map((item) => {
              const variant = item.product.variants[item.selectedVariantIndex];
              return (
                <div key={item.id} className="flex gap-4 p-4 rounded-xl bg-white/50 dark:bg-white/5 border border-gray-100 dark:border-white/5">
                  <div className="h-16 w-16 rounded-lg bg-gradient-to-br from-indigo-100 to-purple-100 dark:from-indigo-900 dark:to-purple-900 flex items-center justify-center text-indigo-600 dark:text-indigo-300 font-bold text-xl shrink-0">
                    {item.product.appName.charAt(0)}
                  </div>
                  <div className="flex-1 min-w-0">
                    <h3 className="font-bold text-gray-900 dark:text-white truncate">{item.product.appName}</h3>
                    <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{variant.type} • {variant.duration}</p>
                    <p className="text-sm font-semibold text-indigo-600 dark:text-indigo-400 mt-1">{formatRupiah(variant.price)}</p>
                  </div>
                  <button 
                    onClick={() => removeFromCart(item.id)}
                    className="p-2 text-gray-400 hover:text-red-500 transition-colors"
                  >
                    <Trash2 size={18} />
                  </button>
                </div>
              );
            })
          )}
        </div>

        {/* Footer / Checkout */}
        <div className="p-6 border-t border-gray-200 dark:border-white/10 bg-white/50 dark:bg-black/20">
          {cart.length > 0 && (
            <>
              {/* QRIS Placeholder */}
              <div className="mb-6 p-4 rounded-xl bg-white dark:bg-slate-800 border border-dashed border-gray-300 dark:border-gray-600 text-center">
                <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">Scan QRIS untuk Pembayaran</p>
                {/* Simulated QR Image */}
                <div className="mx-auto w-32 h-32 bg-gray-200 dark:bg-slate-700 rounded-lg flex items-center justify-center">
                  <span className="text-xs text-gray-500">QR CODE IMAGE</span>
                </div>
                <div className="mt-2 flex items-center justify-center gap-1 text-[10px] text-gray-500">
                  <ShieldCheck size={12} />
                  Pembayaran Aman & Terverifikasi
                </div>
              </div>

              <div className="flex justify-between items-center mb-4">
                <span className="text-gray-600 dark:text-gray-300 font-medium">Total Pembayaran</span>
                <span className="text-2xl font-bold text-gray-900 dark:text-white">{formatRupiah(total)}</span>
              </div>

              <button
                onClick={handleCheckout}
                className="w-full flex items-center justify-center gap-2 py-4 rounded-xl bg-[#25D366] hover:bg-[#20bd5a] text-white font-bold text-lg shadow-lg shadow-green-500/30 hover:shadow-green-500/50 hover:-translate-y-0.5 transition-all duration-200"
              >
                <MessageCircle size={24} />
                Konfirmasi via WhatsApp
              </button>
            </>
          )}
        </div>

      </div>
    </div>
  );
};

