import React, { useState } from 'react';
import { CartItem, Order } from '../types';
import { formatRupiah } from '../constants';
import { X, Trash2, MessageCircle, CreditCard, ShieldCheck, Plus, Minus, User } from 'lucide-react';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
  saveOrder: (order: Order) => void;
}

const CartModal: React.FC<CartModalProps> = ({ 
  isOpen, 
  onClose, 
  cart, 
  updateQuantity,
  removeFromCart,
  clearCart,
  saveOrder
}) => {
  const [customerName, setCustomerName] = useState('');
  const [error, setError] = useState('');

  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.product.variants[item.selectedVariantIndex].price * item.quantity), 0);

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (!customerName.trim()) {
      setError('Mohon isi nama Anda terlebih dahulu');
      return;
    }

    // 1. Construct Message
    let message = `Halo Admin, saya ${customerName}, saya ingin memesan:\n\n`;
    cart.forEach((item, index) => {
      const variant = item.product.variants[item.selectedVariantIndex];
      const subtotal = variant.price * item.quantity;
      message += `${index + 1}. ${item.product.appName} - ${variant.type} (${variant.duration}) x${item.quantity}\n   Harga: ${formatRupiah(subtotal)}\n`;
    });
    message += `\nTotal Pembayaran: ${formatRupiah(total)}\n\nMohon diproses.`;

    // 2. Save to History (Simulated)
    const newOrder: Order = {
      id: `ORD-${Date.now()}`,
      date: new Date().toLocaleDateString('id-ID'),
      items: [...cart],
      total: total,
      status: 'Pending'
    };
    saveOrder(newOrder);

    // 3. Clear Cart
    clearCart();

    // 4. Open WhatsApp
    const phoneNumber = "628123456789"; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');

    // 5. Close Modal
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-end sm:justify-center p-0 sm:p-4">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-black/30 backdrop-blur-sm transition-opacity"
        onClick={onClose}
      ></div>

      {/* Modal Content */}
      <div className="relative w-full h-full sm:h-auto sm:max-w-lg sm:max-h-[90vh] bg-white/80 dark:bg-slate-900/80 backdrop-blur-xl border border-white/20 sm:rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-bottom sm:slide-in-from-bottom-10 fade-in duration-300">

        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-200 dark:border-white/10 bg-white/40 dark:bg-white/5">
          <h2 className="text-xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <CreditCard className="text-indigo-500" />
            Keranjang Belanja
          </h2>
          <button 
            onClick={onClose}
            className="p-2 rounded-full hover:bg-gray-100 dark:hover:bg-white/10 transition-colors"
          >
            <X size={20} className="text-gray-500 dark:text-gray-400" />
          </button>
        </div>

        {/* Cart Items */}
        <div className="flex-1 overflow-y-auto p-6 space-y-4 custom-scrollbar">
          {cart.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-48 text-gray-500 dark:text-gray-400">
              <p>Keranjang masih kosong.</p>
            </div>
          ) : (
            cart.map((item) => {
              const variant = item.product.variants[item.selectedVariantIndex];
              return (
                <div key={item.id} className="flex flex-col gap-3 p-4 rounded-xl bg-white/50 dark:bg-white/5 border border-gray-100 dark:border-white/5">
                  <div className="flex gap-4">
                    <div className="h-16 w-16 rounded-lg bg-gradient-to-br from-indigo-100 to-purple-100 dark:from-indigo-900 dark:to-purple-900 flex items-center justify-center text-indigo-600 dark:text-indigo-300 font-bold text-xl shrink-0">
                      {item.product.appName.charAt(0)}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex justify-between items-start">
                        <h3 className="font-bold text-gray-900 dark:text-white truncate">{item.product.appName}</h3>
                        <button 
                          onClick={() => removeFromCart(item.id)}
                          className="text-gray-400 hover:text-red-500 transition-colors p-1"
                        >
                          <Trash2 size={16} />
                        </button>
                      </div>
                      <p className="text-xs text-gray-500 dark:text-gray-400 truncate">{variant.type}</p>
                      <p className="text-sm font-semibold text-indigo-600 dark:text-indigo-400 mt-1">{formatRupiah(variant.price)}</p>
                    </div>
                  </div>

                  {/* Quantity Control */}
                  <div className="flex items-center justify-between pt-2 border-t border-gray-100 dark:border-white/5">
                    <span className="text-xs text-gray-500">Jumlah</span>
                    <div className="flex items-center gap-3 bg-white/60 dark:bg-black/20 rounded-lg p-1">
                      <button 
                        onClick={() => updateQuantity(item.id, -1)}
                        className="p-1 rounded-md hover:bg-gray-200 dark:hover:bg-white/10 text-gray-600 dark:text-gray-300 transition-colors"
                        disabled={item.quantity <= 1}
                      >
                        <Minus size={14} />
                      </button>
                      <span className="text-sm font-bold w-4 text-center text-gray-900 dark:text-white">{item.quantity}</span>
                      <button 
                         onClick={() => updateQuantity(item.id, 1)}
                         className="p-1 rounded-md hover:bg-gray-200 dark:hover:bg-white/10 text-gray-600 dark:text-gray-300 transition-colors"
                      >
                        <Plus size={14} />
                      </button>
                    </div>
                  </div>
                </div>
              );
            })
          )}
        </div>

        {/* Footer / Checkout */}
        <div className="p-6 border-t border-gray-200 dark:border-white/10 bg-white/50 dark:bg-black/20">
          {cart.length > 0 && (
            <div className="space-y-4">
              {/* Name Input */}
              <div>
                <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 mb-1 ml-1">Nama Pemesan</label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <User size={16} className="text-gray-400" />
                  </div>
                  <input
                    type="text"
                    placeholder="Masukkan nama Anda"
                    value={customerName}
                    onChange={(e) => {
                      setCustomerName(e.target.value);
                      setError('');
                    }}
                    className={`block w-full pl-9 pr-3 py-2.5 border rounded-xl bg-white/50 dark:bg-black/20 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500/50 transition-all ${error ? 'border-red-500 ring-1 ring-red-500/50' : 'border-gray-200 dark:border-gray-700'}`}
                  />
                </div>
                {error && <p className="text-xs text-red-500 mt-1 ml-1">{error}</p>}
              </div>

              {/* QRIS Placeholder */}
              <div className="p-4 rounded-xl bg-white dark:bg-slate-800 border border-dashed border-gray-300 dark:border-gray-600 text-center">
                <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">Scan QRIS</p>
                {/* Simulated QR Image */}
                <div className="mx-auto w-24 h-24 bg-gray-200 dark:bg-slate-700 rounded-lg flex items-center justify-center">
                   <span className="text-[10px] text-gray-500">QR CODE</span>
                </div>
                <div className="mt-2 flex items-center justify-center gap-1 text-[10px] text-gray-500">
                  <ShieldCheck size={12} />
                  Verified
                </div>
              </div>

              <div className="flex justify-between items-center pt-2">
                <span className="text-gray-600 dark:text-gray-300 font-medium">Total</span>
                <span className="text-2xl font-bold text-gray-900 dark:text-white">{formatRupiah(total)}</span>
              </div>

              <button
                onClick={handleCheckout}
                className="w-full flex items-center justify-center gap-2 py-3.5 rounded-xl bg-[#25D366] hover:bg-[#20bd5a] text-white font-bold text-lg shadow-lg shadow-green-500/30 hover:shadow-green-500/50 hover:-translate-y-0.5 transition-all duration-200"
              >
                <MessageCircle size={24} />
                Konfirmasi via WhatsApp
              </button>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export default CartModal;

import React, { useState, useEffect, useMemo } from 'react';
import Navbar from './components/Navbar';
import LiquidBackground from './components/LiquidBackground';
import ProductCard from './components/ProductCard';
import CartModal from './components/CartModal';
import WishlistModal from './components/WishlistModal';
import HistoryModal from './components/HistoryModal';
import Toast from './components/Toast';
import TermsModal from './components/TermsModal';
import { PRODUCTS } from './constants';
import { Product, CartItem, Order, Category, ToastMessage } from './types';
import { Info } from 'lucide-react';

const CATEGORIES: Category[] = ['All', 'Streaming', 'Music', 'Design', 'Productivity', 'Other'];

const App: React.FC = () => {
  // Theme State
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark';
    }
    return false;
  });

  // Modal States
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isWishlistOpen, setIsWishlistOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isTermsOpen, setIsTermsOpen] = useState(false);

  // Filter States
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<Category>('All');

  // Data States
  const [cart, setCart] = useState<CartItem[]>([]);
  const [wishlist, setWishlist] = useState<string[]>(() => {
    const saved = localStorage.getItem('wishlist');
    return saved ? JSON.parse(saved) : [];
  });
  const [orderHistory, setOrderHistory] = useState<Order[]>(() => {
    const saved = localStorage.getItem('history');
    return saved ? JSON.parse(saved) : [];
  });
  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  // Effects
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    localStorage.setItem('wishlist', JSON.stringify(wishlist));
  }, [wishlist]);

  useEffect(() => {
    localStorage.setItem('history', JSON.stringify(orderHistory));
  }, [orderHistory]);

  // Toast Logic
  const addToast = (message: string, type: 'success' | 'info') => {
    const id = Date.now();
    setToasts([...toasts, { id, message, type }]);
    // Remove automatically after 3 seconds (handled in component too but good for safety)
    setTimeout(() => removeToast(id), 3500);
  };

  const removeToast = (id: number) => {
    setToasts((current) => current.filter((t) => t.id !== id));
  };

  // Cart Logic
  const addToCart = (product: Product, variantIndex: number) => {
    const existingItem = cart.find(item => item.product.appName === product.appName && item.selectedVariantIndex === variantIndex);

    if (existingItem) {
      updateQuantity(existingItem.id, 1);
    } else {
      const newItem: CartItem = {
        id: `${product.appName}-${variantIndex}-${Date.now()}`,
        product,
        selectedVariantIndex: variantIndex,
        quantity: 1
      };
      setCart([...cart, newItem]);
    }
    addToast(`${product.appName} ditambahkan ke keranjang`, 'success');
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const clearCart = () => setCart([]);

  const saveOrder = (order: Order) => {
    setOrderHistory([order, ...orderHistory]);
    addToast('Pesanan berhasil dibuat!', 'success');
  };

  // Wishlist Logic
  const toggleWishlist = (appName: string) => {
    if (wishlist.includes(appName)) {
      setWishlist(wishlist.filter(id => id !== appName));
      addToast(`${appName} dihapus dari favorit`, 'info');
    } else {
      setWishlist([...wishlist, appName]);
      addToast(`${appName} ditambahkan ke favorit`, 'success');
    }
  };

  const removeFromWishlist = (appName: string) => {
    setWishlist(wishlist.filter(id => id !== appName));
    addToast(`${appName} dihapus dari favorit`, 'info');
  };

  // Filter Logic
  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(product => {
      const matchesSearch = product.appName.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory]);

  return (
    <div className="relative min-h-screen">
      <LiquidBackground />
      <Toast toasts={toasts} removeToast={removeToast} />

      <Navbar 
        toggleTheme={() => setIsDarkMode(!isDarkMode)}
        isDarkMode={isDarkMode}
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)}
        openCart={() => setIsCartOpen(true)}
        openWishlist={() => setIsWishlistOpen(true)}
        openHistory={() => setIsHistoryOpen(true)}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
      />

      <main className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-8 pb-24">
        {/* Header Section */}
        <div className="mb-10 text-center relative">
          <h1 className="text-4xl sm:text-5xl font-extrabold tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-purple-600 dark:from-indigo-400 dark:to-purple-400 mb-4 drop-shadow-sm">
            Premium Apps Store
          </h1>
          <p className="text-lg text-gray-600 dark:text-gray-300 max-w-2xl mx-auto mb-6">
            Upgrade gaya hidup digitalmu dengan langganan aplikasi premium legal, aman, dan bergaransi.
          </p>

          <button 
            onClick={() => setIsTermsOpen(true)}
            className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-white/50 dark:bg-white/10 border border-indigo-200 dark:border-indigo-800 text-sm font-medium text-indigo-700 dark:text-indigo-300 hover:bg-white/80 dark:hover:bg-white/20 transition-all"
          >
            <Info size={16} />
            Syarat & Ketentuan
          </button>

          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[120%] h-[150%] bg-white/30 dark:bg-black/30 blur-3xl -z-10 rounded-full pointer-events-none"></div>
        </div>

        {/* Category Filters */}
        <div className="flex flex-wrap justify-center gap-2 mb-8">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`px-4 py-2 rounded-xl text-sm font-bold transition-all duration-300 border ${
                selectedCategory === cat
                  ? 'bg-indigo-600 text-white border-indigo-600 shadow-lg shadow-indigo-500/30'
                  : 'bg-white/40 dark:bg-black/40 text-gray-600 dark:text-gray-300 border-white/40 dark:border-white/10 hover:bg-white/60 dark:hover:bg-white/10'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Product Grid */}
        {filteredProducts.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredProducts.map((product, index) => (
              <ProductCard 
                key={index}
                product={product}
                addToCart={addToCart}
                toggleWishlist={toggleWishlist}
                isWishlisted={wishlist.includes(product.appName)}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-20">
            <p className="text-gray-500 dark:text-gray-400 text-lg">Tidak ada produk yang ditemukan.</p>
            <button 
              onClick={() => {setSearchQuery(''); setSelectedCategory('All');}}
              className="mt-4 text-indigo-500 hover:underline"
            >
              Reset Filter
            </button>
          </div>
        )}
      </main>

      {/* Modals */}
      <CartModal 
        isOpen={isCartOpen}
        onClose={() => setIsCartOpen(false)}
        cart={cart}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
        saveOrder={saveOrder}
      />

      <WishlistModal 
        isOpen={isWishlistOpen}
        onClose={() => setIsWishlistOpen(false)}
        wishlistIds={wishlist}
        allProducts={PRODUCTS}
        removeFromWishlist={removeFromWishlist}
      />

      <HistoryModal
        isOpen={isHistoryOpen}
        onClose={() => setIsHistoryOpen(false)}
        history={orderHistory}
      />

      <TermsModal 
        isOpen={isTermsOpen}
        onClose={() => setIsTermsOpen(false)}
      />

      {/* Footer */}
      <footer className="text-center py-8 text-gray-500 dark:text-gray-400 text-sm">
        <p>&copy; {new Date().getFullYear()} PremiumStore. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';

const LiquidBackground: React.FC = () => {
  return (
    <div className="fixed inset-0 w-full h-full -z-50 overflow-hidden pointer-events-none">
      {/* Base Gradient - Luxurious Dark */}
      <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-stone-200 via-stone-100 to-stone-200 dark:from-[#1a0505] dark:via-[#0f0505] dark:to-[#050505] transition-colors duration-500"></div>

