import { X, Trash2, MessageCircle, CreditCard, ShieldCheck, Plus, Minus, User, ShoppingBag } from 'lucide-react';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
  saveOrder: (order: Order) => void;
}

const CartModal: React.FC<CartModalProps> = ({ 
  isOpen, 
  onClose, 
  cart, 
  updateQuantity,
  removeFromCart,
  clearCart,
  saveOrder
}) => {
  const [customerName, setCustomerName] = useState('');
  const [error, setError] = useState('');

  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.product.variants[item.selectedVariantIndex].price * item.quantity), 0);

  const handleCheckout = () => {
    if (cart.length === 0) return;
    if (!customerName.trim()) {
      setError('Please enter your name to proceed');
      return;
    }

    // 1. Construct Message
    let message = `*PREMIUM ORDER REQUEST*\n\nName: ${customerName}\n\n*Items:*\n`;
    cart.forEach((item, index) => {
      const variant = item.product.variants[item.selectedVariantIndex];
      const subtotal = variant.price * item.quantity;
      message += `${index + 1}. ${item.product.appName} - ${variant.type} (${variant.duration}) x${item.quantity}\n   Price: ${formatRupiah(subtotal)}\n`;
    });
    message += `\n*Total: ${formatRupiah(total)}*\n\nPlease process my order. Thank you.`;

    const newOrder: Order = {
      id: `ORD-${Date.now()}`,
      date: new Date().toLocaleDateString('id-ID'),
      items: [...cart],
      total: total,
      status: 'Pending'
    };
    saveOrder(newOrder);
    clearCart();

    const phoneNumber = "6282116505311"; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-end sm:justify-center p-0 sm:p-4 font-sans">
