import React, { useState, useEffect, useRef } from 'react';
import { CartItem, Order } from '../types';
import { formatRupiah } from '../constants';
import { X, MessageCircle, ShieldCheck, User, Receipt, Clock, Hash, Upload, Image as ImageIcon, Trash2 } from 'lucide-react';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: () => void;
  saveOrder: (order: Order) => void;
}

const CartModal: React.FC<CartModalProps> = ({ 
  isOpen, 
  onClose, 
  cart, 
  clearCart,
  saveOrder
}) => {
  const [customerName, setCustomerName] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [paymentProof, setPaymentProof] = useState<string | null>(null);
  const [error, setError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Generate Unique Invoice Number when modal opens
  useEffect(() => {
    if (isOpen) {
      const date = new Date();
      const dateStr = date.toISOString().slice(0, 10).replace(/-/g, ''); // YYYYMMDD
      const randomStr = Math.floor(1000 + Math.random() * 9000).toString(); // 4 digit random
      setInvoiceNumber(`INV-${dateStr}-${randomStr}`);
      setCustomerName(''); 
      setPaymentProof(null);
      setError('');
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const total = cart.reduce((acc, item) => acc + (item.product.variants[item.selectedVariantIndex].price * item.quantity), 0);
  const currentDate = new Date().toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
  const currentTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Create a fake local URL for preview
      const objectUrl = URL.createObjectURL(file);
      setPaymentProof(objectUrl);
      setError('');
    }
  };

  const handleCheckout = () => {
    if (cart.length === 0) return;

    if (!customerName.trim()) {
      setError('Nama wajib diisi.');
      return;
    }

    if (!paymentProof) {
      setError('Wajib upload bukti pembayaran sebelum konfirmasi.');
      return;
    }

    // 1. Construct Item Detail String for WhatsApp
    let itemDetails = cart.map((item) => {
      const variant = item.product.variants[item.selectedVariantIndex];
      return `${item.product.appName} [${variant.type} - ${variant.duration}]`;
    }).join(', ');

    // 2. Construct Specific WhatsApp Message
    // "Halo Admin, saya sudah melakukan pembayaran. No Invoice: [Nomor_Invoice]. Item: [Detail Pesanan]. Total: [Total_Harga]. Status: SUDAH UPLOAD BUKTI. Mohon diproses ya!"
    const message = `Halo Admin, saya sudah melakukan pembayaran. 
No Invoice: ${invoiceNumber}
Nama: ${customerName}
Item: ${itemDetails}
Total: ${formatRupiah(total)}

Status: SUDAH UPLOAD BUKTI. 
Mohon diproses ya!`;

    // 3. Save Order to History with "Processing" status (Sedang Diproses/Diverifikasi)
    const newOrder: Order = {
      id: invoiceNumber,
      date: new Date().toLocaleDateString('id-ID'),
      items: [...cart],
      total: total,
      status: 'Processing', // Changed to Processing upon upload
      paymentProof: paymentProof
    };
    saveOrder(newOrder);

    // 4. Clear and Redirect
    clearCart();
    const phoneNumber = "6282116505311"; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 font-sans">
      <div 
        className="absolute inset-0 bg-burgundy-950/80 dark:bg-black/90 backdrop-blur-md transition-opacity"
        onClick={onClose}
      ></div>

      <div className="relative w-full max-w-md max-h-[90vh] bg-stone-50/95 dark:bg-[#1a0505]/95 backdrop-blur-2xl border border-burgundy-900/30 dark:border-white/10 rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Receipt Header - Deep Burgundy Theme */}
        <div className="flex items-center justify-between p-5 border-b border-burgundy-900/10 dark:border-white/10 bg-gradient-to-r from-burgundy-100/50 to-stone-100/50 dark:from-burgundy-950/50 dark:to-black/50">
          <div>
            <h2 className="text-lg font-bold text-burgundy-900 dark:text-stone-100 flex items-center gap-2 font-serif tracking-wide">
              <Receipt size={18} className="text-burgundy-700 dark:text-gold-500" />
              DIGITAL INVOICE
            </h2>
            <p className="text-[10px] text-stone-500 uppercase tracking-widest mt-1">Dhevv Premium Store</p>
          </div>
          <button 
            onClick={onClose}
            className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors text-stone-500"
          >
            <X size={20} />
          </button>
        </div>

        {/* Receipt Content */}
        <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">

          {/* Invoice Meta */}
          <div className="flex justify-between items-end mb-6 text-xs text-stone-500 dark:text-stone-400 font-mono">
            <div className="space-y-1">
              <div className="flex items-center gap-2">
                <Hash size={12} />
                <span className="font-bold text-burgundy-900 dark:text-stone-200">{invoiceNumber}</span>
              </div>
              <div className="flex items-center gap-2">
                <Clock size={12} />
                <span>{currentDate}, {currentTime}</span>
              </div>
            </div>
            <div className="text-right">
              <span className="inline-block px-2 py-1 rounded-md bg-burgundy-100 dark:bg-burgundy-900/30 text-burgundy-800 dark:text-burgundy-400 font-bold border border-burgundy-200 dark:border-burgundy-800/30 uppercase tracking-wider text-[10px]">
                Payment Required
              </span>
            </div>
          </div>

          {/* Item List */}
          <div className="space-y-3 mb-6">
            <div className="text-[10px] uppercase tracking-widest text-stone-400 border-b border-stone-200 dark:border-white/10 pb-2 mb-2 flex justify-between">
              <span>Item Description</span>
              <span>Subtotal</span>
            </div>

            {cart.length === 0 ? (
               <p className="text-center text-sm text-stone-400 italic py-4">No items in invoice.</p>
            ) : (
              cart.map((item) => {
                const variant = item.product.variants[item.selectedVariantIndex];
                const subtotal = variant.price * item.quantity;
                return (
                  <div key={item.id} className="flex justify-between items-start text-sm group">
                    <div className="pr-4">
                      <p className="font-bold text-burgundy-950 dark:text-stone-200">{item.product.appName}</p>
                      <p className="text-xs text-stone-500">{variant.type} ({variant.duration}) x{item.quantity}</p>
                    </div>
                    <p className="font-mono text-burgundy-900 dark:text-stone-300 whitespace-nowrap">
                      {formatRupiah(subtotal)}
                    </p>
                  </div>
                );
              })
            )}
          </div>

          {/* Divider */}
          <div className="border-t border-dashed border-stone-300 dark:border-white/20 mb-4"></div>

          {/* Totals */}
          <div className="flex justify-between items-center mb-8">
            <span className="text-stone-600 dark:text-stone-400 font-bold">Total Bill</span>
            <span className="text-2xl font-bold text-burgundy-900 dark:text-gold-400 font-mono">
              {formatRupiah(total)}
            </span>
          </div>

          {/* QRIS Section - Elegant Card */}
          <div className="bg-white dark:bg-black/40 p-5 rounded-2xl border border-stone-200 dark:border-white/10 text-center mb-6 relative overflow-hidden shadow-inner">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-burgundy-900 via-gold-500 to-burgundy-900"></div>

            <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-4">Scan QRIS to Pay</p>

            <div className="mx-auto w-48 h-auto bg-white p-2.5 rounded-xl shadow-md border border-stone-100">
               <img 
                 src="https://user2158.na.imgto.link/public/20260210/img-1294.avif" 
                 alt="QRIS Payment"
                 className="w-full h-full object-contain rounded-lg"
               />
            </div>

            <div className="mt-4 flex items-center justify-center gap-1.5 text-[10px] text-stone-500 dark:text-stone-400">
              <ShieldCheck size={12} className="text-emerald-500" />
              <span>Verified Merchant • Secure Transaction</span>
            </div>
          </div>

          {/* Customer Inputs */}
          <div className="space-y-4">

            {/* Name Input */}
            <div>
              <label className="block text-xs font-bold text-stone-500 dark:text-stone-400 mb-2 ml-1 uppercase">Your Name</label>
              <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <User size={16} className="text-stone-400" />
                  </div>
                  <input
                    type="text"
                    placeholder="Enter your name..."
                    value={customerName}
                    onChange={(e) => {
                      setCustomerName(e.target.value);
                      setError('');
                    }}
                    className="block w-full pl-9 pr-3 py-3 border rounded-xl bg-white/50 dark:bg-black/20 text-sm focus:outline-none focus:ring-1 focus:ring-gold-500/50 transition-all border-burgundy-900/10 dark:border-white/10 text-burgundy-950 dark:text-stone-100 placeholder-stone-400"
                  />
              </div>
            </div>

            {/* Payment Proof Upload */}
            <div>
              <label className="block text-xs font-bold text-stone-500 dark:text-stone-400 mb-2 ml-1 uppercase">
                Upload Payment Proof <span className="text-red-500">*</span>
              </label>

              {!paymentProof ? (
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="group cursor-pointer border-2 border-dashed border-stone-300 dark:border-white/20 hover:border-burgundy-500 dark:hover:border-gold-500/50 rounded-xl p-6 transition-all flex flex-col items-center justify-center bg-stone-50/50 dark:bg-white/5 hover:bg-white/80 dark:hover:bg-white/10"
                >
                  <div className="h-10 w-10 mb-2 rounded-full bg-stone-200 dark:bg-white/10 flex items-center justify-center text-stone-500 dark:text-stone-400 group-hover:scale-110 transition-transform">
                    <Upload size={20} />
                  </div>
                  <p className="text-xs font-medium text-stone-600 dark:text-stone-300">Click to upload screenshot</p>
                  <p className="text-[10px] text-stone-400 mt-1">JPG, PNG supported</p>
                </div>
              ) : (
                <div className="relative rounded-xl overflow-hidden border border-burgundy-900/10 dark:border-white/10 group">
                  <img src={paymentProof} alt="Proof" className="w-full h-32 object-cover" />
                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <button 
                      onClick={() => setPaymentProof(null)}
                      className="p-2 bg-red-500 rounded-full text-white hover:bg-red-600 transition-colors shadow-lg"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                  <div className="absolute bottom-2 left-2 px-2 py-1 bg-black/60 rounded text-[10px] text-white flex items-center gap-1">
                    <ImageIcon size={10} /> Image Uploaded
                  </div>
                </div>
              )}
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept="image/*"
              />
            </div>

            {error && (
              <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-500/20 flex items-center gap-2 animate-pulse">
                <ShieldCheck size={16} className="text-red-500" />
                <p className="text-xs text-red-600 dark:text-red-400 font-medium">{error}</p>
              </div>
            )}

          </div>

        </div>

        {/* Footer Action */}
        <div className="p-5 border-t border-burgundy-900/5 dark:border-white/5 bg-stone-100/50 dark:bg-black/30 backdrop-blur-sm">
          <button
            onClick={handleCheckout}
