import React, { useState } from 'react';
import { User as UserType, Order, Product } from '../types';
import { X, User, Package, Heart, LogOut, Sparkles, Clock, CheckCircle, Hourglass, FileCheck } from 'lucide-react';
import { formatRupiah } from '../constants';

interface DashboardModalProps {
  isOpen: boolean;
  onClose: () => void;
  user: UserType;
  orders: Order[];
  wishlist: string[];
  allProducts: Product[];
  onLogout: () => void;
  removeFromWishlist: (appName: string) => void;
}

type Tab = 'overview' | 'orders' | 'wishlist';

const DashboardModal: React.FC<DashboardModalProps> = ({ 
  isOpen, 
  onClose, 
  user,
  orders,
  wishlist,
  allProducts,
  onLogout,
  removeFromWishlist
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('overview');

  if (!isOpen) return null;

  const wishlistProducts = allProducts.filter(p => wishlist.includes(p.appName));

  const getStatusColor = (status: Order['status']) => {
    switch (status) {
      case 'Processing': return 'text-emerald-600 dark:text-emerald-400 bg-emerald-100 dark:bg-emerald-900/30';
      case 'Completed': return 'text-emerald-600 dark:text-emerald-400 bg-emerald-100 dark:bg-emerald-900/30';
      default: return 'text-amber-600 dark:text-amber-400 bg-amber-100 dark:bg-amber-900/30';
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
       <div 
        className="absolute inset-0 bg-burgundy-950/80 dark:bg-black/90 backdrop-blur-md transition-opacity"
        onClick={onClose}
      ></div>

      <div className="relative w-full max-w-4xl h-[85vh] bg-stone-50 dark:bg-[#1a0505] border border-burgundy-900/10 dark:border-white/10 rounded-3xl shadow-2xl flex overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Sidebar */}
        <div className="w-20 md:w-64 bg-white/50 dark:bg-black/20 border-r border-burgundy-900/5 dark:border-white/5 flex flex-col">
          <div className="p-6 flex items-center gap-3 border-b border-burgundy-900/5 dark:border-white/5">
            <div className="h-10 w-10 rounded-full bg-gradient-to-br from-gold-400 to-gold-600 flex items-center justify-center text-burgundy-950 font-bold shadow-lg">
              {user.name.charAt(0).toUpperCase()}
            </div>
            <div className="hidden md:block overflow-hidden">
              <p className="font-bold text-burgundy-950 dark:text-stone-100 truncate">{user.name}</p>
              <p className="text-[10px] text-stone-500 uppercase tracking-wider">Member</p>
            </div>
          </div>

          <nav className="flex-1 p-4 space-y-2">
            <button 
              onClick={() => setActiveTab('overview')}
              className={`w-full flex items-center gap-3 p-3 rounded-xl transition-all ${activeTab === 'overview' ? 'bg-burgundy-950 dark:bg-stone-100 text-white dark:text-burgundy-950 shadow-lg' : 'text-stone-500 hover:bg-black/5 dark:hover:bg-white/5'}`}
            >
              <User size={20} />
              <span className="hidden md:block font-medium text-sm">Overview</span>
            </button>
            <button 
              onClick={() => setActiveTab('orders')}
              className={`w-full flex items-center gap-3 p-3 rounded-xl transition-all ${activeTab === 'orders' ? 'bg-burgundy-950 dark:bg-stone-100 text-white dark:text-burgundy-950 shadow-lg' : 'text-stone-500 hover:bg-black/5 dark:hover:bg-white/5'}`}
            >
              <Package size={20} />
              <span className="hidden md:block font-medium text-sm">My Orders</span>
            </button>
            <button 
              onClick={() => setActiveTab('wishlist')}
              className={`w-full flex items-center gap-3 p-3 rounded-xl transition-all ${activeTab === 'wishlist' ? 'bg-burgundy-950 dark:bg-stone-100 text-white dark:text-burgundy-950 shadow-lg' : 'text-stone-500 hover:bg-black/5 dark:hover:bg-white/5'}`}
            >
              <Heart size={20} />
              <span className="hidden md:block font-medium text-sm">Wishlist</span>
            </button>
          </nav>

          <div className="p-4 border-t border-burgundy-900/5 dark:border-white/5">
            <button 
              onClick={() => { onLogout(); onClose(); }}
              className="w-full flex items-center gap-3 p-3 rounded-xl text-red-500 hover:bg-red-50 dark:hover:bg-red-900/10 transition-all"
            >
              <LogOut size={20} />
              <span className="hidden md:block font-medium text-sm">Logout</span>
            </button>
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 flex flex-col bg-stone-50/50 dark:bg-transparent overflow-hidden">
          {/* Header */}
          <div className="h-16 flex items-center justify-between px-6 border-b border-burgundy-900/5 dark:border-white/5">
            <h2 className="text-xl font-bold font-serif text-burgundy-950 dark:text-stone-100 capitalize">
              {activeTab === 'overview' ? 'Dashboard Overview' : activeTab}
            </h2>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 text-stone-500">
              <X size={20} />
            </button>
          </div>

          {/* Content Area */}
          <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">

            {/* OVERVIEW TAB */}
            {activeTab === 'overview' && (
              <div className="space-y-6">
                {/* Stats Cards */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div className="p-5 rounded-2xl bg-white dark:bg-white/5 border border-burgundy-900/5 dark:border-white/5 shadow-sm">
                    <p className="text-xs text-stone-500 uppercase tracking-wider mb-1">Total Orders</p>
                    <p className="text-3xl font-bold text-burgundy-900 dark:text-gold-400">{orders.length}</p>
                  </div>
                  <div className="p-5 rounded-2xl bg-white dark:bg-white/5 border border-burgundy-900/5 dark:border-white/5 shadow-sm">
                     <p className="text-xs text-stone-500 uppercase tracking-wider mb-1">Wishlist Items</p>
                    <p className="text-3xl font-bold text-burgundy-900 dark:text-gold-400">{wishlist.length}</p>
                  </div>
                   <div className="p-5 rounded-2xl bg-gradient-to-br from-burgundy-900 to-black text-white shadow-lg">
                     <p className="text-xs text-white/60 uppercase tracking-wider mb-1">Member Since</p>
                    <p className="text-xl font-bold">{user.memberSince}</p>
                  </div>
                </div>

                {/* Recent Activity */}
                <div className="bg-white dark:bg-white/5 rounded-2xl border border-burgundy-900/5 dark:border-white/5 p-6">
                  <h3 className="font-bold text-burgundy-950 dark:text-stone-100 mb-4">Recent Activity</h3>
                  {orders.length > 0 ? (
                    <div className="space-y-4">
                      {orders.slice(0, 3).map(order => (
                        <div key={order.id} className="flex items-center justify-between pb-4 border-b border-stone-100 dark:border-white/5 last:border-0 last:pb-0">
                          <div className="flex items-center gap-3">
                            <div className="p-2 rounded-lg bg-stone-100 dark:bg-white/10 text-burgundy-900 dark:text-stone-300">
                              <Package size={18} />
                            </div>
                            <div>
                              <p className="text-sm font-bold text-burgundy-950 dark:text-stone-200">Order {order.id}</p>
                              <p className="text-xs text-stone-500">{order.date}</p>
                            </div>
                          </div>
                          <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${getStatusColor(order.status)}`}>
                            {order.status === 'Processing' ? 'Sedang Diverifikasi' : order.status === 'Completed' ? 'Berhasil' : 'Menunggu'}
                          </span>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <p className="text-sm text-stone-500 italic">No recent activity.</p>
                  )}
                </div>
              </div>
            )}

            {/* ORDERS TAB */}
            {activeTab === 'orders' && (
               <div className="space-y-4">
                 {orders.length === 0 ? (
                    <div className="text-center py-10 text-stone-400">
                      <Package size={40} className="mx-auto mb-3 opacity-50" />
                      <p>You haven't placed any orders yet.</p>
                    </div>
                 ) : (
                   orders.map(order => (
                     <div key={order.id} className="bg-white dark:bg-white/5 rounded-2xl border border-burgundy-900/5 dark:border-white/5 p-5 hover:border-gold-500/30 transition-all">
                       <div className="flex justify-between items-start mb-4">
                         <div>
                            <div className="flex items-center gap-2 mb-1">
                                <span className={`h-2 w-2 rounded-full ${order.status === 'Pending' ? 'bg-amber-500' : 'bg-emerald-500'}`}></span>
                                <h3 className="font-bold text-burgundy-950 dark:text-stone-100 text-sm">{order.id}</h3>
                            </div>
                            <p className="text-xs text-stone-500">{order.date}</p>
                         </div>
                         <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${getStatusColor(order.status)}`}>
                           {order.status === 'Processing' ? 'Verifying' : order.status}
                         </span>
                       </div>

                       <div className="space-y-2 mb-4 bg-stone-50 dark:bg-black/20 p-3 rounded-xl">
                          {order.items.map((item, i) => (
                            <div key={i} className="flex justify-between text-sm">
                              <span className="text-stone-600 dark:text-stone-300">{item.product.appName} <span className="text-stone-400 text-xs">({item.product.variants[item.selectedVariantIndex].type})</span></span>
                              <span className="font-medium text-burgundy-900 dark:text-stone-200">{formatRupiah(item.product.variants[item.selectedVariantIndex].price)}</span>
                            </div>
                          ))}
                       </div>

                       <div className="flex justify-between items-center pt-2 border-t border-dashed border-stone-200 dark:border-white/10">
                          {order.paymentProof ? (
                             <span className="text-[10px] text-emerald-600 dark:text-emerald-400 flex items-center gap-1">
                               <FileCheck size={12} /> Proof Uploaded
                             </span>
                          ) : (
                            <span className="text-[10px] text-amber-600 dark:text-amber-400 flex items-center gap-1">
                               <Hourglass size={12} /> Waiting Proof
                             </span>
                          )}
                          <p className="font-bold text-burgundy-900 dark:text-gold-400 font-serif">Total: {formatRupiah(order.total)}</p>
                       </div>
                     </div>
                   ))
                 )}
               </div>
            )}

            {/* WISHLIST TAB */}
            {activeTab === 'wishlist' && (
              <div className="grid grid-cols-1 gap-3">
                 {wishlistProducts.length === 0 ? (
                    <div className="text-center py-10 text-stone-400">
                      <Sparkles size={40} className="mx-auto mb-3 opacity-50" />
                      <p>Your wishlist is empty.</p>
                    </div>
                 ) : (
                   wishlistProducts.map(product => (
                    <div key={product.appName} className="flex items-center justify-between p-4 rounded-xl bg-white dark:bg-white/5 border border-burgundy-900/5 dark:border-white/5 transition-colors group">
                      <div className="flex items-center gap-4">
                        <div className="h-12 w-12 rounded-lg bg-stone-200 dark:bg-white/10 flex items-center justify-center font-bold text-burgundy-900 dark:text-gold-500 font-serif text-lg">
                          {product.appName.charAt(0)}
                        </div>
                        <div>
                          <h3 className="font-bold text-burgundy-950 dark:text-stone-100 text-sm group-hover:text-gold-600 transition-colors">{product.appName}</h3>
                          <p className="text-xs text-stone-500">From {formatRupiah(product.variants[0].price)}</p>
                        </div>
                      </div>
                      <button 
                        onClick={() => removeFromWishlist(product.appName)}
                        className="p-2 rounded-full hover:bg-red-50 dark:hover:bg-red-900/20 text-stone-400 hover:text-red-500 transition-colors"
                        title="Remove"
                      >
                        <X size={16} />
                      </button>
                    </div>
                  ))
                 )}
              </div>
            )}

          </div>
        </div>
      </div>
    </div>
  );
};

