const CATEGORIES: Category[] = ['All', 'Streaming', 'Music', 'Design', 'Productivity', 'Other'];

const App: React.FC = () => {
  // Theme State
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark';
    }
    return false;
  });

  // User Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('currentUser');
    return saved ? JSON.parse(saved) : null;
  });

  // Modal States
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isWishlistOpen, setIsWishlistOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isTermsOpen, setIsTermsOpen] = useState(false);
  const [isAuthOpen, setIsAuthOpen] = useState(false);
  const [isAnnouncementOpen, setIsAnnouncementOpen] = useState(false);
  const [isDashboardOpen, setIsDashboardOpen] = useState(false);

  // Filter States
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<Category>('All');

  // Data States
  const [cart, setCart] = useState<CartItem[]>([]);
  const [wishlist, setWishlist] = useState<string[]>(() => {
    const saved = localStorage.getItem('wishlist');
    return saved ? JSON.parse(saved) : [];
  });
  const [orderHistory, setOrderHistory] = useState<Order[]>(() => {
    const saved = localStorage.getItem('history');
    return saved ? JSON.parse(saved) : [];
  });
  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  // Effects
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    localStorage.setItem('wishlist', JSON.stringify(wishlist));
  }, [wishlist]);

  useEffect(() => {
    localStorage.setItem('history', JSON.stringify(orderHistory));
  }, [orderHistory]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('currentUser', JSON.stringify(user));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [user]);

  // Toast Logic
  const addToast = (message: string, type: 'success' | 'info') => {
    const id = Date.now();
    setToasts([...toasts, { id, message, type }]);
    setTimeout(() => removeToast(id), 3500);
  };

  const removeToast = (id: number) => {
    setToasts((current) => current.filter((t) => t.id !== id));
  };

  // Auth Logic
  const handleLogin = (newUser: User) => {
    setUser(newUser);
    setIsAuthOpen(false);
    // Show announcement after short delay for effect
    setTimeout(() => setIsAnnouncementOpen(true), 300);
    addToast(`Welcome back, ${newUser.name}!`, 'success');
  };

  const handleLogout = () => {
    setUser(null);
    setIsDashboardOpen(false);
    addToast('Logged out successfully', 'info');
  };

  // Cart Logic
  const addToCart = (product: Product, variantIndex: number) => {
    const existingItem = cart.find(item => item.product.appName === product.appName && item.selectedVariantIndex === variantIndex);

    if (existingItem) {
      updateQuantity(existingItem.id, 1);
    } else {
      const newItem: CartItem = {
        id: `${product.appName}-${variantIndex}-${Date.now()}`,
        product,
        selectedVariantIndex: variantIndex,
        quantity: 1
      };
      setCart([...cart, newItem]);
    }
    addToast(`${product.appName} added to bag`, 'success');
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const clearCart = () => setCart([]);

  const saveOrder = (order: Order) => {
    setOrderHistory([order, ...orderHistory]);
    addToast('Order confirmed successfully!', 'success');
  };

  // Wishlist Logic
  const toggleWishlist = (appName: string) => {
    if (wishlist.includes(appName)) {
      setWishlist(wishlist.filter(id => id !== appName));
      addToast(`${appName} removed from wishlist`, 'info');
    } else {
      setWishlist([...wishlist, appName]);
      addToast(`${appName} added to wishlist`, 'success');
    }
  };

  const removeFromWishlist = (appName: string) => {
    setWishlist(wishlist.filter(id => id !== appName));
    addToast(`${appName} removed from wishlist`, 'info');
  };

  // Filter Logic
  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(product => {
      const matchesSearch = product.appName.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory]);

  return (
    <div className="relative min-h-screen font-sans selection:bg-gold-500/30">
      <LiquidBackground />
      <Toast toasts={toasts} removeToast={removeToast} />

      <Navbar 
        toggleTheme={() => setIsDarkMode(!isDarkMode)}
        isDarkMode={isDarkMode}
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)}
        openCart={() => setIsCartOpen(true)}
        openWishlist={() => user ? setIsDashboardOpen(true) : setIsWishlistOpen(true)}
        openHistory={() => user ? setIsDashboardOpen(true) : setIsHistoryOpen(true)}
        openAuth={() => setIsAuthOpen(true)}
        openDashboard={() => setIsDashboardOpen(true)}
        user={user}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
      />

      <main className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-12 pb-24">
        {/* Header Section */}
        <div className="mb-14 text-center relative z-10">
          <div className="inline-flex items-center justify-center p-2 mb-6 rounded-full bg-burgundy-900/5 dark:bg-white/5 border border-burgundy-900/10 dark:border-white/10 backdrop-blur-sm animate-fade-in-up">
            <span className="px-3 py-1 text-xs font-bold tracking-widest uppercase text-burgundy-800 dark:text-gold-400">
              250++ Account Has Been Sell
            </span>
          </div>

          <h1 className="text-5xl sm:text-7xl font-bold tracking-tight mb-6 drop-shadow-xl">
            <span className="block text-burgundy-950 dark:text-stone-100 mb-2">Elevate Your</span>
            <span className="bg-clip-text text-transparent bg-gradient-to-r from-burgundy-800 via-burgundy-600 to-gold-600 dark:from-gold-300 dark:via-gold-500 dark:to-stone-100 font-serif italic">
              Digital Lifestyle
            </span>
          </h1>

          <p className="text-lg text-burgundy-900/70 dark:text-stone-400 max-w-2xl mx-auto mb-8 font-light leading-relaxed">
            Curated selection of premium subscriptions. Secure, warrantied, and instantly delivered to you.
          </p>

          <button 
            onClick={() => setIsTermsOpen(true)}
            className="group inline-flex items-center gap-2 px-6 py-2.5 rounded-full bg-white/40 dark:bg-white/5 border border-burgundy-900/20 dark:border-white/10 text-sm font-medium text-burgundy-900 dark:text-stone-300 hover:bg-white/60 dark:hover:bg-white/10 transition-all hover:border-gold-500/30"
          >
            <Sparkles size={14} className="text-gold-500" />
            <span>Service Guarantee & Terms</span>
          </button>
        </div>

        {/* Category Filters */}
        <div className="flex flex-wrap justify-center gap-3 mb-12 relative z-10">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`px-5 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 border backdrop-blur-md ${
                selectedCategory === cat
                  ? 'bg-burgundy-950 dark:bg-stone-100 text-stone-100 dark:text-burgundy-950 border-burgundy-950 dark:border-stone-100 shadow-lg shadow-burgundy-900/20'
                  : 'bg-white/30 dark:bg-black/20 text-burgundy-900/70 dark:text-stone-400 border-burgundy-900/5 dark:border-white/5 hover:bg-white/50 dark:hover:bg-white/10 hover:border-gold-500/30'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Product Grid */}
        {filteredProducts.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 relative z-10">
            {filteredProducts.map((product, index) => (
              <ProductCard 
                key={index}
                product={product}
                addToCart={addToCart}
                toggleWishlist={toggleWishlist}
                isWishlisted={wishlist.includes(product.appName)}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-20 relative z-10">
            <div className="inline-flex h-16 w-16 items-center justify-center rounded-full bg-burgundy-100/50 dark:bg-white/5 mb-4 text-burgundy-300 dark:text-stone-600">
               <Sparkles size={32} />
            </div>
            <p className="text-burgundy-900/50 dark:text-stone-500 text-lg">No collections found matching your criteria.</p>
            <button 
              onClick={() => {setSearchQuery(''); setSelectedCategory('All');}}
              className="mt-4 text-burgundy-700 dark:text-gold-500 hover:underline font-medium"
            >
              Clear Filters
            </button>
          </div>
        )}
      </main>

      {/* Modals */}
      <CartModal 
        isOpen={isCartOpen}
        onClose={() => setIsCartOpen(false)}
        cart={cart}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
        saveOrder={saveOrder}
      />

      {/* Render standalone modals only if user is NOT logged in (otherwise they are in dashboard) */}
      {!user && (
        <>
          <WishlistModal 
            isOpen={isWishlistOpen}
            onClose={() => setIsWishlistOpen(false)}
            wishlistIds={wishlist}
            allProducts={PRODUCTS}
            removeFromWishlist={removeFromWishlist}
          />

          <HistoryModal
            isOpen={isHistoryOpen}
            onClose={() => setIsHistoryOpen(false)}
            history={orderHistory}
          />
        </>
      )}

      <TermsModal 
        isOpen={isTermsOpen}
        onClose={() => setIsTermsOpen(false)}
      />

      <AuthModal 
        isOpen={isAuthOpen}
        onClose={() => setIsAuthOpen(false)}
        onLogin={handleLogin}
      />

      <AnnouncementModal 
        isOpen={isAnnouncementOpen}
        onClose={() => setIsAnnouncementOpen(false)}
      />

      {user && (
        <DashboardModal 
          isOpen={isDashboardOpen}
          onClose={() => setIsDashboardOpen(false)}
          user={user}
          orders={orderHistory}
          wishlist={wishlist}
          allProducts={PRODUCTS}
          onLogout={handleLogout}
          removeFromWishlist={removeFromWishlist}
        />
      )}

      {/* Footer */}
      <footer className="text-center py-8 border-t border-burgundy-900/5 dark:border-white/5 mt-auto relative z-10 bg-white/30 dark:bg-black/20 backdrop-blur-md">
        <p className="text-sm text-burgundy-900/40 dark:text-stone-500 font-serif italic">
          &copy; {new Date().getFullYear()} Dhevv Premium Digital. Elevating Standards.
        </p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Play, Music, PenTool, ArrowRight } from 'lucide-react';

interface Panel {
  id: string;
  title: string;
  subtitle: string;
  description: string;
  image: string;
  icon: React.ReactNode;
  category: string;
}

const PANELS: Panel[] = [
  {
    id: 'streaming',
    title: "Unlimited Streaming",
    subtitle: "Netflix, Disney+, Prime",
    description: "Access a world of cinema-quality entertainment. Premium accounts for the ultimate binge-watching experience.",
    image: "https://images.unsplash.com/photo-1574375927938-d5a98e8ffe85?q=80&w=2669&auto=format&fit=crop",
    icon: <Play className="w-5 h-5" fill="currentColor" />,
    category: "Streaming"
  },
  {
    id: 'music',
    title: "High Fidelity Audio",
    subtitle: "Spotify, Apple Music",
    description: "Immerse yourself in ad-free music with premium sound quality. Your soundtrack, uninterrupted.",
    image: "https://images.unsplash.com/photo-1614680376593-902f74cf0d41?q=80&w=2574&auto=format&fit=crop",
    icon: <Music className="w-5 h-5" />,
    category: "Music"
  },
  {
    id: 'creative',
    title: "Creative Suite",
    subtitle: "Canva, Adobe, CapCut",
    description: "Professional tools for designers and creators. Unlock your full potential with premium features.",
    image: "https://images.unsplash.com/photo-1626785774573-4b799314346d?q=80&w=2670&auto=format&fit=crop",
    icon: <PenTool className="w-5 h-5" />,
    category: "Design"
  }
];

interface HeroSectionProps {
  onCategorySelect: (category: string) => void;
}

const HeroSection: React.FC<HeroSectionProps> = ({ onCategorySelect }) => {
  const [activeId, setActiveId] = useState<string>('streaming');
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  // Parallax Effect Handler
  const handleMouseMove = (e: React.MouseEvent) => {
    if (containerRef.current) {
      const { left, top, width, height } = containerRef.current.getBoundingClientRect();
      const x = (e.clientX - left) / width - 0.5;
      const y = (e.clientY - top) / height - 0.5;
      setMousePos({ x, y });
    }
  };

  const handleMouseLeave = () => {
    setMousePos({ x: 0, y: 0 });
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-[500px] md:h-[600px] flex flex-col md:flex-row gap-2 md:gap-4 p-4 overflow-hidden"
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
    >
      {PANELS.map((panel) => {
        const isActive = activeId === panel.id;

        return (
          <div
            key={panel.id}
            onClick={() => {
              setActiveId(panel.id);
              if (isActive) {
                 // If already active and clicked, maybe scroll to products?
                 const productsElement = document.getElementById('products-grid');
                 if(productsElement) productsElement.scrollIntoView({ behavior: 'smooth' });
                 onCategorySelect(panel.category);
              }
            }}
            onMouseEnter={() => setActiveId(panel.id)}
            className={`
              relative rounded-3xl overflow-hidden cursor-pointer transition-all duration-700 ease-in-out group
              ${isActive ? 'flex-[3]' : 'flex-[0.5] md:flex-[0.8] hover:flex-[1]'}
            `}
          >
            {/* Background Image with Parallax */}
            <div 
              className="absolute inset-[-20px] bg-cover bg-center transition-transform duration-100 ease-out"
              style={{
                backgroundImage: `url(${panel.image})`,
                transform: isActive 
                  ? `scale(1.1) translate(${mousePos.x * -20}px, ${mousePos.y * -20}px)` 
                  : 'scale(1.0)',
              }}
            />

            {/* Deep Burgundy Overlay */}
            <div className={`
              absolute inset-0 transition-colors duration-500
              ${isActive 
                ? 'bg-gradient-to-t from-burgundy-950/95 via-burgundy-900/60 to-transparent' 
                : 'bg-burgundy-950/70 hover:bg-burgundy-900/50'}
            `}></div>

            {/* Content Content */}
            <div className="absolute inset-0 flex flex-col justify-end p-6 md:p-10">

              {/* Icon & Subtitle (Always Visible but transformed) */}
              <div className={`flex items-center gap-3 mb-2 transition-all duration-500 ${isActive ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-70'}`}>
                <div className="h-10 w-10 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center text-gold-400">
                  {panel.icon}
                </div>
                {isActive && (
                   <span className="text-gold-400 font-display font-semibold text-sm tracking-widest uppercase animate-fade-in">
                     {panel.subtitle}
                   </span>
                )}
              </div>

              {/* Title */}
              <h2 className={`
                font-serif font-bold text-white transition-all duration-500 origin-left
                ${isActive ? 'text-4xl md:text-6xl mb-4 leading-tight' : 'text-2xl md:text-3xl -rotate-90 md:rotate-0 mb-0 opacity-80'}
              `}>
                <span className={isActive ? '' : 'md:hidden'}>{panel.title}</span>
                <span className={`hidden md:block whitespace-nowrap ${isActive ? '' : 'absolute bottom-20 -left-6 origin-bottom-left -rotate-90'}`}>
                   {panel.title}
                </span>
              </h2>

              {/* Description & Button (Only Visible when Active) */}
              <div className={`
                overflow-hidden transition-all duration-700 ease-out
                ${isActive ? 'max-h-48 opacity-100' : 'max-h-0 opacity-0'}
              `}>
                <p className="text-stone-300 font-display text-sm md:text-base max-w-lg mb-6 leading-relaxed">
                  {panel.description}
                </p>
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    onCategorySelect(panel.category);
                    const productsElement = document.getElementById('products-grid');
                    if(productsElement) productsElement.scrollIntoView({ behavior: 'smooth' });
                  }}
                  className="flex items-center gap-2 px-6 py-3 rounded-full bg-gold-500 text-burgundy-950 font-bold font-display text-sm hover:bg-gold-400 transition-colors shadow-lg shadow-gold-500/20 group/btn"
                >
                  Belanja Sekarang
                  <ArrowRight size={16} className="group-hover/btn:translate-x-1 transition-transform" />
                </button>
              </div>

            </div>
          </div>
        );
      })}
    </div>
  );
};

export default HeroSection;

import React, { useState, useEffect, useMemo } from 'react';
import Navbar from './components/Navbar';
import LiquidBackground from './components/LiquidBackground';
import ProductCard from './components/ProductCard';
import CartModal from './components/CartModal';
import WishlistModal from './components/WishlistModal';
import HistoryModal from './components/HistoryModal';
import Toast from './components/Toast';
import TermsModal from './components/TermsModal';
