        </div>

        <div className="flex gap-3">
          {/* Add to Cart - Secondary (Outline) */}
          <button
            onClick={handleAddToCart}
            className="flex-1 py-3 px-3 rounded-xl border border-burgundy-900/30 dark:border-white/20 text-burgundy-900 dark:text-stone-200 font-bold text-xs uppercase tracking-wide hover:bg-burgundy-50 dark:hover:bg-white/5 transition-all flex items-center justify-center gap-2"
          >
            <ShoppingCart size={16} />
            <span className="hidden sm:inline">Add</span>
          </button>

          {/* Buy Now - Primary (Solid Deep Burgundy) */}
          <button
            onClick={handleBuyNow}
            className="flex-[2] py-3 px-4 rounded-xl bg-burgundy-950 dark:bg-gradient-to-r dark:from-burgundy-900 dark:to-burgundy-800 text-white dark:text-gold-100 font-bold text-xs uppercase tracking-wide shadow-lg shadow-burgundy-900/20 hover:shadow-burgundy-900/40 hover:-translate-y-0.5 transition-all flex items-center justify-center gap-2 group/btn relative overflow-hidden"
          >
            <span className="relative z-10 flex items-center gap-2">
              <Zap size={16} fill="currentColor" className="text-gold-400" />
              Buy Now
            </span>
            {/* Shimmer Effect */}
            <div className="absolute inset-0 -translate-x-full group-hover/btn:translate-x-full bg-gradient-to-r from-transparent via-white/20 to-transparent transition-transform duration-700 ease-in-out"></div>
          </button>
        </div>
      </div>

    </div>
  );
};

