import React, { useState, useEffect, useRef } from 'react';
import { CartItem, Order } from '../types';
import { formatRupiah } from '../constants';
import { X, MessageCircle, ShieldCheck, User, Receipt, Clock, Hash, Upload, Image as ImageIcon, Trash2, CheckSquare, Square } from 'lucide-react';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: (selectedIds?: string[]) => void;
  saveOrder: (order: Order) => void;
  initialSelectedId?: string | null;
}

const CartModal: React.FC<CartModalProps> = ({ 
  isOpen, 
  onClose, 
  cart, 
  clearCart,
  saveOrder,
  initialSelectedId
}) => {
  const [customerName, setCustomerName] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [paymentProof, setPaymentProof] = useState<string | null>(null);
  const [error, setError] = useState('');
  const [selectedItems, setSelectedItems] = useState<Set<string>>(new Set());
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initialize selection
  useEffect(() => {
    if (isOpen) {
      if (initialSelectedId) {
        // If specific item requested (Buy Now), only select that one
        setSelectedItems(new Set([initialSelectedId]));
      } else {
        // Otherwise default to all items selected
        setSelectedItems(new Set(cart.map(item => item.id)));
      }

      const date = new Date();
      const dateStr = date.toISOString().slice(0, 10).replace(/-/g, '');
      const randomStr = Math.floor(1000 + Math.random() * 9000).toString();
      setInvoiceNumber(`INV-${dateStr}-${randomStr}`);
      setCustomerName(''); 
      setPaymentProof(null);
      setError('');
    }
  }, [isOpen, initialSelectedId, cart.length]); // Dependency on cart.length ensures if cart changes while open, logic holds (though simple usually)

  const toggleSelection = (id: string) => {
    const newSelection = new Set(selectedItems);
    if (newSelection.has(id)) {
      newSelection.delete(id);
    } else {
      newSelection.add(id);
    }
    setSelectedItems(newSelection);
  };

  const toggleSelectAll = () => {
    if (selectedItems.size === cart.length) {
      setSelectedItems(new Set());
    } else {
      setSelectedItems(new Set(cart.map(item => item.id)));
    }
  };

  if (!isOpen) return null;

  // Filter items for checkout
  const checkoutItems = cart.filter(item => selectedItems.has(item.id));
  const total = checkoutItems.reduce((acc, item) => acc + (item.product.variants[item.selectedVariantIndex].price * item.quantity), 0);

  const currentDate = new Date().toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
  const currentTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const objectUrl = URL.createObjectURL(file);
      setPaymentProof(objectUrl);
      setError('');
    }
  };

  const handleCheckout = () => {
    if (checkoutItems.length === 0) {
      setError('Pilih minimal satu item untuk checkout.');
      return;
    }

    if (!customerName.trim()) {
      setError('Nama wajib diisi.');
      return;
    }

    if (!paymentProof) {
      setError('Wajib upload bukti pembayaran sebelum konfirmasi.');
      return;
    }

    let itemDetails = checkoutItems.map((item) => {
      const variant = item.product.variants[item.selectedVariantIndex];
      return `${item.product.appName} [${variant.type} - ${variant.duration}]`;
    }).join(', ');

    const message = `Halo Admin, saya sudah melakukan pembayaran. 
No Invoice: ${invoiceNumber}
Nama: ${customerName}
Item: ${itemDetails}
Total: ${formatRupiah(total)}

Status: SUDAH UPLOAD BUKTI. 
Mohon diproses ya!`;

    const newOrder: Order = {
      id: invoiceNumber,
      date: new Date().toLocaleDateString('id-ID'),
      items: [...checkoutItems],
      total: total,
      status: 'Processing',
      paymentProof: paymentProof
    };
    saveOrder(newOrder);

    // Clear only checked items
    const checkedIdsArray = Array.from(selectedItems);
    clearCart(checkedIdsArray);

    const phoneNumber = "6282116505311"; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 font-sans">
      <div 
        className="absolute inset-0 bg-burgundy-950/80 dark:bg-black/90 backdrop-blur-md transition-opacity"
        onClick={onClose}
      ></div>

      <div className="relative w-full max-w-md max-h-[90vh] bg-stone-50/95 dark:bg-[#1a0505]/95 backdrop-blur-2xl border border-burgundy-900/30 dark:border-white/10 rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Receipt Header */}
        <div className="flex items-center justify-between p-5 border-b border-burgundy-900/10 dark:border-white/10 bg-gradient-to-r from-burgundy-100/50 to-stone-100/50 dark:from-burgundy-950/50 dark:to-black/50">
          <div>
            <h2 className="text-lg font-bold text-burgundy-900 dark:text-stone-100 flex items-center gap-2 font-serif tracking-wide">
              <Receipt size={18} className="text-burgundy-700 dark:text-gold-500" />
              CART & CHECKOUT
            </h2>
            <p className="text-[10px] text-stone-500 uppercase tracking-widest mt-1">Dhevv Premium Store</p>
          </div>
          <button 
            onClick={onClose}
            className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors text-stone-500"
          >
            <X size={20} />
          </button>
        </div>

        {/* Receipt Content */}
        <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">

          {/* Invoice Meta */}
          <div className="flex justify-between items-end mb-6 text-xs text-stone-500 dark:text-stone-400 font-mono">
            <div className="space-y-1">
              <div className="flex items-center gap-2">
                <Hash size={12} />
                <span className="font-bold text-burgundy-900 dark:text-stone-200">{invoiceNumber}</span>
              </div>
              <div className="flex items-center gap-2">
                <Clock size={12} />
                <span>{currentDate}, {currentTime}</span>
              </div>
            </div>
            <div className="text-right">
              <span className="inline-block px-2 py-1 rounded-md bg-burgundy-100 dark:bg-burgundy-900/30 text-burgundy-800 dark:text-burgundy-400 font-bold border border-burgundy-200 dark:border-burgundy-800/30 uppercase tracking-wider text-[10px]">
                Payment Required
              </span>
            </div>
          </div>

          {/* Item List with Selection */}
          <div className="space-y-3 mb-6">
            <div className="text-[10px] uppercase tracking-widest text-stone-400 border-b border-stone-200 dark:border-white/10 pb-2 mb-2 flex justify-between items-center">
              <button onClick={toggleSelectAll} className="flex items-center gap-2 hover:text-burgundy-700 dark:hover:text-gold-500 transition-colors">
                {cart.length > 0 && selectedItems.size === cart.length ? <CheckSquare size={14} /> : <Square size={14} />}
                <span>Select Items</span>
              </button>
              <span>Subtotal</span>
            </div>

            {cart.length === 0 ? (
               <p className="text-center text-sm text-stone-400 italic py-4">No items in cart.</p>
            ) : (
              cart.map((item) => {
                const variant = item.product.variants[item.selectedVariantIndex];
