    image: "https://images.unsplash.com/photo-1626785774573-4b799314346d?q=80&w=2670&auto=format&fit=crop",
    icon: <PenTool className="w-5 h-5" />,
    category: "Design"
  }
];

interface HeroSectionProps {
  onCategorySelect: (category: string) => void;
}

const HeroSection: React.FC<HeroSectionProps> = ({ onCategorySelect }) => {
  const [activeId, setActiveId] = useState<string>('streaming');
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  // Parallax Effect Handler
  const handleMouseMove = (e: React.MouseEvent) => {
    if (containerRef.current) {
      const { left, top, width, height } = containerRef.current.getBoundingClientRect();
      const x = (e.clientX - left) / width - 0.5;
      const y = (e.clientY - top) / height - 0.5;
      setMousePos({ x, y });
    }
  };

  const handleMouseLeave = () => {
    setMousePos({ x: 0, y: 0 });
  };

  return (
    <div 
      ref={containerRef}
      className="w-full h-[500px] md:h-[600px] flex flex-col md:flex-row gap-2 md:gap-4 p-4 overflow-hidden"
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
    >
      {PANELS.map((panel) => {
        const isActive = activeId === panel.id;

        return (
          <div
            key={panel.id}
            onClick={() => {
              setActiveId(panel.id);
              if (isActive) {
                 const productsElement = document.getElementById('products-grid');
                 if(productsElement) productsElement.scrollIntoView({ behavior: 'smooth' });
                 onCategorySelect(panel.category);
              }
            }}
            onMouseEnter={() => setActiveId(panel.id)}
            className={`
              relative rounded-3xl overflow-hidden cursor-pointer transition-all duration-700 ease-in-out group
              ${isActive ? 'flex-[3]' : 'flex-[0.5] md:flex-[0.8] hover:flex-[1]'}
            `}
          >
            {/* Background Image with Parallax */}
            <div 
              className="absolute inset-[-20px] bg-cover bg-center transition-transform duration-100 ease-out"
              style={{
                backgroundImage: `url(${panel.image})`,
                transform: isActive 
                  ? `scale(1.1) translate(${mousePos.x * -20}px, ${mousePos.y * -20}px)` 
                  : 'scale(1.0)',
              }}
            />

            {/* Deep Burgundy Overlay */}
            <div className={`
              absolute inset-0 transition-colors duration-500
              ${isActive 
                ? 'bg-gradient-to-t from-burgundy-950/95 via-burgundy-900/60 to-transparent' 
                : 'bg-burgundy-950/70 hover:bg-burgundy-900/50'}
            `}></div>

            {/* Content Content */}
            <div className="absolute inset-0 flex flex-col justify-end p-6 md:p-10">

              {/* Icon & Subtitle (Always Visible but transformed) */}
              <div className={`flex items-center gap-3 mb-2 transition-all duration-500 ${isActive ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-70'}`}>
                <div className="h-10 w-10 rounded-full bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center text-gold-400">
                  {panel.icon}
                </div>
                {isActive && (
                   <span className="text-gold-400 font-display font-semibold text-sm tracking-widest uppercase animate-fade-in">
                     {panel.subtitle}
                   </span>
                )}
              </div>

              {/* Title */}
              <h2 className={`
                font-serif font-bold text-white transition-all duration-500 origin-left
                ${isActive ? 'text-4xl md:text-6xl mb-4 leading-tight' : 'text-2xl md:text-3xl -rotate-90 md:rotate-0 mb-0 opacity-80'}
              `}>
                <span className={isActive ? '' : 'md:hidden'}>{panel.title}</span>
                <span className={`hidden md:block whitespace-nowrap ${isActive ? '' : 'absolute bottom-20 -left-6 origin-bottom-left -rotate-90'}`}>
                   {panel.title}
                </span>
              </h2>

              {/* Description & Button (Only Visible when Active) */}
              <div className={`
                overflow-hidden transition-all duration-700 ease-out
                ${isActive ? 'max-h-48 opacity-100' : 'max-h-0 opacity-0'}
              `}>
                <p className="text-stone-300 font-display text-sm md:text-base max-w-lg mb-6 leading-relaxed">
                  {panel.description}
                </p>
                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    onCategorySelect(panel.category);
                    const productsElement = document.getElementById('products-grid');
                    if(productsElement) productsElement.scrollIntoView({ behavior: 'smooth' });
                  }}
                  className="flex items-center gap-2 px-6 py-3 rounded-full bg-gold-500 text-burgundy-950 font-bold font-display text-sm hover:bg-gold-400 transition-colors shadow-lg shadow-gold-500/20 group/btn"
                >
                  Belanja Sekarang
                  <ArrowRight size={16} className="group-hover/btn:translate-x-1 transition-transform" />
                </button>
              </div>

            </div>
          </div>
        );
      })}
    </div>
  );
};

