import React, { useState, useEffect, useMemo } from 'react';
import Navbar from './components/Navbar';
import LiquidBackground from './components/LiquidBackground';
import ProductCard from './components/ProductCard';
import CartModal from './components/CartModal';
import WishlistModal from './components/WishlistModal';
import HistoryModal from './components/HistoryModal';
import Toast from './components/Toast';
import TermsModal from './components/TermsModal';
import AuthModal from './components/AuthModal';
import AnnouncementModal from './components/AnnouncementModal';
import DashboardModal from './components/DashboardModal';
import HeroSection from './components/HeroSection';
import { PRODUCTS } from './constants';
import { Product, CartItem, Order, Category, ToastMessage, User } from './types';
import { Sparkles } from 'lucide-react';

const CATEGORIES: Category[] = ['All', 'Streaming', 'Music', 'Design', 'Productivity', 'Other'];

const App: React.FC = () => {
  // Theme State
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark';
    }
    return false;
  });

  // User Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('currentUser');
    return saved ? JSON.parse(saved) : null;
  });

  // Modal States
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [cartInitialSelectedId, setCartInitialSelectedId] = useState<string | null>(null);

  const [isWishlistOpen, setIsWishlistOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isTermsOpen, setIsTermsOpen] = useState(false);
  const [isAuthOpen, setIsAuthOpen] = useState(false);
  const [isAnnouncementOpen, setIsAnnouncementOpen] = useState(false);
  const [isDashboardOpen, setIsDashboardOpen] = useState(false);

  // Filter States
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<Category>('All');

  // Data States
  const [cart, setCart] = useState<CartItem[]>([]);
  const [wishlist, setWishlist] = useState<string[]>(() => {
    const saved = localStorage.getItem('wishlist');
    return saved ? JSON.parse(saved) : [];
  });
  const [orderHistory, setOrderHistory] = useState<Order[]>(() => {
    const saved = localStorage.getItem('history');
    return saved ? JSON.parse(saved) : [];
  });
  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  // Effects
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    localStorage.setItem('wishlist', JSON.stringify(wishlist));
  }, [wishlist]);

  useEffect(() => {
    localStorage.setItem('history', JSON.stringify(orderHistory));
  }, [orderHistory]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('currentUser', JSON.stringify(user));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [user]);

  // Toast Logic
  const addToast = (message: string, type: 'success' | 'info') => {
    const id = Date.now();
    setToasts([...toasts, { id, message, type }]);
    setTimeout(() => removeToast(id), 3500);
  };

  const removeToast = (id: number) => {
    setToasts((current) => current.filter((t) => t.id !== id));
  };

  // Auth Logic
  const handleLogin = (newUser: User) => {
    setUser(newUser);
    setIsAuthOpen(false);
    // Show announcement after short delay for effect
    setTimeout(() => setIsAnnouncementOpen(true), 300);
    addToast(`Welcome back, ${newUser.name}!`, 'success');
  };

  const handleLogout = () => {
    setUser(null);
    setIsDashboardOpen(false);
    addToast('Logged out successfully', 'info');
  };

  // Cart Logic
  const addToCart = (product: Product, variantIndex: number): string => {
    const existingItem = cart.find(item => item.product.appName === product.appName && item.selectedVariantIndex === variantIndex);

    if (existingItem) {
      updateQuantity(existingItem.id, 1);
      addToast(`${product.appName} added to bag`, 'success');
      return existingItem.id;
    } else {
      const id = `${product.appName}-${variantIndex}-${Date.now()}`;
      const newItem: CartItem = {
        id,
        product,
        selectedVariantIndex: variantIndex,
        quantity: 1
      };
      setCart([...cart, newItem]);
      addToast(`${product.appName} added to bag`, 'success');
      return id;
    }
  };

  const openCart = (itemIdToSelect?: string) => {
    if (itemIdToSelect) {
      setCartInitialSelectedId(itemIdToSelect);
    } else {
      setCartInitialSelectedId(null);
    }
    setIsCartOpen(true);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const clearCart = (selectedIds?: string[]) => {
    if (selectedIds) {
      setCart(cart.filter(item => !selectedIds.includes(item.id)));
    } else {
      setCart([]);
    }
  };

  const saveOrder = (order: Order) => {
    setOrderHistory([order, ...orderHistory]);
    addToast('Order confirmed successfully!', 'success');
  };

  // Wishlist Logic
  const toggleWishlist = (appName: string) => {
    if (wishlist.includes(appName)) {
      setWishlist(wishlist.filter(id => id !== appName));
      addToast(`${appName} removed from wishlist`, 'info');
    } else {
      setWishlist([...wishlist, appName]);
      addToast(`${appName} added to wishlist`, 'success');
    }
  };

  const removeFromWishlist = (appName: string) => {
    setWishlist(wishlist.filter(id => id !== appName));
    addToast(`${appName} removed from wishlist`, 'info');
  };

  // Filter Logic
  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(product => {
      const matchesSearch = product.appName.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory]);

  const handleCategorySelect = (categoryName: string) => {
    // Map internal category names to types.ts Category types if needed, or just cast if consistent
    if (CATEGORIES.includes(categoryName as Category)) {
       setSelectedCategory(categoryName as Category);
    } else {
       setSelectedCategory('All');
    }
  };

  return (
    <div className="relative min-h-screen font-sans selection:bg-gold-500/30">
      <LiquidBackground />
      <Toast toasts={toasts} removeToast={removeToast} />

      <Navbar 
        toggleTheme={() => setIsDarkMode(!isDarkMode)}
        isDarkMode={isDarkMode}
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)}
        openCart={() => openCart()}
        openWishlist={() => user ? setIsDashboardOpen(true) : setIsWishlistOpen(true)}
        openHistory={() => user ? setIsDashboardOpen(true) : setIsHistoryOpen(true)}
        openAuth={() => setIsAuthOpen(true)}
        openDashboard={() => setIsDashboardOpen(true)}
        user={user}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
      />

      {/* Hero Section */}
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 mt-6 mb-12 animate-fade-in">
        <HeroSection onCategorySelect={handleCategorySelect} />
      </div>

      <main className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-4 pb-24" id="products-grid">

        {/* Intro Text / Stats */}
        <div className="text-center mb-10 relative z-10">
           <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-burgundy-900/5 dark:bg-white/5 border border-burgundy-900/10 dark:border-white/10 text-xs font-bold uppercase tracking-widest text-burgundy-800 dark:text-gold-400">
              <Sparkles size={12} />
              <span>Premium Collection</span>
           </div>
           <h2 className="mt-4 text-3xl md:text-4xl font-serif font-bold text-burgundy-950 dark:text-stone-100">
             Discover Your Upgrade
           </h2>
        </div>

        {/* Category Filters */}
        <div className="flex flex-wrap justify-center gap-3 mb-10 relative z-10">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`px-5 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 border backdrop-blur-md ${
                selectedCategory === cat
                  ? 'bg-burgundy-950 dark:bg-stone-100 text-stone-100 dark:text-burgundy-950 border-burgundy-950 dark:border-stone-100 shadow-lg shadow-burgundy-900/20'
                  : 'bg-white/30 dark:bg-black/20 text-burgundy-900/70 dark:text-stone-400 border-burgundy-900/5 dark:border-white/5 hover:bg-white/50 dark:hover:bg-white/10 hover:border-gold-500/30'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Product Grid */}
        {filteredProducts.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 relative z-10">
            {filteredProducts.map((product, index) => (
              <ProductCard 
                key={index}
                product={product}
                addToCart={addToCart}
                openCart={openCart}
                toggleWishlist={toggleWishlist}
                isWishlisted={wishlist.includes(product.appName)}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-20 relative z-10">
            <div className="inline-flex h-16 w-16 items-center justify-center rounded-full bg-burgundy-100/50 dark:bg-white/5 mb-4 text-burgundy-300 dark:text-stone-600">
               <Sparkles size={32} />
            </div>
            <p className="text-burgundy-900/50 dark:text-stone-500 text-lg">No collections found matching your criteria.</p>
            <button 
              onClick={() => {setSearchQuery(''); setSelectedCategory('All');}}
              className="mt-4 text-burgundy-700 dark:text-gold-500 hover:underline font-medium"
            >
              Clear Filters
            </button>
          </div>
        )}
      </main>

      {/* Modals */}
      <CartModal 
        isOpen={isCartOpen}
        onClose={() => setIsCartOpen(false)}
        cart={cart}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
        saveOrder={saveOrder}
        initialSelectedId={cartInitialSelectedId}
      />

      {/* Render standalone modals only if user is NOT logged in (otherwise they are in dashboard) */}
      {!user && (
        <>
          <WishlistModal 
            isOpen={isWishlistOpen}
            onClose={() => setIsWishlistOpen(false)}
            wishlistIds={wishlist}
            allProducts={PRODUCTS}
            removeFromWishlist={removeFromWishlist}
          />

          <HistoryModal
            isOpen={isHistoryOpen}
            onClose={() => setIsHistoryOpen(false)}
            history={orderHistory}
          />
        </>
      )}

      <TermsModal 
        isOpen={isTermsOpen}
        onClose={() => setIsTermsOpen(false)}
      />

      <AuthModal 
        isOpen={isAuthOpen}
        onClose={() => setIsAuthOpen(false)}
        onLogin={handleLogin}
      />

      <AnnouncementModal 
        isOpen={isAnnouncementOpen}
        onClose={() => setIsAnnouncementOpen(false)}
      />

      {user && (
        <DashboardModal 
          isOpen={isDashboardOpen}
          onClose={() => setIsDashboardOpen(false)}
          user={user}
          orders={orderHistory}
          wishlist={wishlist}
          allProducts={PRODUCTS}
          onLogout={handleLogout}
          removeFromWishlist={removeFromWishlist}
        />
      )}

      {/* Footer */}
      <footer className="text-center py-8 border-t border-burgundy-900/5 dark:border-white/5 mt-auto relative z-10 bg-white/30 dark:bg-black/20 backdrop-blur-md">
        <p className="text-sm text-burgundy-900/40 dark:text-stone-500 font-serif italic">
          &copy; {new Date().getFullYear()} Dhevv Premium Digital. Elevating Standards.
        </p>
      </footer>
    </div>
  );
};

export default App;

