import React, { useState, useEffect, useRef } from 'react';
import { CartItem, Order } from '../types';
import { formatRupiah } from '../constants';
import { X, MessageCircle, ShieldCheck, User, Receipt, Clock, Hash, Upload, Image as ImageIcon, Trash2, ArrowLeft, CheckSquare, Square, ShoppingBag, Minus, Plus } from 'lucide-react';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: (selectedIds?: string[]) => void;
  saveOrder: (order: Order) => void;
  directCheckoutItem?: CartItem | null; // Single item for "Buy Now" flow
}

type Step = 'cart' | 'invoice';

const CartModal: React.FC<CartModalProps> = ({ 
  isOpen, 
  onClose, 
  cart, 
  updateQuantity,
  removeFromCart,
  clearCart,
  saveOrder,
  directCheckoutItem
}) => {
  const [step, setStep] = useState<Step>('cart');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Invoice State
  const [customerName, setCustomerName] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [paymentProof, setPaymentProof] = useState<string | null>(null);
  const [error, setError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initialize Modal Logic
  useEffect(() => {
    if (isOpen) {
      if (directCheckoutItem) {
        // "Buy Now" Mode: Bypass cart list, go to invoice with specific temp item
        setStep('invoice');
      } else {
        // "View Cart" Mode: Show list, reset selection
        setStep('cart');
        setSelectedIds(new Set());
      }

      // Generate Invoice Number
      const date = new Date();
      const dateStr = date.toISOString().slice(0, 10).replace(/-/g, '');
      const randomStr = Math.floor(1000 + Math.random() * 9000).toString();
      setInvoiceNumber(`INV-${dateStr}-${randomStr}`);

      setCustomerName(''); 
      setPaymentProof(null);
      setError('');
    }
  }, [isOpen, directCheckoutItem]);

  if (!isOpen) return null;

  // Helpers for Cart Logic
  const toggleSelection = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setSelectedIds(newSelected);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === cart.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(cart.map(item => item.id)));
    }
  };

  // Determine which items are being checked out
  // If directCheckoutItem exists, we ignore the cart array entirely for this transaction
  const itemsToCheckout = directCheckoutItem 
    ? [directCheckoutItem] 
    : cart.filter(item => selectedIds.has(item.id));

  const total = itemsToCheckout.reduce((acc, item) => acc + (item.product.variants[item.selectedVariantIndex].price * item.quantity), 0);

  const currentDate = new Date().toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
  const currentTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' });

  // Invoice Handlers
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const objectUrl = URL.createObjectURL(file);
      setPaymentProof(objectUrl);
      setError('');
    }
  };

  const handleConfirmOrder = () => {
    if (itemsToCheckout.length === 0) return;

    if (!customerName.trim()) {
      setError('Nama wajib diisi.');
      return;
    }

    if (!paymentProof) {
      setError('Wajib upload bukti pembayaran.');
      return;
    }

    // 1. WhatsApp String
    let itemDetails = itemsToCheckout.map((item) => {
      const variant = item.product.variants[item.selectedVariantIndex];
      return `${item.product.appName} [${variant.type} - ${variant.duration}] (x${item.quantity})`;
    }).join(', ');

    const message = `Halo Admin, saya sudah melakukan pembayaran. 
No Invoice: ${invoiceNumber}
Nama: ${customerName}
Item: ${itemDetails}
Total: ${formatRupiah(total)}

Status: SUDAH UPLOAD BUKTI. 
Mohon diproses ya!`;

    // 2. Save Order
    const newOrder: Order = {
      id: invoiceNumber,
      date: new Date().toLocaleDateString('id-ID'),
      items: [...itemsToCheckout],
      total: total,
      status: 'Processing',
      paymentProof: paymentProof
    };
    saveOrder(newOrder);

    // 3. Cleanup logic
    if (!directCheckoutItem) {
      // If this was a Cart Checkout, remove the selected items from cart
      const idsToRemove = Array.from(selectedIds);
      clearCart(idsToRemove);
    }
    // If it was Direct Checkout, we do nothing to the cart state because the item wasn't there.

    const phoneNumber = "6282116505311"; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');
    onClose();
  };

  // --- RENDER: CART LIST STEP ---
  if (step === 'cart') {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 font-sans">
        <div className="absolute inset-0 bg-burgundy-950/80 dark:bg-black/90 backdrop-blur-md" onClick={onClose}></div>
        <div className="relative w-full max-w-lg max-h-[90vh] bg-stone-50/95 dark:bg-[#1a0505]/95 backdrop-blur-2xl border border-burgundy-900/30 dark:border-white/10 rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">

          <div className="flex items-center justify-between p-5 border-b border-burgundy-900/5 dark:border-white/5 bg-white/40 dark:bg-white/5">
             <h2 className="text-xl font-bold text-burgundy-950 dark:text-stone-100 flex items-center gap-2 font-serif">
              <ShoppingBag className="text-burgundy-700 dark:text-gold-500" />
              Shopping Cart
            </h2>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 text-stone-500">
              <X size={20} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-5 custom-scrollbar">
            {cart.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-stone-400 gap-4">
                <div className="p-6 rounded-full bg-stone-100 dark:bg-white/5">
                   <ShoppingBag size={48} className="opacity-50" />
                </div>
                <p>Your cart is empty.</p>
              </div>
            ) : (
              <div className="space-y-4">
                 <div className="flex items-center gap-3 pb-2 border-b border-burgundy-900/5 dark:border-white/5">
                    <button onClick={toggleSelectAll} className="flex items-center gap-2 text-xs font-bold text-burgundy-900 dark:text-gold-500 uppercase tracking-wide">
                       {selectedIds.size === cart.length ? <CheckSquare size={18} /> : <Square size={18} />}
                       Select All
                    </button>
                 </div>

                 {cart.map(item => {
                   const variant = item.product.variants[item.selectedVariantIndex];
                   const isSelected = selectedIds.has(item.id);

                   return (
                     <div key={item.id} className={`flex items-start gap-3 p-3 rounded-xl transition-all border ${isSelected ? 'bg-burgundy-50 dark:bg-burgundy-900/20 border-burgundy-900/20 dark:border-gold-500/30' : 'bg-white/50 dark:bg-white/5 border-transparent'}`}>
                       <button onClick={() => toggleSelection(item.id)} className="mt-1 text-burgundy-800 dark:text-gold-500 hover:scale-110 transition-transform">
                          {isSelected ? <CheckSquare size={20} /> : <Square size={20} className="text-stone-300 dark:text-stone-600" />}
                       </button>

                       <div className="h-16 w-16 rounded-lg bg-stone-200 dark:bg-black/40 flex-shrink-0 flex items-center justify-center font-serif font-bold text-burgundy-900 dark:text-stone-400 text-xl">
                          {item.product.appName.charAt(0)}
                       </div>

                       <div className="flex-1 min-w-0">
                          <h4 className="font-bold text-burgundy-950 dark:text-stone-100 truncate">{item.product.appName}</h4>
                          <p className="text-xs text-stone-500 truncate">{variant.type} • {variant.duration}</p>
                          <p className="text-sm font-bold text-burgundy-900 dark:text-gold-500 mt-1">{formatRupiah(variant.price)}</p>
                       </div>

                       <div className="flex flex-col items-end gap-2">
                          <button onClick={() => removeFromCart(item.id)} className="text-stone-400 hover:text-red-500 transition-colors">
                            <Trash2 size={16} />
                          </button>

                          <div className="flex items-center gap-2 bg-white dark:bg-black/30 rounded-lg p-1 border border-stone-200 dark:border-white/10">
                            <button 
                              onClick={() => updateQuantity(item.id, -1)} 
                              className="p-1 hover:bg-stone-100 dark:hover:bg-white/10 rounded disabled:opacity-30"
                              disabled={item.quantity <= 1}
                            >
                              <Minus size={12} />
                            </button>
                            <span className="text-xs font-bold w-4 text-center">{item.quantity}</span>
                            <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:bg-stone-100 dark:hover:bg-white/10 rounded">
                              <Plus size={12} />
                            </button>
                          </div>
                       </div>
                     </div>
                   );
                 })}
              </div>
            )}
          </div>

          <div className="p-5 border-t border-burgundy-900/5 dark:border-white/5 bg-stone-100/50 dark:bg-black/30 backdrop-blur-sm">
            <div className="flex justify-between items-center mb-4">
              <span className="text-xs font-bold text-stone-500 uppercase">Selected Total</span>
              <span className="text-xl font-bold text-burgundy-950 dark:text-gold-400">{formatRupiah(total)}</span>
            </div>
            <button
              onClick={() => setStep('invoice')}
              disabled={selectedIds.size === 0}
              className="w-full py-3.5 rounded-xl bg-burgundy-950 dark:bg-stone-100 text-stone-100 dark:text-burgundy-950 font-bold uppercase tracking-wide disabled:opacity-50 disabled:cursor-not-allowed hover:shadow-lg transition-all"
            >
              Checkout ({selectedIds.size})
            </button>
          </div>
        </div>
      </div>
    );
  }

  // --- RENDER: INVOICE/CHECKOUT STEP ---
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 font-sans">
      <div className="absolute inset-0 bg-burgundy-950/80 dark:bg-black/90 backdrop-blur-md" onClick={onClose}></div>

      <div className="relative w-full max-w-md max-h-[90vh] bg-stone-50/95 dark:bg-[#1a0505]/95 backdrop-blur-2xl border border-burgundy-900/30 dark:border-white/10 rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right-10 duration-300">

        {/* Receipt Header */}
        <div className="flex items-center justify-between p-5 border-b border-burgundy-900/10 dark:border-white/10 bg-gradient-to-r from-burgundy-100/50 to-stone-100/50 dark:from-burgundy-950/50 dark:to-black/50">
          <div className="flex items-center gap-3">
            {!directCheckoutItem && (
              <button onClick={() => setStep('cart')} className="p-1.5 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors">
                <ArrowLeft size={18} className="text-burgundy-900 dark:text-stone-300" />
              </button>
            )}
            <div>
              <h2 className="text-lg font-bold text-burgundy-900 dark:text-stone-100 flex items-center gap-2 font-serif tracking-wide">
                <Receipt size={18} className="text-burgundy-700 dark:text-gold-500" />
                PAYMENT
              </h2>
            </div>
          </div>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 transition-colors text-stone-500">
            <X size={20} />
          </button>
        </div>

        {/* Receipt Content */}
        <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">

          {/* Invoice Meta */}
          <div className="flex justify-between items-end mb-6 text-xs text-stone-500 dark:text-stone-400 font-mono">
            <div className="space-y-1">
              <div className="flex items-center gap-2">
                <Hash size={12} />
                <span className="font-bold text-burgundy-900 dark:text-stone-200">{invoiceNumber}</span>
              </div>
              <div className="flex items-center gap-2">
                <Clock size={12} />
                <span>{currentDate}, {currentTime}</span>
              </div>
            </div>
            <div className="text-right">
              <span className="inline-block px-2 py-1 rounded-md bg-burgundy-100 dark:bg-burgundy-900/30 text-burgundy-800 dark:text-burgundy-400 font-bold border border-burgundy-200 dark:border-burgundy-800/30 uppercase tracking-wider text-[10px]">
                Payment Required
              </span>
            </div>
          </div>

          {/* Item List Summary */}
          <div className="space-y-3 mb-6">
            <div className="text-[10px] uppercase tracking-widest text-stone-400 border-b border-stone-200 dark:border-white/10 pb-2 mb-2 flex justify-between">
              <span>Checkout Items ({itemsToCheckout.length})</span>
              <span>Subtotal</span>
            </div>

            {itemsToCheckout.map((item) => {
              const variant = item.product.variants[item.selectedVariantIndex];
              const subtotal = variant.price * item.quantity;
              return (
                <div key={item.id} className="flex justify-between items-start text-sm group">
                  <div className="pr-4">
                    <p className="font-bold text-burgundy-950 dark:text-stone-200">{item.product.appName}</p>
                    <p className="text-xs text-stone-500">{variant.type} x{item.quantity}</p>
                  </div>
                  <p className="font-mono text-burgundy-900 dark:text-stone-300 whitespace-nowrap">
                    {formatRupiah(subtotal)}
                  </p>
                </div>
              );
            })}
          </div>

          {/* Divider */}
          <div className="border-t border-dashed border-stone-300 dark:border-white/20 mb-4"></div>

          {/* Totals */}
          <div className="flex justify-between items-center mb-8">
            <span className="text-stone-600 dark:text-stone-400 font-bold">Total Pay</span>
            <span className="text-2xl font-bold text-burgundy-900 dark:text-gold-400 font-mono">
              {formatRupiah(total)}
            </span>
          </div>

          {/* QRIS Section */}
          <div className="bg-white dark:bg-black/40 p-5 rounded-2xl border border-stone-200 dark:border-white/10 text-center mb-6 relative overflow-hidden shadow-inner">
            <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-burgundy-900 via-gold-500 to-burgundy-900"></div>
            <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest mb-4">Scan QRIS to Pay</p>
            <div className="mx-auto w-48 h-auto bg-white p-2.5 rounded-xl shadow-md border border-stone-100">
               <img 
                 src="https://user2158.na.imgto.link/public/20260210/img-1294.avif" 
                 alt="QRIS Payment"
                 className="w-full h-full object-contain rounded-lg"
               />
            </div>
            <div className="mt-4 flex items-center justify-center gap-1.5 text-[10px] text-stone-500 dark:text-stone-400">
              <ShieldCheck size={12} className="text-emerald-500" />
              <span>Verified Merchant • Secure Transaction</span>
            </div>
          </div>

          {/* Customer Inputs */}
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold text-stone-500 dark:text-stone-400 mb-2 ml-1 uppercase">Your Name</label>
              <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <User size={16} className="text-stone-400" />
                  </div>
                  <input
                    type="text"
                    placeholder="Enter your name..."
                    value={customerName}
                    onChange={(e) => {
                      setCustomerName(e.target.value);
                      setError('');
                    }}
                    className="block w-full pl-9 pr-3 py-3 border rounded-xl bg-white/50 dark:bg-black/20 text-sm focus:outline-none focus:ring-1 focus:ring-gold-500/50 transition-all border-burgundy-900/10 dark:border-white/10 text-burgundy-950 dark:text-stone-100 placeholder-stone-400"
                  />
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-stone-500 dark:text-stone-400 mb-2 ml-1 uppercase">
                Upload Payment Proof <span className="text-red-500">*</span>
              </label>

              {!paymentProof ? (
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="group cursor-pointer border-2 border-dashed border-stone-300 dark:border-white/20 hover:border-burgundy-500 dark:hover:border-gold-500/50 rounded-xl p-6 transition-all flex flex-col items-center justify-center bg-stone-50/50 dark:bg-white/5 hover:bg-white/80 dark:hover:bg-white/10"
                >
                  <div className="h-10 w-10 mb-2 rounded-full bg-stone-200 dark:bg-white/10 flex items-center justify-center text-stone-500 dark:text-stone-400 group-hover:scale-110 transition-transform">
                    <Upload size={20} />
                  </div>
                  <p className="text-xs font-medium text-stone-600 dark:text-stone-300">Click to upload screenshot</p>
                  <p className="text-[10px] text-stone-400 mt-1">JPG, PNG supported</p>
                </div>
              ) : (
                <div className="relative rounded-xl overflow-hidden border border-burgundy-900/10 dark:border-white/10 group">
                  <img src={paymentProof} alt="Proof" className="w-full h-32 object-cover" />
                  <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <button 
                      onClick={() => setPaymentProof(null)}
                      className="p-2 bg-red-500 rounded-full text-white hover:bg-red-600 transition-colors shadow-lg"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                  <div className="absolute bottom-2 left-2 px-2 py-1 bg-black/60 rounded text-[10px] text-white flex items-center gap-1">
                    <ImageIcon size={10} /> Image Uploaded
                  </div>
                </div>
              )}
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept="image/*"
              />
            </div>

            {error && (
              <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-500/20 flex items-center gap-2 animate-pulse">
                <ShieldCheck size={16} className="text-red-500" />
                <p className="text-xs text-red-600 dark:text-red-400 font-medium">{error}</p>
              </div>
            )}
          </div>
        </div>

        {/* Footer Action */}
        <div className="p-5 border-t border-burgundy-900/5 dark:border-white/5 bg-stone-100/50 dark:bg-black/30 backdrop-blur-sm">
          <button
            onClick={handleConfirmOrder}
            className="w-full flex items-center justify-center gap-2 py-3.5 rounded-xl bg-[#25D366] hover:bg-[#20bd5a] text-white font-bold text-sm uppercase tracking-wide shadow-lg shadow-green-500/20 hover:shadow-green-500/40 hover:-translate-y-0.5 transition-all duration-300"
          >
            <MessageCircle size={18} />
            Confirm via WhatsApp
          </button>
        </div>

      </div>
    </div>
  );
};

export default CartModal;

import React, { useState, useEffect, useMemo } from 'react';
import Navbar from './components/Navbar';
import LiquidBackground from './components/LiquidBackground';
import ProductCard from './components/ProductCard';
import CartModal from './components/CartModal';
import WishlistModal from './components/WishlistModal';
import HistoryModal from './components/HistoryModal';
import Toast from './components/Toast';
import TermsModal from './components/TermsModal';
import AuthModal from './components/AuthModal';
import AnnouncementModal from './components/AnnouncementModal';
import DashboardModal from './components/DashboardModal';
import { PRODUCTS } from './constants';
import { Product, CartItem, Order, Category, ToastMessage, User } from './types';
import { Sparkles, Search } from 'lucide-react';

const CATEGORIES: Category[] = ['All', 'Streaming', 'Music', 'Design', 'Productivity', 'Other'];

const App: React.FC = () => {
  // Theme State
  const [isDarkMode, setIsDarkMode] = useState<boolean>(() => {
    if (typeof window !== 'undefined') {
      return localStorage.getItem('theme') === 'dark';
    }
    return false;
  });

  // User Auth State
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('currentUser');
    return saved ? JSON.parse(saved) : null;
  });

  // Modal States
  const [isCartOpen, setIsCartOpen] = useState(false);

  // NEW: Direct Checkout State (Isolates "Buy Now" data from "Cart" data)
  const [directCheckoutItem, setDirectCheckoutItem] = useState<CartItem | null>(null);

  const [isWishlistOpen, setIsWishlistOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [isTermsOpen, setIsTermsOpen] = useState(false);
  const [isAuthOpen, setIsAuthOpen] = useState(false);
  const [isAnnouncementOpen, setIsAnnouncementOpen] = useState(false);
  const [isDashboardOpen, setIsDashboardOpen] = useState(false);

  // Filter States
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<Category>('All');

  // Data States
  const [cart, setCart] = useState<CartItem[]>([]);
  const [wishlist, setWishlist] = useState<string[]>(() => {
    const saved = localStorage.getItem('wishlist');
    return saved ? JSON.parse(saved) : [];
  });
  const [orderHistory, setOrderHistory] = useState<Order[]>(() => {
    const saved = localStorage.getItem('history');
    return saved ? JSON.parse(saved) : [];
  });
  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  // Effects
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    localStorage.setItem('wishlist', JSON.stringify(wishlist));
  }, [wishlist]);

  useEffect(() => {
    localStorage.setItem('history', JSON.stringify(orderHistory));
  }, [orderHistory]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('currentUser', JSON.stringify(user));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [user]);

  // Toast Logic
  const addToast = (message: string, type: 'success' | 'info') => {
    const id = Date.now();
    setToasts([...toasts, { id, message, type }]);
    setTimeout(() => removeToast(id), 3500);
  };

  const removeToast = (id: number) => {
    setToasts((current) => current.filter((t) => t.id !== id));
  };

  // Auth Logic
  const handleLogin = (newUser: User) => {
    setUser(newUser);
    setIsAuthOpen(false);
    setTimeout(() => setIsAnnouncementOpen(true), 300);
    addToast(`Welcome back, ${newUser.name}!`, 'success');
  };

  const handleLogout = () => {
    setUser(null);
    setIsDashboardOpen(false);
    addToast('Logged out successfully', 'info');
  };

  // --- CART LOGIC (Persistent Storage) ---
  const addToCart = (product: Product, variantIndex: number) => {
    const existingItem = cart.find(item => item.product.appName === product.appName && item.selectedVariantIndex === variantIndex);

    if (existingItem) {
      updateQuantity(existingItem.id, 1);
      addToast(`${product.appName} added to bag`, 'success');
    } else {
      const id = `${product.appName}-${variantIndex}-${Date.now()}`;
      const newItem: CartItem = {
        id,
        product,
        selectedVariantIndex: variantIndex,
        quantity: 1
      };
      setCart([...cart, newItem]);
      addToast(`${product.appName} added to bag`, 'success');
    }
  };

  // --- BUY NOW LOGIC (Direct Checkout, No Storage) ---
  const handleBuyNow = (product: Product, variantIndex: number) => {
    // Create a temporary item that exists ONLY for this transaction
    const tempItem: CartItem = {
      id: `DIRECT-${Date.now()}`,
      product,
      selectedVariantIndex: variantIndex,
      quantity: 1
    };

    // Set the direct item state and open modal
    setDirectCheckoutItem(tempItem);
    setIsCartOpen(true);
  };

  const openCart = () => {
    // When opening via Navbar icon, we want to view the stored Cart items
    setDirectCheckoutItem(null); 
    setIsCartOpen(true);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const removeFromCart = (id: string) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const clearCart = (selectedIds?: string[]) => {
    if (selectedIds) {
      setCart(cart.filter(item => !selectedIds.includes(item.id)));
    } else {
      setCart([]);
    }
  };

  const saveOrder = (order: Order) => {
    setOrderHistory([order, ...orderHistory]);
    addToast('Order confirmed successfully!', 'success');
  };

  // Wishlist Logic
  const toggleWishlist = (appName: string) => {
    if (wishlist.includes(appName)) {
      setWishlist(wishlist.filter(id => id !== appName));
      addToast(`${appName} removed from wishlist`, 'info');
    } else {
      setWishlist([...wishlist, appName]);
      addToast(`${appName} added to wishlist`, 'success');
    }
  };

  const removeFromWishlist = (appName: string) => {
    setWishlist(wishlist.filter(id => id !== appName));
    addToast(`${appName} removed from wishlist`, 'info');
  };

  // Filter Logic
  const filteredProducts = useMemo(() => {
    return PRODUCTS.filter(product => {
      const matchesSearch = product.appName.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [searchQuery, selectedCategory]);

  return (
    <div className="relative min-h-screen font-sans selection:bg-gold-500/30 bg-stone-50 dark:bg-[#0f0505] transition-colors duration-500">
      <LiquidBackground />
      <Toast toasts={toasts} removeToast={removeToast} />

      <Navbar 
        toggleTheme={() => setIsDarkMode(!isDarkMode)}
        isDarkMode={isDarkMode}
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)}
        openCart={openCart}
        openWishlist={() => user ? setIsDashboardOpen(true) : setIsWishlistOpen(true)}
        openHistory={() => user ? setIsDashboardOpen(true) : setIsHistoryOpen(true)}
        openAuth={() => setIsAuthOpen(true)}
        openDashboard={() => setIsDashboardOpen(true)}
        user={user}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
      />

      {/* NEW HERO SECTION: Clean Burgundy Mode */}
      <section className="relative pt-16 pb-12 md:pt-28 md:pb-20 overflow-hidden">
        {/* Clean Ivory/Soft Gradient Background Overlay for Hero */}
        <div className="absolute inset-0 -z-10 bg-gradient-to-b from-stone-50 via-stone-50/90 to-transparent dark:from-[#0f0505] dark:via-[#0f0505]/90 dark:to-transparent"></div>
        <div className="absolute inset-0 -z-20 bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-burgundy-100/40 via-transparent to-transparent dark:from-burgundy-900/20 pointer-events-none"></div>

        <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 text-center relative z-10">

          {/* Floating Badge */}
          <div className="inline-flex items-center gap-2 px-4 py-1.5 mb-8 rounded-full bg-white dark:bg-white/5 border border-burgundy-900/10 dark:border-white/10 shadow-[0_2px_10px_-3px_rgba(128,0,32,0.1)] backdrop-blur-md animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
            </div>
            <span className="text-[10px] font-bold tracking-[0.2em] text-burgundy-800 dark:text-gold-400 uppercase">
              250++ ACCOUNT HAS BEEN SOLD
            </span>
          </div>

          {/* Main Title */}
          <h1 className="text-5xl md:text-7xl font-serif font-bold text-burgundy-950 dark:text-stone-100 tracking-tight mb-6 leading-[1.1] animate-in fade-in slide-in-from-bottom-8 duration-1000 fill-mode-backwards">
            Elevate Your <br className="hidden md:block" />
            <span className="bg-clip-text text-transparent bg-gradient-to-r from-burgundy-800 to-burgundy-500 dark:from-stone-100 dark:to-gold-300">
              Digital Lifestyle
            </span>
          </h1>

          {/* Subtitle */}
          <p className="max-w-2xl mx-auto text-lg text-stone-600 dark:text-stone-400 mb-10 leading-relaxed font-light animate-in fade-in slide-in-from-bottom-8 duration-1000 delay-200 fill-mode-backwards">
            Curated selection of premium subscriptions. Secure, warrantied, and instantly delivered to you.
          </p>

          {/* Elegant Wide Search Bar */}
          <div className="max-w-xl mx-auto relative group animate-in fade-in slide-in-from-bottom-8 duration-1000 delay-300 fill-mode-backwards">
            <div className="absolute inset-y-0 left-0 pl-6 flex items-center pointer-events-none">
              <Search className="text-burgundy-900/40 dark:text-stone-500 group-focus-within:text-burgundy-700 dark:group-focus-within:text-gold-500 transition-colors" size={22} />
            </div>
            <input 
              type="text"
              placeholder="Search app..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="block w-full pl-16 pr-6 py-5 rounded-2xl bg-white dark:bg-white/5 border border-burgundy-900/5 dark:border-white/10 text-lg shadow-[0_8px_30px_rgb(0,0,0,0.04)] dark:shadow-none focus:outline-none focus:ring-2 focus:ring-burgundy-900/10 dark:focus:ring-gold-500/20 transition-all placeholder-stone-400 text-burgundy-950 dark:text-stone-100 hover:shadow-[0_8px_30px_rgb(0,0,0,0.08)]"
            />
          </div>
        </div>
      </section>

      <main className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-4 pb-24" id="products-grid">

        {/* Category Filters */}
        <div className="flex flex-wrap justify-center gap-3 mb-10 relative z-10">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`px-5 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 border backdrop-blur-md ${
                selectedCategory === cat
                  ? 'bg-burgundy-950 dark:bg-stone-100 text-stone-100 dark:text-burgundy-950 border-burgundy-950 dark:border-stone-100 shadow-lg shadow-burgundy-900/20'
                  : 'bg-white/30 dark:bg-black/20 text-burgundy-900/70 dark:text-stone-400 border-burgundy-900/5 dark:border-white/5 hover:bg-white/50 dark:hover:bg-white/10 hover:border-gold-500/30'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Product Grid */}
        {filteredProducts.length > 0 ? (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 relative z-10">
            {filteredProducts.map((product) => (
              <ProductCard 
                key={product.appName}
                product={product}
                addToCart={addToCart}
                onBuyNow={handleBuyNow}
                toggleWishlist={toggleWishlist}
                isWishlisted={wishlist.includes(product.appName)}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-20 relative z-10">
            <div className="inline-flex h-16 w-16 items-center justify-center rounded-full bg-burgundy-100/50 dark:bg-white/5 mb-4 text-burgundy-300 dark:text-stone-600">
               <Sparkles size={32} />
            </div>
            <p className="text-burgundy-900/50 dark:text-stone-500 text-lg">No collections found matching your criteria.</p>
            <button 
              onClick={() => {setSearchQuery(''); setSelectedCategory('All');}}
              className="mt-4 text-burgundy-700 dark:text-gold-500 hover:underline font-medium"
            >
              Clear Filters
            </button>
          </div>
        )}
      </main>

      {/* Modals */}
      <CartModal 
        isOpen={isCartOpen}
        onClose={() => setIsCartOpen(false)}
        cart={cart}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
        saveOrder={saveOrder}
        directCheckoutItem={directCheckoutItem}
      />

      {!user && (
        <>
          <WishlistModal 
            isOpen={isWishlistOpen}
            onClose={() => setIsWishlistOpen(false)}
            wishlistIds={wishlist}
            allProducts={PRODUCTS}
            removeFromWishlist={removeFromWishlist}
          />

          <HistoryModal
            isOpen={isHistoryOpen}
            onClose={() => setIsHistoryOpen(false)}
            history={orderHistory}
          />
        </>
      )}

      <TermsModal 
        isOpen={isTermsOpen}
        onClose={() => setIsTermsOpen(false)}
      />

      <AuthModal 
        isOpen={isAuthOpen}
        onClose={() => setIsAuthOpen(false)}
        onLogin={handleLogin}
      />

      <AnnouncementModal 
        isOpen={isAnnouncementOpen}
        onClose={() => setIsAnnouncementOpen(false)}
      />

      {user && (
        <DashboardModal 
          isOpen={isDashboardOpen}
          onClose={() => setIsDashboardOpen(false)}
          user={user}
          orders={orderHistory}
          wishlist={wishlist}
          allProducts={PRODUCTS}
          onLogout={handleLogout}
          removeFromWishlist={removeFromWishlist}
        />
      )}

      <footer className="text-center py-8 border-t border-burgundy-900/5 dark:border-white/5 mt-auto relative z-10 bg-white/30 dark:bg-black/20 backdrop-blur-md">
        <p className="text-sm text-burgundy-900/40 dark:text-stone-500 font-serif italic">
          &copy; {new Date().getFullYear()} Dhevv Premium Digital. Elevating Standards.
        </p>
      </footer>
    </div>
  );
};

