import React, { useState, useEffect, useRef } from 'react';
import { CartItem, Order, User } from '../types';
import { formatRupiah } from '../constants';
import { X, MessageCircle, ShieldCheck, User as UserIcon, Receipt, Clock, Hash, Upload, Image as ImageIcon, Trash2, ArrowLeft, CheckSquare, Square, ShoppingBag, Minus, Plus, AlertCircle, Timer } from 'lucide-react';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: (selectedIds?: string[]) => void;
  saveOrder: (order: Order) => void;
  directCheckoutItem?: CartItem | null;
  user: User | null; // Added User prop
}

type Step = 'cart' | 'invoice';

const CartModal: React.FC<CartModalProps> = ({ 
  isOpen, 
  onClose, 
  cart, 
  updateQuantity,
  removeFromCart,
  clearCart,
  saveOrder,
  directCheckoutItem,
  user
}) => {
  const [step, setStep] = useState<Step>('cart');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Invoice State
  const [customerName, setCustomerName] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [paymentProof, setPaymentProof] = useState<string | null>(null);
  const [error, setError] = useState('');
  const [timeLeft, setTimeLeft] = useState(24 * 60 * 60); // 24 Hours in seconds

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initialize Modal Logic
  useEffect(() => {
    if (isOpen) {
      if (directCheckoutItem) {
        setStep('invoice');
      } else {
        setStep('cart');
        setSelectedIds(new Set());
      }

      const date = new Date();
      const dateStr = date.toISOString().slice(0, 10).replace(/-/g, '');
      const randomStr = Math.floor(1000 + Math.random() * 9000).toString();
      setInvoiceNumber(`INV-${dateStr}-${randomStr}`);

      // Auto-fill user name if logged in
      setCustomerName(user ? user.name : ''); 
      setPaymentProof(null);
      setError('');
      setTimeLeft(24 * 60 * 60); // Reset timer
    }
  }, [isOpen, directCheckoutItem, user]);

  // Countdown Logic
  useEffect(() => {
    if (!isOpen || step !== 'invoice') return;

    const interval = setInterval(() => {
      setTimeLeft((prev) => (prev > 0 ? prev - 1 : 0));
    }, 1000);

    return () => clearInterval(interval);
  }, [isOpen, step]);

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  if (!isOpen) return null;

  // Helpers for Cart Logic
  const toggleSelection = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setSelectedIds(newSelected);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === cart.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(cart.map(item => item.id)));
    }
  };

  const itemsToCheckout = directCheckoutItem 
    ? [directCheckoutItem] 
    : cart.filter(item => selectedIds.has(item.id));

  const total = itemsToCheckout.reduce((acc, item) => acc + (item.product.variants[item.selectedVariantIndex].price * item.quantity), 0);

  const currentDate = new Date().toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
  const currentTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' });

  // Invoice Handlers
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Validation 1: Check File Type (Image only)
      if (!file.type.startsWith('image/')) {
        setError('Format file tidak valid. Harap upload gambar (JPG/PNG).');
        return;
      }

      // Validation 2: Check File Size (Max 2MB)
      if (file.size > 2 * 1024 * 1024) {
        setError('Ukuran file terlalu besar. Maksimal 2MB.');
        return;
      }

      const objectUrl = URL.createObjectURL(file);
      setPaymentProof(objectUrl);
      setError('');
    }
  };

  const handleConfirmOrder = () => {
    if (itemsToCheckout.length === 0) return;

    if (!customerName.trim()) {
      setError('Nama wajib diisi.');
      return;
    }

    if (!paymentProof) {
      setError('Wajib upload bukti pembayaran.');
      return;
    }

    let itemDetails = itemsToCheckout.map((item) => {
      const variant = item.product.variants[item.selectedVariantIndex];
      return `${item.product.appName} [${variant.type} - ${variant.duration}] (x${item.quantity})`;
    }).join(', ');

    const message = `Halo Admin, saya sudah melakukan pembayaran. 
No Invoice: ${invoiceNumber}
Nama: ${customerName}
Item: ${itemDetails}
Total: ${formatRupiah(total)}

Status: SUDAH UPLOAD BUKTI. 
Mohon diproses ya!`;

    const newOrder: Order = {
      id: invoiceNumber,
      date: new Date().toLocaleDateString('id-ID'),
      items: [...itemsToCheckout],
      total: total,
      status: 'Processing',
      paymentProof: paymentProof
    };
    saveOrder(newOrder);

    if (!directCheckoutItem) {
      const idsToRemove = Array.from(selectedIds);
      clearCart(idsToRemove);
    }

    const phoneNumber = "6282116505311"; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');
    onClose();
  };

  // --- RENDER: CART LIST STEP ---
  if (step === 'cart') {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 font-sans">
        <div className="absolute inset-0 bg-burgundy-950/80 dark:bg-black/90 backdrop-blur-md" onClick={onClose}></div>
        <div className="relative w-full max-w-lg max-h-[90vh] bg-stone-50/95 dark:bg-[#1a0505]/95 backdrop-blur-2xl border border-burgundy-900/30 dark:border-white/10 rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">

          <div className="flex items-center justify-between p-5 border-b border-burgundy-900/5 dark:border-white/5 bg-white/40 dark:bg-white/5">
             <h2 className="text-xl font-bold text-burgundy-950 dark:text-stone-100 flex items-center gap-2 font-serif">
              <ShoppingBag className="text-burgundy-700 dark:text-gold-500" />
              Shopping Cart
            </h2>
            <button onClick={onClose} className="p-2 rounded-full hover:bg-black/5 dark:hover:bg-white/10 text-stone-500">
              <X size={20} />
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-5 custom-scrollbar">
            {cart.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-full text-stone-400 gap-4">
                <div className="p-6 rounded-full bg-stone-100 dark:bg-white/5">
                   <ShoppingBag size={48} className="opacity-50" />
                </div>
                <p>Your cart is empty.</p>
              </div>
            ) : (
              <div className="space-y-4">
                 <div className="flex items-center gap-3 pb-2 border-b border-burgundy-900/5 dark:border-white/5">
                    <button onClick={toggleSelectAll} className="flex items-center gap-2 text-xs font-bold text-burgundy-900 dark:text-gold-500 uppercase tracking-wide">
                       {selectedIds.size === cart.length ? <CheckSquare size={18} /> : <Square size={18} />}
                       Select All
                    </button>
                 </div>

                 {cart.map(item => {
                   const variant = item.product.variants[item.selectedVariantIndex];
                   const isSelected = selectedIds.has(item.id);

                   return (
                     <div key={item.id} className={`flex items-start gap-3 p-3 rounded-xl transition-all border ${isSelected ? 'bg-burgundy-50 dark:bg-burgundy-900/20 border-burgundy-900/20 dark:border-gold-500/30' : 'bg-white/50 dark:bg-white/5 border-transparent'}`}>
                       <button onClick={() => toggleSelection(item.id)} className="mt-1 text-burgundy-800 dark:text-gold-500 hover:scale-110 transition-transform">
                          {isSelected ? <CheckSquare size={20} /> : <Square size={20} className="text-stone-300 dark:text-stone-600" />}
                       </button>

                       <div className="h-16 w-16 rounded-lg bg-stone-200 dark:bg-black/40 flex-shrink-0 flex items-center justify-center font-serif font-bold text-burgundy-900 dark:text-stone-400 text-xl">
                          {item.product.appName.charAt(0)}
                       </div>

                       <div className="flex-1 min-w-0">
                          <h4 className="font-bold text-burgundy-950 dark:text-stone-100 truncate">{item.product.appName}</h4>
                          <p className="text-xs text-stone-500 truncate">{variant.type} • {variant.duration}</p>
