                onClick={() => setIsTutorialOpen(!isTutorialOpen)}
                className="w-full flex items-center justify-between p-4 rounded-2xl bg-white/40 dark:bg-burgundy-950/40 backdrop-blur-xl border border-burgundy-900/10 dark:border-white/10 shadow-lg hover:shadow-xl hover:bg-white/50 dark:hover:bg-burgundy-900/50 transition-all group"
            >
                <div className="flex items-center gap-4 text-left">
                     <div className="h-12 w-12 rounded-xl bg-gradient-to-br from-gold-400 to-gold-600 flex items-center justify-center text-burgundy-950 shadow-inner group-hover:scale-105 transition-transform">
                        <Box size={24} strokeWidth={1.5} />
                     </div>
                     <div>
                        <h3 className="font-bold text-burgundy-950 dark:text-stone-100 text-lg group-hover:text-burgundy-700 dark:group-hover:text-gold-300 transition-colors">Proses Pembelian</h3>
                        <p className="text-xs text-stone-500 dark:text-stone-400">6 langkah mudah untuk membeli produk</p>
                     </div>
                </div>
                <div className={`p-2 rounded-full bg-white/50 dark:bg-white/10 transition-transform duration-500 ${isTutorialOpen ? 'rotate-180 bg-gold-100 dark:bg-gold-900/20 text-gold-700 dark:text-gold-400' : 'text-burgundy-900 dark:text-stone-300'}`}>
                    <ChevronDown size={20} />
                </div>
            </button>

            {/* Collapsible Content */}
            <div className={`overflow-hidden transition-all duration-700 ease-in-out ${isTutorialOpen ? 'max-h-[800px] opacity-100 mt-4' : 'max-h-0 opacity-0'}`}>
                <div className="rounded-3xl border border-burgundy-900/10 dark:border-white/10 bg-white/30 dark:bg-burgundy-950/30 backdrop-blur-xl shadow-2xl overflow-hidden p-6 md:p-8">
                    {/* Horizontal Scroll Container */}
                    <div className="flex flex-nowrap overflow-x-auto gap-6 md:gap-0 md:grid md:grid-cols-6 custom-scrollbar pb-4 md:pb-0 snap-x snap-mandatory">
                        {TUTORIAL_STEPS.map((step, idx) => (
                            <div key={idx} className="flex-none w-48 md:w-auto relative group text-left md:text-center px-4 md:px-2 snap-center first:pl-0">
                                {/* Connector Line (Desktop Only) */}
                                {idx !== TUTORIAL_STEPS.length - 1 && (
                                  <div className="hidden md:block absolute top-10 left-[60%] w-full h-[1px] bg-gradient-to-r from-gold-500/30 to-transparent z-0"></div>
                                )}

                                <div className="relative z-10 flex flex-col md:items-center h-full">
                                  {/* Number Badge */}
                                  <span className="text-xs font-bold text-gold-600 dark:text-gold-500 mb-3 font-mono tracking-widest bg-gold-50 dark:bg-gold-900/20 px-2 py-0.5 rounded-md inline-block">
                                    {step.num}
                                  </span>

                                  {/* Icon */}
                                  <div className="h-14 w-14 rounded-2xl bg-gradient-to-br from-white to-stone-100 dark:from-burgundy-900 dark:to-black border border-burgundy-900/5 dark:border-white/10 flex items-center justify-center text-burgundy-700 dark:text-gold-400 shadow-md mb-4 group-hover:scale-110 group-hover:shadow-gold-500/20 transition-all duration-300">
                                      <step.icon size={24} strokeWidth={1.5} />
                                  </div>

                                  {/* Content */}
                                  <h3 className="font-bold text-sm text-burgundy-950 dark:text-stone-100 leading-tight mb-2">
                                    {step.title}
                                  </h3>
                                  <p className="text-[11px] text-stone-500 dark:text-stone-400 leading-relaxed opacity-80 group-hover:opacity-100 transition-opacity">
                                    {step.desc}
                                  </p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
          </div>

        </div>
      </section>

      <main className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8 py-4 pb-24" id="products-grid">

        {/* Category Filters */}
        <div className="flex flex-wrap justify-center gap-3 mb-10 relative z-10">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setSelectedCategory(cat)}
              className={`px-5 py-2.5 rounded-xl text-sm font-semibold transition-all duration-300 border backdrop-blur-md ${
                selectedCategory === cat
                  ? 'bg-burgundy-950 dark:bg-stone-100 text-stone-100 dark:text-burgundy-950 border-burgundy-950 dark:border-stone-100 shadow-lg shadow-burgundy-900/20'
                  : 'bg-white/30 dark:bg-black/20 text-burgundy-900/70 dark:text-stone-400 border-burgundy-900/5 dark:border-white/5 hover:bg-white/50 dark:hover:bg-white/10 hover:border-gold-500/30'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Product Grid */}
        {filteredProducts.length > 0 ? (
          <div 
            key={selectedCategory} // Force re-render for smooth animation when category changes
            className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 relative z-10 animate-in fade-in zoom-in-95 duration-500"
          >
            {filteredProducts.map((product) => (
              <ProductCard 
                key={product.appName}
                product={product}
                addToCart={addToCart}
                onBuyNow={handleBuyNow}
                toggleWishlist={toggleWishlist}
                isWishlisted={wishlist.includes(product.appName)}
              />
            ))}
          </div>
        ) : (
          <div className="text-center py-20 relative z-10 animate-in fade-in zoom-in-95 duration-500">
            <div className="inline-flex h-16 w-16 items-center justify-center rounded-full bg-burgundy-100/50 dark:bg-white/5 mb-4 text-burgundy-300 dark:text-stone-600">
               <Sparkles size={32} />
            </div>
            <p className="text-burgundy-900/50 dark:text-stone-500 text-lg">No collections found matching your criteria.</p>
            <button 
              onClick={() => {setSearchQuery(''); setSelectedCategory('All');}}
              className="mt-4 text-burgundy-700 dark:text-gold-500 hover:underline font-medium"
            >
              Clear Filters
            </button>
          </div>
        )}
      </main>

      {/* Modals */}
      <CartModal 
        isOpen={isCartOpen}
        onClose={() => setIsCartOpen(false)}
        cart={cart}
        updateQuantity={updateQuantity}
        removeFromCart={removeFromCart}
        clearCart={clearCart}
        saveOrder={saveOrder}
        directCheckoutItem={directCheckoutItem}
        user={user} // Pass user to allow auto-fill
      />

      {!user && (
        <>
          <WishlistModal 
            isOpen={isWishlistOpen}
            onClose={() => setIsWishlistOpen(false)}
            wishlistIds={wishlist}
            allProducts={PRODUCTS}
            removeFromWishlist={removeFromWishlist}
          />

          <HistoryModal
            isOpen={isHistoryOpen}
            onClose={() => setIsHistoryOpen(false)}
            history={orderHistory}
          />
        </>
      )}

      <TermsModal 
        isOpen={isTermsOpen}
        onClose={() => setIsTermsOpen(false)}
      />

      <AuthModal 
        isOpen={isAuthOpen}
        onClose={() => setIsAuthOpen(false)}
        onLogin={handleLogin}
      />

      <AnnouncementModal 
        isOpen={isAnnouncementOpen}
        onClose={() => setIsAnnouncementOpen(false)}
      />

      {user && (
        <DashboardModal 
          isOpen={isDashboardOpen}
          onClose={() => setIsDashboardOpen(false)}
          user={user}
          orders={orderHistory}
          wishlist={wishlist}
          allProducts={PRODUCTS}
          onLogout={handleLogout}
          removeFromWishlist={removeFromWishlist}
        />
      )}

      <footer className="text-center py-8 border-t border-burgundy-900/5 dark:border-white/5 mt-auto relative z-10 bg-white/30 dark:bg-black/20 backdrop-blur-md">
        <p className="text-sm text-burgundy-900/40 dark:text-stone-500 font-serif italic">
          &copy; {new Date().getFullYear()} Dhevv Premium Digital. Elevating Standards.
        </p>
      </footer>
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';
import { ShoppingCart, Moon, Sun, Search, LogIn } from 'lucide-react';
import { User as UserType } from '../types';

interface NavbarProps {
  toggleTheme: () => void;
  isDarkMode: boolean;
  cartCount: number;
  openCart: () => void;
  openAuth: () => void;
  openDashboard: () => void;
  user: UserType | null;
  searchQuery: string;
  setSearchQuery: (query: string) => void;
}

const Navbar: React.FC<NavbarProps> = ({ 
  toggleTheme, 
  isDarkMode, 
  cartCount, 
  openCart,
  openAuth,
  openDashboard,
  user,
  searchQuery,
  setSearchQuery
}) => {
  const [isBouncing, setIsBouncing] = useState(false);

  // Trigger animation when cartCount increases
  useEffect(() => {
    if (cartCount > 0) {
      setIsBouncing(true);
      const timer = setTimeout(() => setIsBouncing(false), 300); // 300ms animation
      return () => clearTimeout(timer);
    }
  }, [cartCount]);

  return (
    <nav className="sticky top-0 z-40 w-full">
      {/* Glassmorphism Container */}
      <div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">
        <div className="relative my-4 rounded-2xl border border-white/20 dark:border-white/5 bg-white/70 dark:bg-burgundy-950/40 backdrop-blur-xl shadow-2xl transition-all duration-300">
          <div className="flex h-16 items-center justify-between px-4 sm:px-6 gap-4">

            {/* Logo */}
            <div className="flex-shrink-0 flex items-center gap-3 group cursor-pointer">
              <div className="h-9 w-9 rounded-lg bg-gradient-to-br from-burgundy-800 to-burgundy-950 border border-gold-500/30 flex items-center justify-center text-gold-400 font-serif font-bold text-xl shadow-lg group-hover:shadow-gold-500/20 transition-all">
                P
              </div>
              <span className="hidden md:block text-xl font-bold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-burgundy-900 to-burgundy-700 dark:from-stone-100 dark:to-gold-200">
                Dhevv<span className="font-light italic">Premium</span>
              </span>
            </div>

            {/* Central Search Bar */}
            <div className="flex-1 max-w-md hidden sm:block">
              <div className="relative group">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Search className="text-burgundy-900/40 dark:text-stone-500" size={16} />
                </div>
                <input 
                  type="text"
                  placeholder="Search products..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="block w-full pl-10 pr-4 py-2 rounded-xl bg-white/50 dark:bg-white/5 border border-burgundy-900/10 dark:border-white/10 text-sm focus:outline-none focus:ring-2 focus:ring-gold-500/20 transition-all placeholder-stone-400 text-burgundy-950 dark:text-stone-100"
                />
              </div>
            </div>

            {/* Right Actions */}
            <div className="flex items-center gap-2 sm:gap-4">

              {/* Login / Profile Button */}
              {user ? (
                 <button 
                  onClick={openDashboard}
                  className="flex items-center gap-2 px-3 py-1.5 rounded-xl bg-burgundy-100/50 dark:bg-white/10 text-burgundy-900 dark:text-stone-200 hover:bg-burgundy-200 dark:hover:bg-white/20 transition-all border border-transparent hover:border-gold-500/30"
                >
                  <div className="h-7 w-7 rounded-full bg-gradient-to-br from-gold-400 to-gold-600 flex items-center justify-center text-[10px] font-bold text-black shadow-inner">
                    {user.name.charAt(0).toUpperCase()}
                  </div>
                  <span className="text-xs font-bold hidden md:block max-w-[80px] truncate">{user.name}</span>
                </button>
              ) : (
                <button 
                  onClick={openAuth}
                  className="flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold bg-burgundy-950 dark:bg-stone-100 text-white dark:text-burgundy-950 hover:shadow-lg transition-all"
                >
                  <LogIn size={16} />
                  <span className="hidden sm:inline">Login</span>
                </button>
              )}

              {/* Theme Toggle */}
              <button
                onClick={toggleTheme}
                className="p-2.5 rounded-xl text-burgundy-900 dark:text-stone-300 hover:bg-burgundy-100/50 dark:hover:bg-white/5 transition-all hover:text-burgundy-700 dark:hover:text-gold-300"
                aria-label="Toggle Theme"
              >
                {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
              </button>

              {/* Cart */}
              <button
                onClick={openCart}
                className={`group relative p-2.5 ml-1 rounded-xl bg-gradient-to-b from-burgundy-800 to-burgundy-950 dark:from-burgundy-900 dark:to-black text-gold-100 shadow-lg shadow-burgundy-900/20 hover:shadow-burgundy-900/40 transition-all duration-300 border border-white/10 ${isBouncing ? 'scale-110 ring-2 ring-gold-500/50' : 'hover:scale-105'}`}
              >
                <ShoppingCart size={20} className={isBouncing ? 'animate-bounce' : ''} />
                {cartCount > 0 && (
                  <span className="absolute -top-1 -right-1 flex h-4 w-4 items-center justify-center rounded-full bg-gold-600 text-[10px] font-bold text-black ring-2 ring-stone-100 dark:ring-burgundy-950 animate-pulse">
                    {cartCount}
                  </span>
                )}
              </button>
            </div>

          </div>
        </div>
      </div>
    </nav>
  );
};

