                        <div className="flex gap-3">
                            <div className="h-10 w-10 rounded-lg bg-stone-100 dark:bg-black/30 flex items-center justify-center font-bold text-burgundy-800 dark:text-stone-400 border border-stone-200 dark:border-white/5">
                                {item.product.appName.charAt(0)}
                            </div>
                            <div>
                                <p className="font-bold text-sm text-burgundy-900 dark:text-stone-200 leading-tight">{item.product.appName}</p>
                                <p className="text-xs text-stone-500 mt-0.5">{variant.type}</p>
                                <div className="flex items-center gap-2 mt-1">
