                  <div className="absolute bottom-2 left-2 px-2 py-1 bg-black/60 rounded text-[10px] text-white flex items-center gap-1">
                    <ImageIcon size={10} /> Image Uploaded
                  </div>
                </div>
              )}
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept="image/png, image/jpeg, image/jpg"
              />
            </div>

            {error && (
              <div className="p-3 rounded-lg bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-500/20 flex items-center gap-2 animate-pulse">
                <AlertCircle size={16} className="text-red-500" />
                <p className="text-xs text-red-600 dark:text-red-400 font-medium">{error}</p>
              </div>
            )}
          </div>
        </div>

        {/* Footer Action */}
        <div className="p-5 border-t border-burgundy-900/5 dark:border-white/5 bg-stone-100/50 dark:bg-black/30 backdrop-blur-sm">
          <button
            onClick={handleConfirmOrder}
            disabled={isSending}
            className="w-full flex items-center justify-center gap-2 py-3.5 rounded-xl bg-[#25D366] hover:bg-[#20bd5a] text-white font-bold text-sm uppercase tracking-wide shadow-lg shadow-green-500/20 hover:shadow-green-500/40 hover:-translate-y-0.5 transition-all duration-300 disabled:opacity-70 disabled:cursor-not-allowed"
          >
            {isSending ? (
              <span className="flex items-center gap-2">
                <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full"></div>
                Sending...
              </span>
            ) : (
              <>
                <MessageCircle size={18} />
                Confirm via WhatsApp
              </>
            )}
          </button>
        </div>

      </div>
    </div>
  );
};

export default CartModal;

import React, { useState, useEffect, useRef } from 'react';
import { CartItem, Order, User } from '../types';
import { formatRupiah } from '../constants';
import { X, MessageCircle, ShieldCheck, User as UserIcon, Receipt, Clock, Hash, Upload, Image as ImageIcon, Trash2, ArrowLeft, CheckSquare, Square, ShoppingBag, Minus, Plus, AlertCircle, Timer, Phone, Send } from 'lucide-react';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: (selectedIds?: string[]) => void;
  saveOrder: (order: Order) => void;
  directCheckoutItem?: CartItem | null;
  user: User | null; // Added User prop
}

type Step = 'cart' | 'invoice';

const CartModal: React.FC<CartModalProps> = ({ 
  isOpen, 
  onClose, 
  cart, 
  updateQuantity,
  removeFromCart,
  clearCart,
  saveOrder,
  directCheckoutItem,
  user
}) => {
  const [step, setStep] = useState<Step>('cart');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Invoice State
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState(''); // New State for Phone
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [paymentProof, setPaymentProof] = useState<string | null>(null);
  const [paymentFile, setPaymentFile] = useState<File | null>(null); // New State for Raw File
  const [error, setError] = useState('');
  const [isSending, setIsSending] = useState(false);
  const [timeLeft, setTimeLeft] = useState(24 * 60 * 60); // 24 Hours in seconds

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initialize Modal Logic
  useEffect(() => {
    if (isOpen) {
      if (directCheckoutItem) {
        setStep('invoice');
      } else {
        setStep('cart');
        setSelectedIds(new Set());
      }

      const date = new Date();
      const dateStr = date.toISOString().slice(0, 10).replace(/-/g, '');
      const randomStr = Math.floor(1000 + Math.random() * 9000).toString();
      setInvoiceNumber(`INV-${dateStr}-${randomStr}`);

      // Auto-fill user data if logged in
      setCustomerName(user ? user.name : ''); 
      setCustomerPhone(user?.phoneNumber || '');
      setPaymentProof(null);
      setPaymentFile(null);
      setError('');
      setIsSending(false);
      setTimeLeft(24 * 60 * 60); // Reset timer
    }
  }, [isOpen, directCheckoutItem, user]);

  // Countdown Logic
  useEffect(() => {
    if (!isOpen || step !== 'invoice') return;

    const interval = setInterval(() => {
      setTimeLeft((prev) => (prev > 0 ? prev - 1 : 0));
    }, 1000);

    return () => clearInterval(interval);
  }, [isOpen, step]);

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  if (!isOpen) return null;

  // Helpers for Cart Logic
  const toggleSelection = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setSelectedIds(newSelected);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === cart.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(cart.map(item => item.id)));
    }
  };

  const itemsToCheckout = directCheckoutItem 
    ? [directCheckoutItem] 
    : cart.filter(item => selectedIds.has(item.id));

  const total = itemsToCheckout.reduce((acc, item) => acc + (item.product.variants[item.selectedVariantIndex].price * item.quantity), 0);

  const currentDate = new Date().toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
  const currentTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' });

  // Invoice Handlers
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Validation 1: Check File Type (Image only)
      if (!file.type.startsWith('image/')) {
        setError('Format file tidak valid. Harap upload gambar (JPG/PNG).');
        return;
      }

      // Validation 2: Check File Size (Max 2MB)
      if (file.size > 2 * 1024 * 1024) {
        setError('Ukuran file terlalu besar. Maksimal 2MB.');
        return;
      }

      const objectUrl = URL.createObjectURL(file);
      setPaymentProof(objectUrl);
      setPaymentFile(file); // Store raw file for Telegram
      setError('');
    }
  };

  const sendCheckoutToTelegram = async () => {
    if (!paymentFile) return;

    const botToken = "8526909837:AAEgNfIAHl9rj-fbqo108xtX8PqRyrpyGiQ";
    const chatId = "2130333895";
    const url = `https://api.telegram.org/bot${botToken}/sendPhoto`;

    // Construct Caption
    const productNames = itemsToCheckout.map(i => 
      `- ${i.product.appName} [${i.product.variants[i.selectedVariantIndex].type}]`
    ).join('\n');

    const caption = `💰 PESANAN BARU + BUKTI BAYAR
--------------------------
👤 Nama: ${customerName}
📦 Produk: 
${productNames}
💵 Total: ${formatRupiah(total)}
📱 WA: ${customerPhone || '-'}
--------------------------
Tolong segera dicek Bos Daffa!`;

    const formData = new FormData();
    formData.append("chat_id", chatId);
    formData.append("photo", paymentFile);
    formData.append("caption", caption);

    try {
      const response = await fetch(url, {
        method: "POST",
        body: formData,
      });

      if (response.ok) {
        alert("Bukti pembayaran berhasil dikirim!");
      } else {
        console.error("Telegram Error:", await response.text());
      }
    } catch (error) {
      console.error("Failed to send to Telegram:", error);
    }
  };

  const handleConfirmOrder = async () => {
    if (itemsToCheckout.length === 0) return;

    if (!customerName.trim()) {
      setError('Nama wajib diisi.');
      return;
    }

    if (!paymentProof) {
      setError('Wajib upload bukti pembayaran.');
      return;
    }

    setIsSending(true);

    // 1. Send to Telegram (Async)
    await sendCheckoutToTelegram();

    // 2. Prepare Data for Local & WhatsApp
    let itemDetails = itemsToCheckout.map((item) => {
      const variant = item.product.variants[item.selectedVariantIndex];
      return `${item.product.appName} [${variant.type} - ${variant.duration}] (x${item.quantity})`;
    }).join(', ');

    const message = `Halo Admin, saya sudah melakukan pembayaran. 
No Invoice: ${invoiceNumber}
Nama: ${customerName}
WA: ${customerPhone}
Item: ${itemDetails}
Total: ${formatRupiah(total)}

Status: SUDAH UPLOAD BUKTI. 
Mohon diproses ya!`;

    const newOrder: Order = {
      id: invoiceNumber,
      date: new Date().toLocaleDateString('id-ID'),
      items: [...itemsToCheckout],
      total: total,
      status: 'Processing',
      paymentProof: paymentProof
    };

    // 3. Save Order Locally
    saveOrder(newOrder);

    if (!directCheckoutItem) {
      const idsToRemove = Array.from(selectedIds);
      clearCart(idsToRemove);
    }

    setIsSending(false);

    // 4. Redirect to WhatsApp
    const phoneNumber = "6282116505311"; 
    window.open(`https://wa.me/${phoneNumber}?text=${encodeURIComponent(message)}`, '_blank');
    onClose();
  };

  // --- RENDER: CART LIST STEP ---
  if (step === 'cart') {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 font-sans">
        <div className="absolute inset-0 bg-burgundy-950/80 dark:bg-black/90 backdrop-blur-md" onClick={onClose}></div>
        <div className="relative w-full max-w-lg max-h-[90vh] bg-stone-50/95 dark:bg-[#1a0505]/95 backdrop-blur-2xl border border-burgundy-900/30 dark:border-white/10 rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">

