          </div>
        </div>

        {/* Footer Action */}
        <div className="p-5 border-t border-burgundy-900/5 dark:border-white/5 bg-stone-100/50 dark:bg-black/30 backdrop-blur-sm">
          <button
            onClick={handleConfirmOrder}
            disabled={isSending}
            className="w-full flex items-center justify-center gap-2 py-3.5 rounded-xl bg-[#25D366] hover:bg-[#20bd5a] text-white font-bold text-sm uppercase tracking-wide shadow-lg shadow-green-500/20 hover:shadow-green-500/40 hover:-translate-y-0.5 transition-all duration-300 disabled:opacity-70 disabled:cursor-not-allowed"
          >
            {isSending ? (
              <span className="flex items-center gap-2">
