import React, { useState, useEffect, useRef } from 'react';
import { CartItem, Order, User } from '../types';
import { formatRupiah } from '../constants';
import { X, MessageCircle, ShieldCheck, User as UserIcon, Receipt, Clock, Hash, Upload, Image as ImageIcon, Trash2, ArrowLeft, CheckSquare, Square, ShoppingBag, Minus, Plus, AlertCircle, Timer, Phone, Send, CheckCircle, Sparkles, Lock } from 'lucide-react';

interface CartModalProps {
  isOpen: boolean;
  onClose: () => void;
  cart: CartItem[];
  updateQuantity: (id: string, delta: number) => void;
  removeFromCart: (id: string) => void;
  clearCart: (selectedIds?: string[]) => void;
  saveOrder: (order: Order) => void;
  directCheckoutItem?: CartItem | null;
  user: User | null;
  onOpenAuth: () => void; // Added prop to trigger Auth Modal
}

type Step = 'cart' | 'invoice' | 'success';

const CartModal: React.FC<CartModalProps> = ({ 
  isOpen, 
  onClose, 
  cart, 
  updateQuantity,
  removeFromCart,
  clearCart,
  saveOrder,
  directCheckoutItem,
  user,
  onOpenAuth
}) => {
  const [step, setStep] = useState<Step>('cart');
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());

  // Invoice State
  const [customerName, setCustomerName] = useState('');
  const [customerPhone, setCustomerPhone] = useState('');
  const [invoiceNumber, setInvoiceNumber] = useState('');
  const [paymentProof, setPaymentProof] = useState<string | null>(null);
  const [paymentFile, setPaymentFile] = useState<File | null>(null);
  const [error, setError] = useState('');
  const [isSending, setIsSending] = useState(false);
  const [timeLeft, setTimeLeft] = useState(24 * 60 * 60);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Initialize Modal Logic
  useEffect(() => {
    if (isOpen) {
      if (directCheckoutItem) {
        setStep('invoice');
      } else {
        setStep('cart');
        setSelectedIds(new Set());
      }

      const date = new Date();
      const dateStr = date.toISOString().slice(0, 10).replace(/-/g, '');
      const randomStr = Math.floor(1000 + Math.random() * 9000).toString();
      setInvoiceNumber(`INV-${dateStr}-${randomStr}`);

      // Auto-fill user data if logged in
      if (user) {
        setCustomerName(user.name);
        setCustomerPhone(user.phoneNumber || '');
      } else {
        setCustomerName('');
        setCustomerPhone('');
      }

      setPaymentProof(null);
      setPaymentFile(null);
      setError('');
      setIsSending(false);
      setTimeLeft(24 * 60 * 60);
    }
  }, [isOpen, directCheckoutItem, user]);

  // Countdown Logic
  useEffect(() => {
    if (!isOpen || step !== 'invoice') return;

    const interval = setInterval(() => {
      setTimeLeft((prev) => (prev > 0 ? prev - 1 : 0));
    }, 1000);

    return () => clearInterval(interval);
  }, [isOpen, step]);

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  if (!isOpen) return null;

  // Helpers for Cart Logic
  const toggleSelection = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setSelectedIds(newSelected);
  };

  const toggleSelectAll = () => {
    if (selectedIds.size === cart.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(cart.map(item => item.id)));
    }
  };

  const itemsToCheckout = directCheckoutItem 
    ? [directCheckoutItem] 
    : cart.filter(item => selectedIds.has(item.id));

  const total = itemsToCheckout.reduce((acc, item) => acc + (item.product.variants[item.selectedVariantIndex].price * item.quantity), 0);

  const currentDate = new Date().toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
  const currentTime = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit' });

  // Invoice Handlers
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setError('Format file tidak valid. Harap upload gambar (JPG/PNG).');
        return;
      }
      if (file.size > 2 * 1024 * 1024) {
        setError('Ukuran file terlalu besar. Maksimal 2MB.');
        return;
      }
      const objectUrl = URL.createObjectURL(file);
      setPaymentProof(objectUrl);
      setPaymentFile(file);
      setError('');
    }
  };

  const sendCheckoutToTelegram = async () => {
    if (!paymentFile) return;

    const botToken = "8526909837:AAEgNfIAHl9rj-fbqo108xtX8PqRyrpyGiQ";
    const chatId = "2130333895";
    const url = `https://api.telegram.org/bot${botToken}/sendPhoto`;

    // Construct Caption
    const productNames = itemsToCheckout.map(i => 
      `- ${i.product.appName} [${i.product.variants[i.selectedVariantIndex].type}]`
    ).join('\n');

    const caption = `💰 PESANAN BARU + BUKTI BAYAR
--------------------------
👤 Nama: ${customerName}
📦 Produk: 
${productNames}
💵 Total: ${formatRupiah(total)}
📱 WA: ${customerPhone || '-'}
--------------------------
Tolong segera dicek Bos Daffa!`;

    const formData = new FormData();
    formData.append("chat_id", chatId);
    formData.append("photo", paymentFile);
    formData.append("caption", caption);

    try {
      const response = await fetch(url, {
        method: "POST",
        body: formData,
      });

      if (!response.ok) {
        console.error("Telegram Error:", await response.text());
      }
    } catch (error) {
      console.error("Failed to send to Telegram:", error);
    }
  };

  const handleConfirmOrder = async (e?: React.MouseEvent) => {
    if (e) e.preventDefault();

    // LOGIN PROTECTION CHECK
    if (!user) {
      setError('Silakan Login/Daftar terlebih dahulu untuk melakukan pemesanan.');
      setTimeout(() => {
        onOpenAuth(); // Trigger Auth Modal
      }, 1500); // Slight delay to let user read the error
      return;
    }

    if (itemsToCheckout.length === 0) return;

    if (!customerName.trim()) {
      setError('Nama wajib diisi.');
      return;
    }

    if (!paymentProof) {
      setError('Wajib upload bukti pembayaran.');
      return;
    }

    setIsSending(true);

    // 1. Send to Telegram (Async)
    await sendCheckoutToTelegram();

    const newOrder: Order = {
      id: invoiceNumber,
      date: new Date().toLocaleDateString('id-ID'),
      items: [...itemsToCheckout],
      total: total,
      status: 'Processing',
      paymentProof: paymentProof
    };

    // 2. Save Order Locally
    saveOrder(newOrder);

    // 3. Clear Cart if needed
    if (!directCheckoutItem) {
      const idsToRemove = Array.from(selectedIds);
      clearCart(idsToRemove);
    }

    setIsSending(false);

    // 4. Show Success State
    setStep('success');
  };

  // --- RENDER: SUCCESS STEP ---
  if (step === 'success') {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 font-sans">
        <div className="absolute inset-0 bg-burgundy-950/80 dark:bg-black/90 backdrop-blur-md" onClick={onClose}></div>
        <div className="relative w-full max-w-sm bg-white dark:bg-[#1a0505] rounded-3xl shadow-2xl p-8 flex flex-col items-center text-center animate-in zoom-in-95 duration-500 overflow-hidden">

             <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none opacity-30">
                <div className="absolute top-[-20%] left-[-20%] w-40 h-40 bg-gold-500/40 rounded-full blur-[60px] animate-pulse"></div>
                <div className="absolute bottom-[-20%] right-[-20%] w-40 h-40 bg-burgundy-500/40 rounded-full blur-[60px] animate-pulse"></div>
            </div>

            <div className="relative z-10">
                <div className="h-20 w-20 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center mx-auto mb-6 animate-bounce">
                    <CheckCircle size={40} className="text-emerald-600 dark:text-emerald-400" />
                </div>

                <h2 className="text-2xl font-bold text-burgundy-950 dark:text-stone-100 mb-2 font-serif">
                    Pesanan Berhasil!
                </h2>
                <p className="text-sm text-stone-600 dark:text-stone-400 mb-6 leading-relaxed">
                    Terima kasih <b>{customerName}</b>. <br/>
                    Bukti pembayaran telah kami terima. Admin akan segera memproses pesananmu.
                </p>

                <div className="bg-stone-50 dark:bg-white/5 rounded-xl p-4 mb-6 border border-burgundy-900/5 dark:border-white/5">
                    <p className="text-xs text-stone-500 uppercase tracking-widest mb-1">Order ID</p>
                    <p className="font-mono font-bold text-burgundy-900 dark:text-gold-400 text-lg">{invoiceNumber}</p>
                </div>

                <button 
                    onClick={onClose}
                    className="w-full py-3.5 rounded-xl bg-burgundy-950 dark:bg-stone-100 text-stone-100 dark:text-burgundy-950 font-bold uppercase tracking-wide hover:shadow-lg hover:-translate-y-0.5 transition-all"
                >
                    Tutup
                </button>
            </div>
        </div>
      </div>
    );
  }

  // --- RENDER: CART LIST STEP ---
  if (step === 'cart') {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 font-sans">
        <div className="absolute inset-0 bg-burgundy-950/80 dark:bg-black/90 backdrop-blur-md" onClick={onClose}></div>
        <div className="relative w-full max-w-lg max-h-[90vh] bg-stone-50/95 dark:bg-[#1a0505]/95 backdrop-blur-2xl border border-burgundy-900/30 dark:border-white/10 rounded-3xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-300">

          <div className="flex items-center justify-between p-5 border-b border-burgundy-900/5 dark:border-white/5 bg-white/40 dark:bg-white/5">
             <h2 className="text-xl font-bold text-burgundy-950 dark:text-stone-100 flex items-center gap-2 font-serif">
              <ShoppingBag className="text-burgundy-700 dark:text-gold-500" />
