                    value={customerPhone}
                    readOnly={!!user?.phoneNumber} // Read-only only if phone number exists
                    onChange={(e) => setCustomerPhone(e.target.value)}
                    className={`block w-full pl-9 pr-3 py-3 border rounded-xl text-sm focus:outline-none focus:ring-1 focus:ring-gold-500/50 transition-all border-burgundy-900/10 dark:border-white/10 text-burgundy-950 dark:text-stone-100 placeholder-stone-400 ${
                        user?.phoneNumber
                        ? 'bg-stone-100 dark:bg-white/5 opacity-80 cursor-not-allowed' 
                        : 'bg-white/50 dark:bg-black/20'
