interface AuthModalProps {
  isOpen: boolean;
  onClose: () => void;
  onLogin: (user: UserType) => void;
}

const AuthModal: React.FC<AuthModalProps> = ({ isOpen, onClose, onLogin }) => {
  const [isRegister, setIsRegister] = useState(false);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [error, setError] = useState('');

  if (!isOpen) return null;

  const sendTelegramNotification = (name: string, email: string, phone: string) => {
    const token = "8313935707:AAEvip1y0UNvFkOnXXT6Oa_en2R6XzLXXd8";
    const chatId = "2130333895";
    const date = new Date().toLocaleString('id-ID');

    // Using Markdown for cleaner formatting
    const message = `*🔔 MEMBER BARU TERDAFTAR*
-------------------------
👤 *Nama:* ${name}
📧 *Email:* ${email}
📱 *WA:* ${phone}
📅 *Waktu:* ${date}`;

    const url = `https://api.telegram.org/bot${token}/sendMessage`;
    const params = new URLSearchParams({
        chat_id: chatId,
        text: message,
        parse_mode: 'Markdown'
    });

    // Fire and forget using 'no-cors' to prevent blocking the UI
    fetch(`${url}?${params.toString()}`, {
        method: 'GET',
        mode: 'no-cors' 
    }).catch(err => console.error("Telegram notification failed", err));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!email || !password || (isRegister && (!name || !phoneNumber))) {
      setError('Please fill in all fields');
      return;
    }

    if (isRegister) {
      // Send background notification
      sendTelegramNotification(name, email, phoneNumber);
    }

    // Simulate Auth
    const newUser: UserType = {
      name: isRegister ? name : 'Member User', // Use input name or default
      email: email,
      phoneNumber: isRegister ? phoneNumber : undefined,
      memberSince: new Date().toLocaleDateString('id-ID', { year: 'numeric', month: 'long', day: 'numeric' }),
      password: password, // Store password for simulation purposes
    };

    onLogin(newUser);
    // Reset form
    setName('');
    setEmail('');
    setPassword('');
    setPhoneNumber('');
  };

  return (
