import React, { useState, useEffect } from 'react';
import { User as UserType, Order, Product } from '../types';
import { X, User, Package, Heart, LogOut, Sparkles, ShoppingBag, FileCheck, Hourglass, Settings, Save, Lock, Phone } from 'lucide-react';
