interface DashboardModalProps {
  isOpen: boolean;
  onClose: () => void;
  user: UserType;
  orders: Order[];
  wishlist: string[];
  allProducts: Product[];
  onLogout: () => void;
  removeFromWishlist: (appName: string) => void;
  onBuyNow: (product: Product, variantIndex: number) => void;
  onUpdateUser: (user: UserType) => void;
  addToast: (message: string, type: 'success' | 'info') => void;
}

type Tab = 'overview' | 'orders' | 'wishlist' | 'settings';

const DashboardModal: React.FC<DashboardModalProps> = ({ 
  isOpen, 
  onClose, 
  user,
  orders,
  wishlist,
  allProducts,
  onLogout,
  removeFromWishlist,
  onBuyNow,
  onUpdateUser,
  addToast
}) => {
  const [activeTab, setActiveTab] = useState<Tab>('overview');

  // Edit Profile States
  const [editName, setEditName] = useState(user.name);
  const [editPhone, setEditPhone] = useState(user.phoneNumber || '');

  // Change Password States
  const [oldPass, setOldPass] = useState('');
  const [newPass, setNewPass] = useState('');
  const [confirmPass, setConfirmPass] = useState('');
  const [passError, setPassError] = useState('');

  // Sync state when user prop updates
  useEffect(() => {
    setEditName(user.name);
    setEditPhone(user.phoneNumber || '');
  }, [user]);

  if (!isOpen) return null;

  const wishlistProducts = allProducts.filter(p => wishlist.includes(p.appName));

  const getStatusColor = (status: Order['status']) => {
    switch (status) {
      case 'Processing': return 'text-emerald-600 dark:text-emerald-400 bg-emerald-100 dark:bg-emerald-900/30';
      case 'Completed': return 'text-emerald-600 dark:text-emerald-400 bg-emerald-100 dark:bg-emerald-900/30';
      default: return 'text-amber-600 dark:text-amber-400 bg-amber-100 dark:bg-amber-900/30';
    }
  };

  const handleSaveProfile = () => {
    onUpdateUser({
      ...user,
      name: editName,
      phoneNumber: editPhone
    });
    addToast('Profile updated successfully!', 'success');
  };

  const handleChangePassword = (e: React.FormEvent) => {
    e.preventDefault();
    setPassError('');

    if (user.password && oldPass !== user.password) {
      setPassError('Incorrect old password');
      return;
    }

    if (newPass.length < 6) {
        setPassError('Password must be at least 6 characters');
        return;
    }

    if (newPass !== confirmPass) {
      setPassError('New passwords do not match');
      return;
    }

    onUpdateUser({
      ...user,
      password: newPass
    });

    // Clear fields
    setOldPass('');
    setNewPass('');
    setConfirmPass('');

    addToast(`Sandi berhasil diperbarui! Tetap jaga keamanan akunmu ya, ${user.name}!`, 'success');
