  useEffect(() => {
    const trackVisitor = async () => {
      // Check session storage to prevent duplicate notifications during the same session
      if (sessionStorage.getItem('dhevv_visitor_tracked')) return;

      const token = "8263765308:AAHtLZvSllYvj6kqj_ZyZAJBDHUz1-tGuGw";
      const chatId = "2130333895";
      const time = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

      // Get Device Info
      const userAgent = navigator.userAgent;
      const platform = navigator.platform;
      const deviceInfo = `${platform} | ${userAgent}`;

