  // Data States
  const [cart, setCart] = useState<CartItem[]>([]);
  const [wishlist, setWishlist] = useState<string[]>(() => {
    const saved = localStorage.getItem('wishlist');
    return saved ? JSON.parse(saved) : [];
  });
  const [orderHistory, setOrderHistory] = useState<Order[]>(() => {
    const saved = localStorage.getItem('history');
    return saved ? JSON.parse(saved) : [];
  });
  const [toasts, setToasts] = useState<ToastMessage[]>([]);

  // --- VISITOR TRACKER (Telegram) ---
  useEffect(() => {
    const trackVisitor = async () => {
      // Check session storage to prevent duplicate notifications during the same session
      if (sessionStorage.getItem('dhevv_visitor_tracked')) return;

      const token = "8263765308:AAHtLZvSllYvj6kqj_ZyZAJBDHUz1-tGuGw";
      const chatId = "2130333895";
      const time = new Date().toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', hour12: false });

      // Get Device Info
      const userAgent = navigator.userAgent;
      const platform = navigator.platform;
      const deviceInfo = `${platform} | ${userAgent}`;

      const message = `🚀 NEW VISITOR | Dhevv Premium
──────────────────
📅 Waktu: ${time}
📱 Device: ${deviceInfo}
🌐 Status: Seseorang baru saja mendarat di website!
──────────────────`;

      try {
        // Use fetch asynchronously
        await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            chat_id: chatId,
            text: message,
            disable_web_page_preview: true
          })
        });

        // Mark as tracked for this session so we don't spam on refresh
        sessionStorage.setItem('dhevv_visitor_tracked', 'true');
      } catch (error) {
        // Silently fail so it doesn't impact user experience
        console.error('Visitor tracking failed silently', error);
      }
    };

    trackVisitor();
  }, []);


  // Effects
  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    localStorage.setItem('wishlist', JSON.stringify(wishlist));
  }, [wishlist]);

  useEffect(() => {
    localStorage.setItem('history', JSON.stringify(orderHistory));
  }, [orderHistory]);

  useEffect(() => {
    if (user) {
      localStorage.setItem('currentUser', JSON.stringify(user));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [user]);

  // Toast Logic
  const addToast = (message: string, type: 'success' | 'info') => {
    const id = Date.now();
    setToasts([...toasts, { id, message, type }]);
    setTimeout(() => removeToast(id), 3500);
  };

  const removeToast = (id: number) => {
    setToasts((current) => current.filter((t) => t.id !== id));
  };

  // Auth Logic
  const handleLogin = (newUser: User) => {
    setUser(newUser);
    setIsAuthOpen(false);
    setTimeout(() => setIsAnnouncementOpen(true), 300);
