  const generateResponse = (input: string): string => {
    const lowerInput = input.toLowerCase();

    // 1. Greetings
    if (['halo', 'hi', 'hai', 'hello', 'pagi', 'siang', 'malam'].some(w => lowerInput.includes(w))) {
      return "Halo! Ada yang bisa Dhevv bantu? Mau cari Netflix, Spotify, atau tanya soal Sharing vs Private?";
    }

    // 2. Product Search (Dynamic from PRODUCTS constant)
    const foundProduct = PRODUCTS.find(p => lowerInput.includes(p.appName.toLowerCase()));
    if (foundProduct) {
      const startPrice = formatRupiah(foundProduct.variants[0].price);
      return `${foundProduct.appName} tersedia! Mulai dari ${startPrice}. Ada varian ${foundProduct.variants.map(v => v.type).join(', ')}. Mau beli yang mana?`;
    }

    // 3. Definitions (Knowledge Base)
    if (lowerInput.includes('sharing') && lowerInput.includes('private')) {
      return "Bedanya simpel kak: \n\n• **Sharing**: 1 Akun dipakai bareng user lain. Murah, tapi dilarang ganti password/profil. \n• **Private**: Akun khusus buat kakak sendiri. Bebas atur profil & lebih stabil. \n\nPilih sesuai budget ya!";
    }
    if (lowerInput.includes('sharing')) {
      return "Sharing itu artinya 1 akun dipakai rame-rame (patungan). Harganya jauh lebih murah, tapi ada aturannya: Dilarang ganti password & profil orang lain ya.";
    }
    if (lowerInput.includes('private')) {
      return "Private itu akun sultan! Kakak dapat akun utuh buat sendiri. Bisa ganti password, bikin profil sendiri, history tontonan aman, dan pastinya lebih anti-limit.";
    }

