import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Sparkles, Bot, Minimize2 } from 'lucide-react';
import { GoogleGenAI, Chat } from "@google/genai";
import { PRODUCTS, formatRupiah } from '../constants';

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'bot';
  timestamp: Date;
}

const AIChatWidget: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [chatSession, setChatSession] = useState<Chat | null>(null);

  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      text: "Halo! Saya Dhevv AI. Bingung mau pilih aplikasi premium yang mana? Tanya saya apa saja ya! ✨",
      sender: 'bot',
      timestamp: new Date()
    }
  ]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Initialize Gemini Chat Session with Product Context
  useEffect(() => {
    const initChat = async () => {
      try {
        // Guard: Check if API key exists
        if (!process.env.API_KEY) {
          console.warn("Dhevv AI: API_KEY not found in process.env");
          return;
        }

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Construct Dynamic Product Knowledge Base
        const productContext = PRODUCTS.map(p => {
          const variants = p.variants.map(v => 
            `- ${v.type} (${v.duration}): ${formatRupiah(v.price)} ${v.note ? `(Note: ${v.note})` : ''}`
          ).join('\n');
          return `**${p.appName}** (${p.category})\n${variants}`;
        }).join('\n\n');

        const systemInstruction = `
          Anda adalah Dhevv AI, asisten virtual cerdas untuk "Dhevv Premium Digital Store".

          **Tugas Utama:**
          1. Membantu pelanggan memilih produk digital (Streaming, Musik, Desain, dll).
          2. Menjelaskan perbedaan akun Sharing vs Private.
          3. Memberikan informasi harga yang AKURAT sesuai database produk di bawah ini.
          4. Memandu cara pembayaran.

          **Database Produk & Harga Resmi:**
          ${productContext}

          **Informasi Layanan:**
          - **Sharing**: 1 Akun dipakai bersama user lain. Lebih murah. Dilarang ganti email/password/profil. 1 Device only.
          - **Private**: Akun khusus milik pembeli (1 akun 1 orang). Bisa ganti password/profil. Lebih stabil & eksklusif.
          - **Cara Beli**: Pilih Produk > Klik 'Add' atau 'Buy Now' > Isi Nama > Scan QRIS > Upload Bukti > Akun dikirim via WhatsApp.
          - **Garansi**: Full garansi selama masa aktif jika mematuhi aturan. Klaim via Admin WA.

          **Gaya Komunikasi:**
          - Gunakan Bahasa Indonesia yang ramah, santai, dan membantu.
          - Gunakan emoji secukupnya agar menarik (✨, 🚀, 📦).
          - Jawaban harus ringkas dan mudah dibaca di layar HP (gunakan poin-poin atau bold).
          - Jika produk tidak ada di database, katakan mohon maaf produk belum tersedia.
        `;

        const chat = ai.chats.create({
          model: 'gemini-3-pro-preview',
          config: {
            systemInstruction: systemInstruction,
            temperature: 0.7, 
          }
        });

        setChatSession(chat);
      } catch (error) {
        console.error("Dhevv AI Init Error:", error);
      }
    };

    initChat();
  }, []);

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping, isOpen]);

  // Focus input when opened
  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 300);
    }
  }, [isOpen]);

  const toggleChat = () => setIsOpen(!isOpen);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!inputValue.trim()) return;

    const userText = inputValue;

    // 1. Add User Message
    const userMsg: Message = {
      id: Date.now().toString(),
      text: userText,
      sender: 'user',
      timestamp: new Date()
    };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsTyping(true);

    // 2. Generate AI Response
    try {
      let responseText = "Maaf, koneksi ke Dhevv AI sedang gangguan. Silakan hubungi admin manual.";

      if (chatSession) {
        const result = await chatSession.sendMessage({ message: userText });
        if (result.text) {
          responseText = result.text;
        }
      } else {
        responseText = "Maaf, fitur AI belum siap (API Key Missing). Silakan hubungi admin via WhatsApp.";
      }

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        text: responseText,
        sender: 'bot',
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error("AI Response Error:", error);
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        text: "Maaf, saya sedang pusing 😵. Coba tanya lagi nanti ya!",
        sender: 'bot',
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <>
      {/* Floating Button */}
      <div 
        className="fixed bottom-5 right-5 z-[60] flex flex-col items-end gap-2"
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >
        {/* Hover Tooltip (Desktop only) */}
        {!isOpen && (
          <div className={`transition-all duration-300 origin-right ${isHovered ? 'opacity-100 scale-100 translate-x-0' : 'opacity-0 scale-90 translate-x-4 pointer-events-none'}`}>
            <div className="bg-white dark:bg-stone-800 text-burgundy-950 dark:text-stone-100 px-4 py-2 rounded-xl shadow-lg border border-burgundy-900/10 dark:border-white/10 text-xs font-bold mb-2">
              Butuh bantuan? Chat Dhevv AI! 👋
            </div>
          </div>
        )}

        <button
          onClick={toggleChat}
          className={`group relative flex items-center justify-center h-14 w-14 rounded-full shadow-[0_0_20px_rgba(128,0,32,0.3)] border border-white/20 transition-all duration-300 ${
            isOpen 
              ? 'bg-stone-100 dark:bg-stone-800 rotate-90' 
              : 'bg-gradient-to-br from-burgundy-800 to-burgundy-950 hover:scale-110'
          }`}
        >
          {isOpen ? (
            <X className="text-burgundy-900 dark:text-stone-200" size={24} />
          ) : (
            <>
              <MessageCircle className="text-gold-100 group-hover:text-white transition-colors" size={28} />
              {/* Pulse Indicator */}
              <span className="absolute top-0 right-0 h-4 w-4">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-gold-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-4 w-4 bg-gold-500 border-2 border-burgundy-900"></span>
              </span>
            </>
          )}
        </button>
      </div>

      {/* Chat Window */}
      {isOpen && (
        <div className="fixed bottom-[5.5rem] right-4 sm:right-6 z-[60] w-[calc(100%-2rem)] sm:w-[380px] max-w-[380px] h-[500px] max-h-[70vh] flex flex-col rounded-3xl bg-white/90 dark:bg-[#1a0505]/95 backdrop-blur-2xl border border-burgundy-900/10 dark:border-white/10 shadow-2xl overflow-hidden animate-in slide-in-from-bottom-10 fade-in duration-300 origin-bottom-right">

          {/* Header */}
          <div className="h-16 px-5 flex items-center justify-between bg-gradient-to-r from-burgundy-950 to-burgundy-900 dark:from-black dark:to-burgundy-950/50">
            <div className="flex items-center gap-3">
              <div className="h-10 w-10 rounded-full bg-white/10 flex items-center justify-center border border-white/20 shadow-inner relative">
                <Bot className="text-gold-400" size={22} />
                <div className="absolute -bottom-0.5 -right-0.5 h-3 w-3 bg-emerald-500 border-2 border-burgundy-900 rounded-full"></div>
              </div>
              <div>
                <h3 className="text-white font-bold font-serif text-sm flex items-center gap-1">
                  Dhevv AI <Sparkles size={10} className="text-gold-400" />
                </h3>
                <p className="text-[10px] text-white/60">Powered by Gemini 3.0</p>
              </div>
            </div>
            <button onClick={toggleChat} className="text-white/50 hover:text-white transition-colors">
              <Minimize2 size={18} />
            </button>
          </div>

          {/* Messages Area */}
          <div className="flex-1 overflow-y-auto p-4 custom-scrollbar space-y-4 bg-stone-50/50 dark:bg-transparent">
            {messages.map((msg) => (
              <div 
                key={msg.id} 
                className={`flex w-full ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
              >
                <div 
                  className={`max-w-[85%] p-3.5 rounded-2xl text-sm leading-relaxed shadow-sm ${
                    msg.sender === 'user' 
                      ? 'bg-burgundy-900 text-white rounded-tr-none' 
                      : 'bg-white dark:bg-white/10 text-stone-700 dark:text-stone-200 border border-burgundy-900/5 dark:border-white/5 rounded-tl-none'
                  }`}
                >
                  {/* Render text with basic markdown-like bold parsing */}
                  {msg.text.split('\n').map((line, i) => (
                    <p key={i} className={`min-h-[1em] ${i > 0 ? 'mt-1' : ''}`}>
                      {line.split(/(\*\*.*?\*\*)/).map((part, j) => 
                        part.startsWith('**') && part.endsWith('**') 
                          ? <strong key={j} className="text-gold-300 dark:text-gold-400 font-bold">{part.slice(2, -2)}</strong> 
                          : part
                      )}
                    </p>
                  ))}
                  <p className={`text-[9px] mt-1 text-right opacity-60 ${msg.sender === 'user' ? 'text-white' : 'text-stone-400'}`}>
                    {msg.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </p>
                </div>
              </div>
            ))}

            {/* Typing Indicator */}
            {isTyping && (
              <div className="flex justify-start w-full">
                <div className="bg-white dark:bg-white/10 border border-burgundy-900/5 dark:border-white/5 p-4 rounded-2xl rounded-tl-none flex items-center gap-1.5 w-16 h-10">
                  <span className="w-1.5 h-1.5 bg-stone-400 rounded-full animate-bounce"></span>
                  <span className="w-1.5 h-1.5 bg-stone-400 rounded-full animate-bounce delay-100"></span>
                  <span className="w-1.5 h-1.5 bg-stone-400 rounded-full animate-bounce delay-200"></span>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <form onSubmit={handleSend} className="p-3 bg-white dark:bg-black/20 border-t border-burgundy-900/5 dark:border-white/5">
            <div className="relative flex items-center">
              <input
                ref={inputRef}
                type="text"
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                placeholder="Tanya sesuatu..."
                className="w-full pl-4 pr-12 py-3 bg-stone-100 dark:bg-white/5 border border-transparent focus:border-burgundy-900/30 dark:focus:border-gold-500/30 rounded-xl text-sm text-burgundy-950 dark:text-stone-100 placeholder-stone-400 focus:outline-none transition-all"
              />
              <button 
                type="submit"
                disabled={!inputValue.trim()}
                className="absolute right-2 p-2 rounded-lg bg-burgundy-900 text-white disabled:opacity-50 disabled:bg-stone-300 dark:disabled:bg-white/10 hover:bg-burgundy-800 transition-colors"
              >
                <Send size={16} />
              </button>
            </div>
            <div className="text-center mt-2">
                <p className="text-[9px] text-stone-400 dark:text-stone-500">
                    AI powered by Dhevv Engine v2.0 (Gemini)
                </p>
            </div>
          </form>

        </div>
      )}
    </>
  );
};

