import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Sparkles, Bot, ArrowLeft } from 'lucide-react';
import { GoogleGenAI, Chat } from "@google/genai";
import { PRODUCTS, formatRupiah } from '../constants';

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'bot';
  timestamp: Date;
}

const AIChatWidget: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [chatSession, setChatSession] = useState<Chat | null>(null);

  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      text: "Halo! Saya Dhevv AI. Bingung mau pilih aplikasi premium yang mana? Tanya saya apa saja ya! ✨",
      sender: 'bot',
      timestamp: new Date()
    }
  ]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Initialize Gemini Chat Session
  useEffect(() => {
    const initChat = async () => {
      try {
        if (!process.env.API_KEY) {
            console.error("API Key is missing. Please check process.env.API_KEY");
            return;
        }

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        const productContext = PRODUCTS.map(p => {
          const variants = p.variants.map(v => 
            `- ${v.type} (${v.duration}): ${formatRupiah(v.price)}`
          ).join('\n');
          return `**${p.appName}**\n${variants}`;
        }).join('\n\n');

        const systemInstruction = `
          Anda adalah Dhevv AI, asisten virtual ramah untuk "Dhevv Premium".
          Tugas: Bantu pilih produk, jelaskan Sharing vs Private, dan info harga.

          Database Produk:
          ${productContext}

          Aturan Penting:
          - Sharing: Murah, 1 akun rame-rame, dilarang ganti pass.
          - Private: Eksklusif, bisa ganti pass, lebih aman.
          - Jika user mau beli, arahkan untuk klik tombol 'Add' atau 'Buy Now' di produk terkait.
          - Gunakan Bahasa Indonesia yang asik, santai, dan solutif (seperti teman).
        `;

        const chat = ai.chats.create({
          model: 'gemini-3-pro-preview',
          config: {
            systemInstruction: systemInstruction,
          }
        });

        setChatSession(chat);
      } catch (error) {
        console.error("Dhevv AI Init Error:", error);
      }
    };

    initChat();
  }, []);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping, isOpen]);

  // Handle Body Scroll & Blur
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      setTimeout(() => inputRef.current?.focus(), 300);
    } else {
      document.body.style.overflow = 'auto';
    }
    return () => {
        document.body.style.overflow = 'auto';
    };
  }, [isOpen]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!inputValue.trim() || isTyping) return;

    const userText = inputValue;

    // Add User Message
    setMessages(prev => [...prev, {
      id: Date.now().toString(),
      text: userText,
      sender: 'user',
      timestamp: new Date()
    }]);

    setInputValue('');
    setIsTyping(true);

    try {
      if (chatSession) {
        const result = await chatSession.sendMessage({ message: userText });
        const botText = result.text;

        if (botText) {
          setMessages(prev => [...prev, {
            id: (Date.now() + 1).toString(),
            text: botText,
            sender: 'bot',
            timestamp: new Date()
          }]);
        }
      } else {
        throw new Error("Chat session not initialized");
      }
    } catch (error) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        text: "Waduh, koneksi lagi agak lemot nih. Tanya lagi ya, Daffa!",
        sender: 'bot',
        timestamp: new Date()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <>
      {/* Tombol Floating - Hilang kalau Chat Terbuka */}
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          className="fixed bottom-5 right-5 z-[50] h-14 w-14 rounded-full bg-gradient-to-br from-burgundy-800 to-burgundy-950 shadow-lg flex items-center justify-center border border-white/20 transition-transform hover:scale-110"
        >
          <MessageCircle className="text-white" size={28} />
          {isHovered && (
            <div className="absolute right-16 bg-white text-burgundy-900 px-3 py-1 rounded-lg text-xs font-bold whitespace-nowrap shadow-md">
              Chat Dhevv AI 👋
            </div>
          )}
        </button>
      )}

      {/* Jendela Chat */}
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 sm:p-4 font-sans">
          {/* Backdrop Blur */}
          <div className="absolute inset-0 bg-black/40 backdrop-blur-md" onClick={() => setIsOpen(false)} />

          <div className="relative w-full h-full sm:max-w-md sm:h-[80vh] bg-white dark:bg-[#1a0505] shadow-2xl flex flex-col sm:rounded-3xl overflow-hidden animate-in zoom-in-95 duration-300">
            {/* Header */}
            <div className="p-4 bg-burgundy-900 flex items-center justify-between text-white">
              <div className="flex items-center gap-3">
                <Bot className="text-gold-400" />
                <div>
                  <h3 className="font-bold text-sm">Dhevv AI Assistant</h3>
                  <p className="text-[10px] text-emerald-400 opacity-80 animate-pulse">● Online</p>
                </div>
              </div>
              <button onClick={() => setIsOpen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <ArrowLeft size={20} className="sm:hidden" />
                <X size={20} className="hidden sm:block" />
              </button>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-stone-50 dark:bg-stone-900/20">
              {messages.map((msg) => (
                <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${
                    msg.sender === 'user' ? 'bg-burgundy-800 text-white rounded-tr-none' : 'bg-white dark:bg-white/10 border dark:text-white rounded-tl-none shadow-sm'
                  }`}>
                     {/* Basic markdown parsing for bold text */}
                     {msg.text.split(/(\*\*.*?\*\*)/).map((part, index) => 
                        part.startsWith('**') && part.endsWith('**') 
                          ? <strong key={index}>{part.slice(2, -2)}</strong> 
                          : part
                      )}
                  </div>
                </div>
              ))}
              {isTyping && <div className="text-xs text-stone-400 animate-pulse">Dhevv AI sedang mengetik...</div>}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <form onSubmit={handleSend} className="p-4 border-t dark:border-white/5 bg-white dark:bg-stone-900">
              <div className="flex gap-2">
                <input
                  ref={inputRef}
                  type="text"
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  placeholder="Tanya harga atau aplikasi..."
                  className="flex-1 p-3 bg-stone-100 dark:bg-white/5 rounded-xl text-sm outline-none focus:ring-1 focus:ring-burgundy-500 dark:text-white"
                />
                <button type="submit" className="p-3 bg-burgundy-900 text-white rounded-xl hover:bg-burgundy-800">
                  <Send size={18} />
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

