import { PRODUCTS, formatRupiah } from '../constants';

// --- KONFIGURASI GROQ API ---
// Silakan tempel API Key Groq Anda di sini
const GROQ_API_KEY = "gsk_..."; // Ganti dengan API Key Groq Anda

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'bot';
  timestamp: Date;
}

const AIChatWidget: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      text: "Halo! Saya Dhevv AI. Bingung mau pilih aplikasi premium yang mana? Tanya saya apa saja ya! ✨",
      sender: 'bot',
      timestamp: new Date()
    }
  ]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping, isOpen]);

  // Handle Body Scroll & Blur focus
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      setTimeout(() => inputRef.current?.focus(), 300);
    } else {
      document.body.style.overflow = 'auto';
    }
    return () => {
        document.body.style.overflow = 'auto';
    };
  }, [isOpen]);

  const getSystemInstruction = () => {
    const productContext = PRODUCTS.map(p => {
      const variants = p.variants.map(v => 
        `- ${v.type} (${v.duration}): ${formatRupiah(v.price)}`
      ).join('\n');
      return `**${p.appName}**\n${variants}`;
    }).join('\n\n');

    return `
      Anda adalah Dhevv AI, asisten virtual ramah untuk "Dhevv Premium".

      **Tugas Utama:**
      1. Membantu pelanggan memilih produk digital (Streaming, Musik, Desain, dll).
      2. Menjelaskan perbedaan akun Sharing vs Private.
      3. Memberikan informasi harga yang AKURAT sesuai database produk di bawah.

      **Database Produk & Harga Resmi:**
      ${productContext}

      **Aturan Format Jawaban (WAJIB):**
      - **JANGAN** mengirim jawaban dalam satu paragraf panjang (wall of text).
      - Gunakan **Baris Baru (Enter)** antar poin agar mudah dibaca di HP.
      - Gunakan **Bullet Points (-)** atau **Angka (1., 2.)** untuk daftar harga atau langkah-langkah.
      - **Bold** nama produk dan harga penting (contoh: **Netflix Sharing** Rp 20.000).
      - Berikan jarak antar topik pembahasan.

      **Gaya Bahasa:**
      - Asik, ramah, santai, dan solutif (seperti teman tapi sopan).
      - Gunakan emoji secukupnya (✨, 🚀, 📦).
      - Jawaban ringkas dan padat.

      **Informasi Layanan:**
      - **Sharing**: Murah, 1 akun dipakai bersama, 1 device only, dilarang ganti password/profil.
      - **Private**: Eksklusif, milik sendiri, bisa ganti password, lebih aman & stabil.
      - **Cara Beli**: Arahkan klik tombol 'Add' atau 'Buy Now' di produk terkait.
    `;
  };

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!inputValue.trim() || isTyping) return;

    const userText = inputValue;

    // 1. Add User Message to UI
    const newUserMsg: Message = {
      id: Date.now().toString(),
      text: userText,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, newUserMsg]);
    setInputValue('');
    setIsTyping(true);

    try {
      // 2. Prepare History for Context (Llama3 needs history)
      // Kita ambil pesan sebelumnya, ubah ke format API Groq
      const conversationHistory = messages.map(m => ({
        role: m.sender === 'user' ? 'user' : 'assistant',
        content: m.text
      }));

      // Tambahkan pesan user terbaru
      conversationHistory.push({ role: 'user', content: userText });

      // 3. Call Groq API
      const response = await fetch("https://api.groq.com/openai/v1/chat/completions", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${GROQ_API_KEY}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          messages: [
            {
              role: "system",
              content: getSystemInstruction()
            },
            ...conversationHistory
          ],
          model: "llama3-8b-8192",
          temperature: 0.6,
          max_tokens: 1024,
        })
      });

      if (!response.ok) {
        throw new Error(`API Error: ${response.statusText}`);
      }

      const data = await response.json();
      const botText = data.choices[0]?.message?.content || "Maaf, saya tidak mengerti.";

      // 4. Add Bot Response to UI
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        text: botText,
        sender: 'bot',
        timestamp: new Date()
      }]);

    } catch (error) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        text: "Waduh, koneksi ke server lagi sibuk. Coba tanya lagi ya! (Cek API Key)",
        sender: 'bot',
        timestamp: new Date()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <>
      {/* Tombol Floating - Hilang kalau Chat Terbuka */}
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          className="fixed bottom-5 right-5 z-[50] h-14 w-14 rounded-full bg-gradient-to-br from-burgundy-800 to-burgundy-950 shadow-lg flex items-center justify-center border border-white/20 transition-transform hover:scale-110"
        >
          <MessageCircle className="text-white" size={28} />
          {isHovered && (
            <div className="absolute right-16 bg-white text-burgundy-900 px-3 py-1 rounded-lg text-xs font-bold whitespace-nowrap shadow-md">
              Chat Dhevv AI 👋
            </div>
          )}
        </button>
      )}

      {/* Jendela Chat */}
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 sm:p-4 font-sans">
          {/* Backdrop Blur */}
          <div className="absolute inset-0 bg-black/40 backdrop-blur-md" onClick={() => setIsOpen(false)} />

          <div className="relative w-full h-full sm:max-w-md sm:h-[80vh] bg-white dark:bg-[#1a0505] shadow-2xl flex flex-col sm:rounded-3xl overflow-hidden animate-in zoom-in-95 duration-300">
            {/* Header */}
            <div className="p-4 bg-burgundy-900 flex items-center justify-between text-white">
              <div className="flex items-center gap-3">
                <Bot className="text-gold-400" />
                <div>
                  <h3 className="font-bold text-sm">Dhevv AI Assistant</h3>
                  <p className="text-[10px] text-emerald-400 opacity-80 animate-pulse">● Online (Llama3)</p>
                </div>
              </div>
              <button onClick={() => setIsOpen(false)} className="p-2 hover:bg-white/10 rounded-full transition-colors">
                <ArrowLeft size={20} className="sm:hidden" />
                <X size={20} className="hidden sm:block" />
              </button>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-stone-50 dark:bg-stone-900/20">
              {messages.map((msg) => (
                <div key={msg.id} className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] p-3 rounded-2xl text-sm whitespace-pre-wrap ${
                    msg.sender === 'user' ? 'bg-burgundy-800 text-white rounded-tr-none' : 'bg-white dark:bg-white/10 border dark:text-white rounded-tl-none shadow-sm'
                  }`}>
                     {/* Basic markdown parsing for bold text */}
                     {msg.text.split(/(\*\*.*?\*\*)/).map((part, index) => 
