                                <p className="font-bold text-sm text-burgundy-900 dark:text-stone-200 leading-tight">{item.product.appName}</p>
                                <p className="text-xs text-stone-500 mt-0.5">{variant.type}</p>
                                <div className="flex items-center gap-2 mt-1">
                                    <span className="text-[10px] bg-stone-200 dark:bg-white/10 px-1.5 py-0.5 rounded text-stone-600 dark:text-stone-400 font-mono">{variant.duration}</span>
                                    <span className="text-xs text-stone-400">x{item.quantity}</span>
                                </div>
                            </div>
                        </div>
                        <p className="font-bold text-sm text-burgundy-950 dark:text-gold-400">{formatRupiah(subtotal)}</p>
                    </div>
                );
                })}
            </div>
            <div className="mt-4 pt-3 border-t border-stone-200 dark:border-white/10 flex justify-between items-center">
                <span className="text-xs font-bold text-stone-500 uppercase tracking-widest">Total Amount</span>
                <span className="text-2xl font-bold text-burgundy-900 dark:text-gold-400">{formatRupiah(total)}</span>
            </div>
          </div>

          <div className="space-y-4">
             <div>
                <label className="block text-xs font-bold text-stone-500 uppercase ml-1 mb-2">Customer Name</label>
                <div className="relative">
                   <UserIcon size={18} className="absolute left-4 top-3.5 text-stone-400" />
                   <input 
                     type="text" 
                     value={customerName}
                     onChange={(e) => setCustomerName(e.target.value)}
                     className="w-full pl-12 pr-4 py-3 rounded-xl bg-white dark:bg-white/5 border border-stone-200 dark:border-white/10 focus:ring-2 focus:ring-gold-500/50 outline-none text-sm dark:text-stone-200"
                     placeholder="Your Name"
                     readOnly={!!user}
                   />
                </div>
             </div>

             <div>
                <label className="block text-xs font-bold text-stone-500 uppercase ml-1 mb-2">Proof of Payment</label>
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className={`border-2 border-dashed rounded-xl p-6 flex flex-col items-center justify-center cursor-pointer transition-all ${paymentProof ? 'border-emerald-500 bg-emerald-50/50 dark:bg-emerald-900/10' : 'border-stone-300 dark:border-white/10 hover:border-gold-500 hover:bg-gold-50/50 dark:hover:bg-white/5'}`}
                >
                  <input ref={fileInputRef} type="file" accept="image/*" onChange={handleFileChange} className="hidden" />
                  {paymentProof ? (
                    <div className="relative w-full h-32 rounded-lg overflow-hidden group">
                       <img src={paymentProof} alt="Proof" className="w-full h-full object-cover" />
                       <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                          <span className="text-white text-xs font-bold flex items-center gap-1"><Upload size={14} /> Change</span>
                       </div>
                    </div>
                  ) : (
                    <>
                      <div className="h-10 w-10 rounded-full bg-stone-100 dark:bg-white/10 flex items-center justify-center mb-2 text-stone-400">
                        <ImageIcon size={20} />
                      </div>
                      <p className="text-sm font-bold text-stone-600 dark:text-stone-300">Upload Screenshot</p>
                      <p className="text-[10px] text-stone-400">JPG or PNG, Max 2MB</p>
                    </>
                  )}
                </div>
             </div>
          </div>
        </div>

        <div className="p-5 border-t border-burgundy-900/5 dark:border-white/5 bg-white/60 dark:bg-black/20 backdrop-blur-md">
           {error && (
             <div className="flex items-center gap-2 text-red-500 text-xs font-bold bg-red-50 dark:bg-red-900/20 p-3 rounded-xl mb-3 border border-red-100 dark:border-red-900/30">
               <AlertCircle size={14} /> {error}
             </div>
           )}
           <button 
             onClick={handleConfirmOrder} 
             disabled={isSending}
             className="w-full py-3.5 rounded-xl bg-gradient-to-r from-burgundy-950 to-burgundy-800 text-white font-bold uppercase tracking-wide hover:shadow-lg hover:-translate-y-0.5 transition-all shadow-burgundy-900/20 disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2"
           >
             {isSending ? (
               <>
                 <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                 Processing...
               </>
             ) : (
               <>
                 <Send size={18} /> Confirm Payment
               </>
             )}
           </button>
        </div>
      </div>
    </div>
  );
};

