                    <p className="text-3xl font-black text-burgundy-900 dark:text-stone-100">{wishlist.length}</p>
                  </div>
                </div>

                <div className="bg-white/40 dark:bg-white/5 backdrop-blur-md rounded-[35px] border border-white/20 p-8 shadow-sm">
