import React, { useState } from 'react';
import { formatRupiah } from '../constants';
import { Product } from '../types';
import { Heart, ShoppingCart, Zap } from 'lucide-react';

interface ProductCardProps {
  product: Product;
  addToCart: (product: Product, variantIndex: number) => void;
  onBuyNow: (product: Product, variantIndex: number) => void;
  toggleWishlist: (appName: string) => void;
  isWishlisted: boolean;
}

const ProductCard: React.FC<ProductCardProps> = ({ 
  product, 
  addToCart, 
  onBuyNow,
  toggleWishlist, 
  isWishlisted 
}) => {
  const [selectedVariantIdx, setSelectedVariantIdx] = useState(0);

  const currentVariant = product.variants?.[selectedVariantIdx] || product.variants?.[0];

  if (!currentVariant) {
    return null;
  }

  const handleAddToCart = () => {
    addToCart(product, selectedVariantIdx);
  };

  const handleBuyNow = () => {
    onBuyNow(product, selectedVariantIdx);
  };

  return (
    <div className="group relative flex flex-col overflow-hidden rounded-2xl border border-burgundy-900/10 dark:border-white/5 bg-white/30 dark:bg-burgundy-950/30 backdrop-blur-md shadow-lg transition-all duration-500 hover:shadow-2xl hover:border-gold-500/30 hover:-translate-y-1">

      {/* Decorative Glow */}
      <div className="absolute top-0 right-0 w-32 h-32 bg-gold-500/10 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 group-hover:bg-gold-500/20 transition-all duration-500"></div>

      {/* Header */}
      <div className="relative p-6 pb-4 z-10">
        <div className="flex justify-between items-start">
          <div className="flex items-center gap-4">
            <div className="h-14 w-14 rounded-2xl bg-gradient-to-br from-stone-100 to-stone-200 dark:from-burgundy-900 dark:to-black border border-white/20 dark:border-white/5 flex items-center justify-center text-burgundy-900 dark:text-gold-400 font-serif font-bold text-2xl shadow-inner">
              {product.appName.charAt(0)}
            </div>
            <div>
              <h3 className="text-lg font-bold text-burgundy-950 dark:text-stone-100 leading-tight group-hover:text-burgundy-700 dark:group-hover:text-gold-300 transition-colors">
                {product.appName}
              </h3>
              <p className="text-xs text-burgundy-800/60 dark:text-stone-400 font-medium tracking-wide uppercase">Premium Access</p>
            </div>
          </div>
          <button 
            onClick={() => toggleWishlist(product.appName)}
            className={`rounded-full p-2.5 transition-all duration-300 ${
              isWishlisted 
                ? 'bg-burgundy-50 dark:bg-burgundy-900/50 text-burgundy-600 dark:text-burgundy-400' 
                : 'text-stone-400 hover:bg-stone-100 dark:hover:bg-white/5 hover:text-burgundy-600 dark:hover:text-gold-400'
            }`}
          >
            <Heart size={18} fill={isWishlisted ? "currentColor" : "none"} />
          </button>
        </div>

        {/* Tags */}
        <div className="mt-4 flex flex-wrap gap-2">
          {product.tags?.map(tag => (
             <span key={tag} className="px-2.5 py-1 rounded-md bg-gradient-to-r from-gold-100 to-white dark:from-gold-900/30 dark:to-burgundy-900/30 text-[10px] font-bold tracking-wider text-gold-700 dark:text-gold-300 border border-gold-200 dark:border-gold-800/50">
               {tag}
             </span>
          ))}
        </div>
      </div>

      {/* Variant Selection */}
      <div className="flex-1 px-6 py-2 relative z-10">
        <label className="text-[10px] font-bold text-burgundy-900/50 dark:text-stone-400 mb-3 block uppercase tracking-widest">
          Select Package
        </label>

        <div className="custom-scrollbar max-h-[140px] overflow-y-auto pr-1 space-y-2 mb-2">
          {product.variants.map((variant, idx) => (
            <button
              key={idx}
              onClick={() => setSelectedVariantIdx(idx)}
              className={`w-full text-left p-3 rounded-xl border transition-all duration-300 relative overflow-hidden group/item ${
                selectedVariantIdx === idx
                  ? 'border-gold-500/50 bg-gold-50/50 dark:bg-gold-500/10 dark:border-gold-400'
                  : 'border-burgundy-900/5 dark:border-white/10 hover:bg-white/40 dark:hover:bg-white/5'
              }`}
            >
              <div className="flex justify-between items-center relative z-10">
                <div>
                  <p className={`text-xs font-semibold ${selectedVariantIdx === idx ? 'text-burgundy-900 dark:text-white' : 'text-stone-600 dark:text-stone-200'}`}>
                    {variant.type}
                  </p>
                  <p className="text-[10px] text-stone-400 dark:text-stone-400">
                    {variant.duration}
                  </p>
                </div>
                <div className="text-right">
                  <p className={`text-sm font-bold ${selectedVariantIdx === idx ? 'text-burgundy-900 dark:text-gold-400' : 'text-stone-800 dark:text-stone-200'}`}>
                    {formatRupiah(variant.price)}
                  </p>
                </div>
              </div>
            </button>
          ))}
        </div>

        {currentVariant.note && (
          <div className="mb-4 p-2.5 rounded-lg bg-stone-100/50 dark:bg-white/5 border border-stone-200 dark:border-white/5 text-[10px] text-stone-600 dark:text-stone-400 italic">
            <span className="font-semibold text-burgundy-800 dark:text-gold-500">Note:</span> {currentVariant.note}
          </div>
        )}
      </div>

      {/* Footer Action */}
      <div className="p-6 pt-2 mt-auto relative z-10">
        <div className="flex items-end justify-between mb-4">
           <div>
             <span className="text-[10px] font-bold text-burgundy-900/40 dark:text-stone-500 uppercase tracking-widest">Price</span>
             <p className="text-xl font-bold text-burgundy-950 dark:text-stone-100 font-sans">
               {formatRupiah(currentVariant.price)}
             </p>
           </div>
        </div>

        <div className="flex gap-3">
          {/* Add to Cart - Outline Style */}
          <button
            onClick={handleAddToCart}
            className="flex-1 py-3.5 px-3 rounded-xl border border-burgundy-900/30 dark:border-white/20 text-burgundy-900 dark:text-stone-200 font-bold text-xs uppercase tracking-wide hover:bg-burgundy-50 dark:hover:bg-white/5 transition-all flex items-center justify-center gap-2 group/add"
            title="Add to Cart"
          >
            <ShoppingCart size={18} className="group-hover/add:scale-110 transition-transform" />
            <span className="hidden sm:inline">Add</span>
          </button>

          {/* Buy Now - Solid Deep Burgundy */}
          <button
            onClick={handleBuyNow}
            className="flex-[2] py-3.5 px-4 rounded-xl bg-burgundy-950 dark:bg-gradient-to-r dark:from-burgundy-900 dark:to-burgundy-800 text-white dark:text-gold-100 font-bold text-xs uppercase tracking-wide shadow-lg shadow-burgundy-900/20 hover:shadow-burgundy-900/40 hover:-translate-y-0.5 transition-all flex items-center justify-center gap-2 group/btn relative overflow-hidden"
          >
            <span className="relative z-10 flex items-center gap-2">
              <Zap size={16} fill="currentColor" className="text-gold-400 animate-pulse" />
              Buy Now
            </span>
            {/* Shimmer Effect */}
            <div className="absolute inset-0 -translate-x-full group-hover/btn:translate-x-full bg-gradient-to-r from-transparent via-white/20 to-transparent transition-transform duration-700 ease-in-out"></div>
          </button>
        </div>
      </div>

    </div>
  );
};

export default ProductCard;

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Sparkles, Bot, ArrowLeft } from 'lucide-react';
import { PRODUCTS, formatRupiah } from '../constants';

// --- KONFIGURASI GROQ API ---
const GROQ_API_KEY = "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"; 

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'bot';
  timestamp: Date;
}

const AIChatWidget: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      text: "Halo! Saya Dhevv AI. Bingung mau pilih aplikasi premium yang mana? Tanya saya apa saja ya! ✨",
      sender: 'bot',
      timestamp: new Date()
    }
  ]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping, isOpen]);

  // Handle Body Scroll & Blur focus
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
      setTimeout(() => inputRef.current?.focus(), 100);
    } else {
      document.body.style.overflow = 'auto';
    }
    return () => {
        document.body.style.overflow = 'auto';
    };
  }, [isOpen]);

  const getSystemInstruction = () => {
    const productContext = PRODUCTS.map(p => {
      const variants = p.variants.map(v => 
        `- ${v.type} (${v.duration}): ${formatRupiah(v.price)}`
      ).join('\n');
      return `**${p.appName}**\n${variants}`;
    }).join('\n\n');

    return `
      Anda adalah Dhevv AI, asisten virtual ramah untuk "Dhevv Premium".

      **Tugas Utama:**
      1. Membantu pelanggan memilih produk digital (Streaming, Musik, Desain, dll).
      2. Menjelaskan perbedaan akun Sharing vs Private.
      3. Memberikan informasi harga yang AKURAT sesuai database produk di bawah.

      **Database Produk & Harga Resmi:**
      ${productContext}

      **Aturan Format Jawaban (WAJIB):**
      - **JANGAN** mengirim jawaban dalam satu paragraf panjang (wall of text).
      - Gunakan **Baris Baru (Enter)** antar poin agar mudah dibaca di HP.
      - Gunakan **Bullet Points (-)** atau **Angka (1., 2.)** untuk daftar harga atau langkah-langkah.
      - **Bold** nama produk dan harga penting (contoh: **Netflix Sharing** Rp 20.000).
      - Berikan jarak antar topik pembahasan.

      **Gaya Bahasa:**
      - Asik, ramah, santai, dan solutif (seperti teman tapi sopan).
      - Gunakan emoji secukupnya (✨, 🚀, 📦).
      - Jawaban ringkas dan padat.
      - Gunakan bahasa aku dan kamu.
      - Humoris & Humble: Jangan ragu buat ketawa (pake "wkwk", "hehe", atau "hihi") kalau situasinya pas.
      - Ramah Banget: Gunakan kata-kata hangat seperti "Siap Kak!", "Boleh banget dong!", "Waduh, tenang aja...".
      - Santai: Posisikan diri sebagai teman curhat soal aplikasi premium, bukan CS kaku.
      - Manusiawi: Gunakan ekspresi seperti "Jujurly...", "Mantap bener,", atau "Gaspol Kak!".

      **Informasi Layanan:**
      - **Sharing**: Murah, 1 akun dipakai bersama, 1 device only, dilarang ganti password/profil.
      - **Private**: Eksklusif, milik sendiri, bisa ganti password, lebih aman & stabil.
      - **Cara Beli**: Arahkan klik tombol 'Add' atau 'Buy Now' di produk terkait.
    `;
  };

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!inputValue.trim() || isTyping) return;

    const userText = inputValue;

    // 1. Add User Message to UI
    const newUserMsg: Message = {
      id: Date.now().toString(),
      text: userText,
      sender: 'user',
      timestamp: new Date()
    };

    setMessages(prev => [...prev, newUserMsg]);
    setInputValue('');
    setIsTyping(true);

    try {
      // 2. Prepare History for Context
      const conversationHistory = messages
        .filter(m => m.id !== 'welcome')
        .map(m => ({
          role: m.sender === 'user' ? 'user' : 'assistant',
          content: m.text
        }));

      conversationHistory.push({ role: 'user', content: userText });

      // 3. Call Groq API
      const response = await fetch("https://api.groq.com/openai/v1/chat/completions", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${GROQ_API_KEY}`,
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          messages: [
            {
              role: "system",
              content: getSystemInstruction()
            },
            ...conversationHistory
          ],
          model: "llama-3.3-70b-versatile",
          temperature: 0.6,
          max_tokens: 1024,
        })
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => null);
        const errorMessage = errorData?.error?.message || response.statusText || `Status ${response.status}`;
        throw new Error(errorMessage);
      }

      const data = await response.json();
      const botText = data.choices[0]?.message?.content || "Maaf, saya tidak mengerti.";

      // 4. Add Bot Response to UI
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        text: botText,
        sender: 'bot',
        timestamp: new Date()
      }]);

    } catch (error: any) {
      console.error("Chat Error:", error);
      setMessages(prev => [...prev, {
        id: (Date.now() + 1).toString(),
        text: `Maaf, ada kendala teknis: ${error.message || 'Koneksi error'}. Coba lagi ya!`,
        sender: 'bot',
        timestamp: new Date()
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <>
      {!isOpen && (
        <button
          onClick={() => setIsOpen(true)}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          className="fixed bottom-5 right-5 z-[50] h-14 w-14 rounded-full bg-gradient-to-br from-burgundy-800 to-burgundy-950 shadow-lg flex items-center justify-center border border-white/20"
        >
          <MessageCircle className="text-white" size={28} />
          {isHovered && (
            <div className="absolute right-16 bg-white text-burgundy-900 px-3 py-1 rounded-lg text-xs font-bold whitespace-nowrap shadow-md">
              Chat Dhevv AI 👋
            </div>
          )}
        </button>
      )}

      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 sm:p-4 font-sans">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-md" onClick={() => setIsOpen(false)} />

          <div className="relative w-full h-full sm:max-w-md sm:h-[80vh] bg-white dark:bg-[#1a0505] shadow-2xl flex flex-col sm:rounded-3xl overflow-hidden">
            {/* Header */}
            <div className="p-4 bg-burgundy-900 flex items-center justify-between text-white">
              <div className="flex items-center gap-3">
                <Bot className="text-gold-400" />
                <div>
                  <h3 className="font-bold text-sm">Dhevv AI Assistant</h3>
                  <p className="text-[10px] text-emerald-400 opacity-80">● Online</p>
                </div>
              </div>
              <button onClick={() => setIsOpen(false)} className="p-2 hover:bg-white/10 rounded-full">
                <ArrowLeft size={20} className="sm:hidden" />
                <X size={20} className="hidden sm:block" />
              </button>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-stone-50 dark:bg-stone-900/20">
              {messages.map((msg) => (
                <div 
                  key={msg.id} 
                  className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
                >
                  <div className={`max-w-[85%] p-3 rounded-2xl text-sm whitespace-pre-wrap shadow-sm ${
                    msg.sender === 'user' ? 'bg-burgundy-800 text-white rounded-tr-none' : 'bg-white dark:bg-white/10 border dark:text-white rounded-tl-none'
                  }`}>
                     {msg.text.split(/(\*\*.*?\*\*)/).map((part, index) => 
                        part.startsWith('**') && part.endsWith('**') 
                          ? <strong key={index} className="font-bold">{part.slice(2, -2)}</strong> 
                          : part
                     )}
                  </div>
                </div>
              ))}
              {isTyping && (
                <div className="flex justify-start">
                  <div className="bg-white dark:bg-white/10 border p-3 rounded-2xl rounded-tl-none flex gap-1">
                    <span className="w-1.5 h-1.5 bg-stone-400 rounded-full"></span>
                    <span className="w-1.5 h-1.5 bg-stone-400 rounded-full"></span>
                    <span className="w-1.5 h-1.5 bg-stone-400 rounded-full"></span>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <form onSubmit={handleSend} className="p-4 border-t dark:border-white/5 bg-white dark:bg-stone-900">
              <div className="flex gap-2">
                <input
                  ref={inputRef}
                  type="text"
                  value={inputValue}
                  onChange={(e) => setInputValue(e.target.value)}
                  placeholder="Tanya harga atau aplikasi..."
                  className="flex-1 p-3 bg-stone-100 dark:bg-white/5 rounded-xl text-sm outline-none focus:ring-1 focus:ring-burgundy-500 dark:text-white"
                />
                <button type="submit" className="p-3 bg-burgundy-900 text-white rounded-xl hover:bg-burgundy-800">
                  <Send size={18} />
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </>
  );
};

export default AIChatWidget;
